/* AUTO-GENERATED — Rhode Island Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["RI"] = {"code":"RI","name":"Rhode Island","agency":"Rhode Island DMV","agencyShort":"DMV","handbook":"https://dmv.ri.gov/licenses-permits-ids/commercial/commercial-driving-license-cdl","links":{},"en":[{"q":"On Rhode Island highways, what is the maximum legal width of a commercial vehicle or its load, without a special permit?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"answer":1,"explanation":"Rhode Island General Laws § 31-25-3 sets the maximum width of any vehicle or its load at 102 inches (8 feet 6 inches). Anything wider requires a RIDOT oversize permit. Source: R.I. Gen. Laws § 31-25-3.","handbook":"","hbref":""},{"q":"What is the maximum legal height of a vehicle, including its load, on Rhode Island highways without a permit?","options":["162 inches (13 feet 6 inches)","156 inches (13 feet)","168 inches (14 feet)","150 inches (12 feet 6 inches)"],"answer":0,"explanation":"Rhode Island General Laws § 31-25-4 limits vehicle height, including load, to 162 inches (13 feet 6 inches). Loads exceeding this require a RIDOT overheight permit. Source: R.I. Gen. Laws § 31-25-4.","handbook":"","hbref":""},{"q":"What is the maximum overall gross weight, in pounds, for a vehicle or combination of vehicles on Rhode Island highways without an overweight permit?","options":["73,280 pounds","80,000 pounds","88,000 pounds","100,000 pounds"],"answer":1,"explanation":"Rhode Island caps overall gross weight at 80,000 pounds, matching the federal Interstate standard, unless a special permit is obtained. Source: R.I. Gen. Laws § 31-25-14; RIDOT Manual for Overweight and Oversize Vehicle Permits.","handbook":"","hbref":""},{"q":"In Rhode Island, the gross weight imposed on the highway by the wheels of any single axle may not exceed how many pounds?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"answer":2,"explanation":"Rhode Island General Laws § 31-25-13 sets a single-axle limit of 22,400 pounds. This is higher than the 20,000-pound federal Interstate single-axle standard, a Rhode Island state-specific figure. Source: R.I. Gen. Laws § 31-25-13.","handbook":"","hbref":""},{"q":"What is the maximum legal weight on a tandem axle group in Rhode Island when the axle spacing does not exceed 8 feet?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"answer":2,"explanation":"Rhode Island General Laws § 31-25-14 limits a tandem axle group to 36,000 pounds when the axle spacing does not exceed 8 feet. Source: R.I. Gen. Laws § 31-25-14.","handbook":"","hbref":""},{"q":"Under Rhode Island law, how is a single \"axle load\" defined for weight-limit purposes?","options":["The total load on all wheels within two parallel transverse vertical planes 40 inches apart","The total load on all wheels within two planes 96 inches apart","The load carried by any one tire on the vehicle","Half of the vehicle's registered gross weight"],"answer":0,"explanation":"Rhode Island General Laws § 31-25-13 defines an axle load as the total load transmitted to the road by all wheels whose centers lie between two parallel transverse vertical planes 40 inches apart, extending across the full width of the vehicle. Source: R.I. Gen. Laws § 31-25-13.","handbook":"","hbref":""},{"q":"What is the maximum length of a single vehicle (not a combination), including load and bumpers, on Rhode Island highways?","options":["35 feet","40 feet","48 feet","53 feet"],"answer":1,"explanation":"Rhode Island General Laws § 31-25-5 limits a single vehicle, including any load, to 40 feet overall (45 feet for a motor bus, motorized camper, or camping recreational vehicle). Source: R.I. Gen. Laws § 31-25-5.","handbook":"","hbref":""},{"q":"In Rhode Island, what is the maximum length of a single motor bus, motorized camper, or camping recreational vehicle?","options":["40 feet","42 feet","45 feet","48 feet"],"answer":2,"explanation":"Rhode Island General Laws § 31-25-5 allows a motor bus, motorized camper, or camping recreational vehicle to reach 45 feet, while other single vehicles are limited to 40 feet. Source: R.I. Gen. Laws § 31-25-5.","handbook":"","hbref":""},{"q":"What is the maximum length of a semitrailer operating in Rhode Island, excluding bumpers and accessories?","options":["48 feet 6 inches","51 feet","53 feet","57 feet"],"answer":2,"explanation":"Rhode Island General Laws § 31-25-6 permits semitrailers up to 53 feet, excluding bumpers and accessories. Source: R.I. Gen. Laws § 31-25-6.","handbook":"","hbref":""},{"q":"In Rhode Island, semitrailers longer than what length may operate only on the Interstate highway system and on highways specifically designated by the director?","options":["45 feet","48 feet 6 inches","50 feet","53 feet"],"answer":1,"explanation":"Rhode Island General Laws § 31-25-6 restricts semitrailers exceeding 48 feet 6 inches to the Interstate highway system and to highways, streets, and roads designated by the director. Source: R.I. Gen. Laws § 31-25-6.","handbook":"","hbref":""},{"q":"Which agency issues oversize and overweight vehicle permits in Rhode Island?","options":["The Rhode Island Department of Transportation (RIDOT)","The Rhode Island State Police","The Federal Highway Administration","The local city or town clerk where travel begins"],"answer":0,"explanation":"Special permits for vehicles exceeding the legal size or weight limits are issued by the State Department of Transportation (RIDOT). Source: RIDOT Manual for Overweight and Oversize Vehicle Permits; R.I. Gen. Laws § 31-25-18.","handbook":"","hbref":""},{"q":"Which formula does Rhode Island use to determine the allowable gross weight on any group of consecutive axles?","options":["The federal Bridge Formula: W = 500[(LN/(N-1)) + 12N + 36]","Gross weight = 1,000 pounds per inch of tire width","Gross weight = 34,000 pounds per axle group, fixed","Gross weight = 80,000 divided by the number of axles"],"answer":0,"explanation":"Rhode Island General Laws § 31-25-14 applies the federal Bridge Formula, W = 500[(LN/(N-1)) + 12N + 36], where W is the gross weight on a group of consecutive axles, L is the distance in feet between the outer axles of the group, and N is the number of axles. Source: R.I. Gen. Laws § 31-25-14.","handbook":"","hbref":""},{"q":"In the Rhode Island Bridge Formula W = 500[(LN/(N-1)) + 12N + 36], what does the variable \"N\" represent?","options":["The number of axles in the group being considered","The net weight of the cargo only","The number of tires on the drive axle","The nominal width of the vehicle in feet"],"answer":0,"explanation":"In the Bridge Formula adopted by Rhode Island, N is the number of axles in the group, L is the distance in feet between the extreme axles, and W is the maximum allowable gross weight on that group. Source: R.I. Gen. Laws § 31-25-14.","handbook":"","hbref":""},{"q":"Under Rhode Island's weight rules, if the Bridge Formula produces a tandem-axle limit below 36,000 pounds, what value is used as the legal limit?","options":["The lower formula result must be used","34,000 pounds is used","36,000 pounds is treated as the legal limit","The axle group must be re-spaced before loading"],"answer":2,"explanation":"Rhode Island General Laws § 31-25-14 provides that when the Bridge Formula yields a tandem-axle figure below 36,000 pounds, 36,000 pounds is considered the legal limit. Source: R.I. Gen. Laws § 31-25-14.","handbook":"","hbref":""},{"q":"A carrier needs to move an indivisible load 11 feet wide on a Rhode Island highway. What must the carrier do?","options":["Nothing; 11 feet is within the legal width","Obtain an oversize permit from RIDOT before moving","Notify only the local police department","Reduce the load to 96 inches first"],"answer":1,"explanation":"Because 11 feet (132 inches) exceeds the 102-inch legal width under § 31-25-3, the carrier must obtain an oversize permit from RIDOT before moving the load. Source: R.I. Gen. Laws § 31-25-3 and § 31-25-18; RIDOT Permit Manual.","handbook":"","hbref":""},{"q":"What is the standard RIDOT single-trip fee for moving a non-divisible oversize or overweight vehicle or load in Rhode Island?","options":["$10.00 per trip","$20.00 per trip","$50.00 per trip","$100.00 per trip"],"answer":1,"explanation":"The RIDOT Manual for Overweight and Oversize Vehicle Permits charges a $20.00 trip fee for the movement of non-divisible vehicles or loads. Source: RIDOT Manual for Overweight and Oversize Vehicle Permits, Sec. 4.4.","handbook":"","hbref":""},{"q":"Instead of paying per-trip fees, a carrier making repeated intrastate oversize/overweight moves in Rhode Island may obtain a blanket permit for what fee?","options":["$50.00","$100.00","$250.00","$500.00"],"answer":1,"explanation":"The RIDOT permit manual allows a blanket permit for intrastate moves to be obtained for $100.00 in lieu of paying per-trip fees. Source: RIDOT Manual for Overweight and Oversize Vehicle Permits, Sec. 4.4.","handbook":"","hbref":""},{"q":"Under the Rhode Island permit manual, how many escort (pilot) vehicles are required for a load with an overall width over 14 feet 6 inches?","options":["No escort is required","One escort vehicle","Two escort vehicles","Four escort vehicles"],"answer":2,"explanation":"The RIDOT permit manual requires one escort for widths between 12 feet 0 inches and 14 feet 6 inches, and two escort vehicles for widths over 14 feet 6 inches. Source: RIDOT Manual for Overweight and Oversize Vehicle Permits, Sec. 5.4.","handbook":"","hbref":""},{"q":"According to the Rhode Island permit manual, when are permitted oversize/overweight moves generally NOT authorized?","options":["From sunset Friday to sunrise Monday and on listed holidays","Only between midnight and 4:00 a.m. daily","Only during the first week of each month","Never; permitted moves may run at any time"],"answer":0,"explanation":"The RIDOT permit manual prohibits moves, unless otherwise noted, from sunset Friday to sunrise Monday and on the listed legal holidays. Source: RIDOT Manual for Overweight and Oversize Vehicle Permits, Sec. 4.15 / 5.7.","handbook":"","hbref":""},{"q":"How does Rhode Island law treat farm vehicles, farm tractors, road machinery, and fire apparatus with respect to the Chapter 31-25 size and weight limits?","options":["They are exempt from the size and weight limitations","They are limited to 50% of the normal weight limits","They must carry an annual oversize permit at all times","They are barred from all numbered state highways"],"answer":0,"explanation":"Rhode Island General Laws § 31-25-2 exempts fire apparatus, road machinery, and farm vehicles (including farm tractors) temporarily moved on a highway from the Chapter 31-25 size and weight limitations. Source: R.I. Gen. Laws § 31-25-2.","handbook":"","hbref":""},{"q":"In Rhode Island, what is the minimum age to obtain a CDL valid for INTRASTATE (within-state) operation only?","options":["16 years old","18 years old","21 years old","25 years old"],"answer":1,"explanation":"The RI CDL Manual (Guidelines for CDL Applicants) states you must have a valid operator's license for at least two years and be at least 18 years old for an INTRASTATE CDL ONLY; 21 is required for interstate. Source: RI DMV Commercial Driver License Manual (AAMVA 2005, Rev. July 2014).","handbook":"","hbref":""},{"q":"What is the minimum age required in Rhode Island to operate a commercial motor vehicle in INTERSTATE commerce (crossing state lines)?","options":["18 years old","19 years old","21 years old","23 years old"],"answer":2,"explanation":"RI DMV requires a driver to be 21 to be eligible for interstate (crossing state lines) CDL operation; 18 qualifies only for intrastate. Source: RI DMV CDL page and RI Commercial Driver License Manual (Rev. July 2014).","handbook":"","hbref":""},{"q":"Under Rhode Island's CDL classification, which class authorizes operating any COMBINATION of vehicles with a GCWR of 26,001 lbs or more, provided the GVWR of the unit(s) being towed exceeds 10,000 lbs?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"Per the RI CDL Manual, a Class A CDL authorizes operation of any combination of vehicles with a GCWR of 26,001 or more pounds provided the GVWR of the vehicle(s) being towed is in excess of 10,000 pounds. Source: RI Commercial Driver License Manual, License Classes.","handbook":"","hbref":""},{"q":"In Rhode Island, a CDL authorizing a SINGLE vehicle with a GVWR of 26,001 lbs or more (or such a vehicle towing a unit not over 10,000 lbs GVWR) is which class?","options":["Class A","Class B","Class C","Class E"],"answer":1,"explanation":"The RI CDL Manual defines Class B as any single vehicle with a GVWR of 26,001 or more pounds, or such a vehicle towing a vehicle not in excess of 10,000 pounds GVWR. Source: RI Commercial Driver License Manual, License Classes.","handbook":"","hbref":""},{"q":"Which Rhode Island CDL class covers a vehicle (not meeting Class A or B) designed to transport 16 or more passengers including the driver, or one placarded for hazardous materials?","options":["Class A","Class B","Class C","Class M"],"answer":2,"explanation":"The RI CDL Manual defines Class C as any vehicle that does not meet Class A or B but is designed to transport 16 or more passengers including the driver, or is placarded for hazardous materials. Source: RI Commercial Driver License Manual, License Classes.","handbook":"","hbref":""},{"q":"On a Rhode Island CDL, which endorsement code is required to transport hazardous materials in quantities requiring placarding under federal DOT regulations?","options":["Code N","Code H","Code T","Code P"],"answer":1,"explanation":"Per the RI CDL Manual, the H (HazMat) endorsement is required on ANY license class when transporting hazardous materials in any quantity requiring placarding by federal DOT regulations. Source: RI Commercial Driver License Manual, Endorsements.","handbook":"","hbref":""},{"q":"Which endorsement does Rhode Island require to operate a tank vehicle hauling liquid or gaseous material, or a portable tank rated 1,000 gallons or more?","options":["N - Tank Vehicles","T - Double/Triple Trailers","P - Passenger","S - School Bus"],"answer":0,"explanation":"The RI CDL Manual states the N (Tank Vehicles) endorsement is required on any license class when transporting liquid or gaseous material in a tank vehicle, or any portable tank rated 1,000 gallons or more. Source: RI Commercial Driver License Manual, Endorsements.","handbook":"","hbref":""},{"q":"In Rhode Island, the T (Double/Triple Trailers) endorsement may be obtained only by operators holding which CDL class?","options":["Class C operators","Class B operators","Class A operators","Any class operator"],"answer":2,"explanation":"The RI CDL Manual states the T (Double/Triple Trailers) endorsement is required for Class A operators who haul double/triple trailers where operation is permitted by law. Source: RI Commercial Driver License Manual, Endorsements.","handbook":"","hbref":""},{"q":"Before testing, what additional step does Rhode Island require for a school bus (S) endorsement beyond the written exam and skills test?","options":["A TSA security threat assessment","A RI School Bus Certificate through the DMV School Bus Safety Office","A green chauffeur license application","A doubles/triples knowledge test"],"answer":1,"explanation":"The RI CDL Manual states S (School Bus) endorsement operators must first obtain a RI School Bus Certificate through the DMV School Bus Safety Office. Source: RI Commercial Driver License Manual, Endorsements.","handbook":"","hbref":""},{"q":"Per the Rhode Island CDL Manual, the P (Passenger) endorsement is required when a vehicle is designed to seat more than how many people including the operator?","options":["8","12","15","16"],"answer":3,"explanation":"The RI CDL Manual states the P endorsement is required on any license class when the vehicle is designed to seat more than 16 passengers including the operator; a green chauffeur license application must also be completed. Source: RI Commercial Driver License Manual, Endorsements.","handbook":"","hbref":""},{"q":"Which Rhode Island CDL endorsement combines the HazMat and Tank Vehicle endorsements, requiring both knowledge examinations to be passed?","options":["Code S","Code T","Code X","Code P"],"answer":2,"explanation":"The RI CDL Manual describes endorsement X as the combination of H (HazMat) and N (Tank); both examinations must be taken. Source: RI Commercial Driver License Manual, Endorsements.","handbook":"","hbref":""},{"q":"Under federal rules applied in Rhode Island, how long must a Commercial Learner's Permit be held before the holder may take the CDL skills test?","options":["7 days","14 days","30 days","60 days"],"answer":1,"explanation":"Federal regulation 49 CFR 383.25, applied by RI DMV, prohibits a CLP holder from taking the CDL skills test in the first 14 days after the CLP is initially issued. Source: 49 CFR 383.25; RI DMV CLP requirements.","handbook":"","hbref":""},{"q":"Which knowledge test must EVERY Rhode Island CDL applicant pass, regardless of class or endorsement sought?","options":["Air Brakes test","Combination Vehicles test","General Knowledge test","Passenger Transport test"],"answer":2,"explanation":"The RI CDL Manual states the General Knowledge test is taken by all applicants; other tests depend on class and endorsements. Source: RI Commercial Driver License Manual, Section 1, Knowledge Tests.","handbook":"","hbref":""},{"q":"On the Rhode Island General Knowledge CDL exam, how many of the 50 questions must be answered correctly to pass (80%)?","options":["30","40","44","45"],"answer":1,"explanation":"The RI CDL Manual's electronic/manual test schedule lists the General Knowledge test as 50 questions, requiring 40 correct (80%) to pass. Source: RI Commercial Driver License Manual, Electronic/Manual Tests.","handbook":"","hbref":""},{"q":"Which agency administers and schedules the CDL road (skills) test for Rhode Island applicants?","options":["The RI DMV main office in Cranston","The Community College of Rhode Island (CCRI)","The RI State Police","The Rhode Island DOT permit office"],"answer":1,"explanation":"The RI CDL Manual states road tests are given by and must be scheduled with the Community College of Rhode Island (CCRI). Source: RI Commercial Driver License Manual, Road Tests.","handbook":"","hbref":""},{"q":"Which of the following is a required document for a Rhode Island CDL applicant, per the RI DMV's CLP guidelines?","options":["A valid Social Security card","A notarized employer letter","A commercial vehicle title","A motorcycle endorsement"],"answer":0,"explanation":"The RI CDL Manual requires all applicants to present a valid Social Security card, a valid Medical Card (if non-excepted), and proof of identity/residency. Source: RI Commercial Driver License Manual, Guidelines for CDL Applicants.","handbook":"","hbref":""},{"q":"Federal Entry-Level Driver Training (ELDT), enforced in Rhode Island, must be completed through a provider listed on which registry?","options":["The state DMV training database","The FMCSA Training Provider Registry (TPR)","The AAMVA driver education list","The TSA approved schools list"],"answer":1,"explanation":"Since Feb 7, 2022, first-time Class A/B applicants, B-to-A upgrades, and new P/S/H endorsement seekers must complete ELDT with a provider on the FMCSA Training Provider Registry before the skills test (knowledge test for H). Source: FMCSA ELDT rule; FMCSA Training Provider Registry.","handbook":"","hbref":""},{"q":"When self-certifying medical status to the Rhode Island DMV, which of the following is one of the four valid categories a CDL holder must choose from?","options":["Interstate Commerce Non-excepted","Recreational Commerce Exempt","Foreign Commerce Certified","Agricultural Commerce Waived"],"answer":0,"explanation":"The RI CDL Manual lists four self-certification categories: Interstate Excepted, Interstate Non-excepted, Intrastate Excepted, and Intrastate Non-excepted. Non-excepted drivers must present a valid medical card (49 CFR 391.45). Source: RI Commercial Driver License Manual, Self-Certification.","handbook":"","hbref":""},{"q":"Per the Rhode Island CDL Manual, within how many days must a CDL holder present a new Medical Card to the DMV after it is issued?","options":["10 days","15 days","30 days","45 days"],"answer":1,"explanation":"The RI CDL Manual states you must present your new Medical Card to the DMV within 15 days of issuance; failure to comply can result in a downgrade of your license. Source: RI Commercial Driver License Manual, Medical Certification.","handbook":"","hbref":""},{"q":"While operating a commercial motor vehicle in Rhode Island, what is the blood alcohol concentration (BAC) at or above which a driver is considered legally intoxicated for CMV purposes?","options":["0.04%","0.08%","0.02%","0.10%"],"answer":0,"explanation":"In Rhode Island, operating a CMV with a BAC of 0.04% or greater is a major offense, half the 0.08% limit that applies to non-commercial drivers. Source: R.I. Gen. Laws 31-10.3-31; RI CDL Manual, Section 2.","handbook":"","hbref":""},{"q":"Under Rhode Island's implied consent law, a CDL holder who refuses to submit to a chemical test of breath, blood, or urine when lawfully requested is treated as having committed what?","options":["A major offense, like a DUI conviction","A serious traffic violation only","An out-of-service order violation","A non-reportable administrative matter"],"answer":0,"explanation":"In Rhode Island, refusing a required chemical test is a major offense carrying the same disqualification as a DUI conviction. Source: R.I. Gen. Laws 31-10.3-31; RI CDL Manual, Section 2.","handbook":"","hbref":""},{"q":"In Rhode Island, what is the minimum disqualification period for a CDL holder's FIRST major offense (such as DUI in a CMV) when NOT transporting placarded hazardous materials?","options":["1 year","60 days","3 years","6 months"],"answer":0,"explanation":"Rhode Island disqualifies a driver for at least 1 year for a first major offense (DUI, 0.04+ BAC, refusal, leaving the scene, or using a CMV in a felony). Source: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Rhode Island, if a driver commits a first major offense while transporting hazardous materials that require placards, the minimum disqualification period increases to:","options":["3 years","1 year","120 days","5 years"],"answer":0,"explanation":"A first major offense while operating a placarded hazmat vehicle results in a minimum 3-year disqualification in Rhode Island, instead of the standard 1 year. Source: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Rhode Island, a CDL holder who is convicted of a SECOND major offense during their lifetime faces what disqualification?","options":["Lifetime disqualification","10-year disqualification","3-year disqualification","1-year disqualification"],"answer":0,"explanation":"A second major offense in a lifetime results in lifetime disqualification in Rhode Island (which may, under certain conditions, be reduced to a minimum of 10 years). Source: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"How many serious traffic violations within a 3-year period (arising from separate incidents) trigger a 60-day CDL disqualification in Rhode Island?","options":["2","3","4","1"],"answer":0,"explanation":"Two serious traffic violations in a CMV within 3 years lead to a 60-day disqualification in Rhode Island. Source: R.I. Gen. Laws 31-10.3-31; RI CDL Manual, Section 2.","handbook":"","hbref":""},{"q":"In Rhode Island, three serious traffic violations within a 3-year period result in a CDL disqualification of how long?","options":["120 days","60 days","90 days","1 year"],"answer":0,"explanation":"Three serious traffic violations in a CMV within 3 years lead to a 120-day disqualification in Rhode Island. Source: R.I. Gen. Laws 31-10.3-31; RI CDL Manual, Section 2.","handbook":"","hbref":""},{"q":"Which of the following is classified as a SERIOUS traffic violation for a Rhode Island CDL holder?","options":["Following the vehicle ahead too closely","Operating a CMV with a 0.04% BAC","Refusing a chemical test","Violating an out-of-service order"],"answer":0,"explanation":"Following too closely is one of the listed serious traffic violations; the other options are major offenses or out-of-service violations with separate penalties. Source: RI CDL Manual, Section 2; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"For a serious traffic violation in Rhode Island, excessive speeding is defined as driving how many miles per hour or more above the posted speed limit?","options":["15 mph or more","10 mph or more","20 mph or more","25 mph or more"],"answer":0,"explanation":"Speeding 15 mph or more over the posted limit is a serious traffic violation for CDL purposes in Rhode Island. Source: RI CDL Manual, Section 2; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under federal rules adopted in Rhode Island, using a hand-held mobile telephone or texting while driving a CMV counts as what type of violation for disqualification purposes?","options":["A serious traffic violation","A major offense","An out-of-service order violation","A railroad-crossing violation"],"answer":0,"explanation":"Texting or using a hand-held phone while driving a CMV is a serious traffic violation in Rhode Island, counting toward the 60-day/120-day disqualifications. Source: 49 CFR 383.51, 392.80-392.82; RI CDL Manual.","handbook":"","hbref":""},{"q":"How many texting/hand-held phone violations within a 3-year period result in a 120-day CDL disqualification in Rhode Island?","options":["3 or more","2","5","4"],"answer":0,"explanation":"Because texting/hand-held use are serious traffic violations, three or more within 3 years cause a 120-day disqualification (two cause 60 days). Source: 49 CFR 383.51, 392.82; RI CDL Manual.","handbook":"","hbref":""},{"q":"In Rhode Island, a THIRD or subsequent out-of-service order violation within a 10-year period (standard operations) results in what disqualification?","options":["3 years","1 year","5 years","Lifetime"],"answer":0,"explanation":"A third or subsequent OOS order violation within 10 years carries a 3-year disqualification in Rhode Island. Source: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"If a Rhode Island CDL holder violates an out-of-service order while transporting placarded hazardous materials or while operating a vehicle designed to carry 16 or more passengers, the FIRST-violation disqualification is at least:","options":["180 days","90 days","1 year","60 days"],"answer":0,"explanation":"A first OOS violation while hauling hazmat or carrying 16+ passengers raises the minimum disqualification to 180 days in Rhode Island. Source: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Rhode Island, what is the minimum disqualification for a CDL holder's FIRST railroad-grade-crossing violation?","options":["60 days","30 days","90 days","120 days"],"answer":0,"explanation":"A first railroad-grade-crossing violation results in a minimum 60-day disqualification in Rhode Island. Source: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Rhode Island, a SECOND railroad-grade-crossing violation within a 3-year period results in a minimum disqualification of:","options":["120 days","60 days","1 year","90 days"],"answer":0,"explanation":"A second railroad-crossing violation within 3 years carries a minimum 120-day disqualification in Rhode Island. Source: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Rhode Island, a THIRD or subsequent railroad-grade-crossing violation within a 3-year period results in a minimum disqualification of:","options":["1 year","120 days","60 days","3 years"],"answer":0,"explanation":"A third or subsequent railroad-crossing violation within 3 years carries a minimum 1-year disqualification in Rhode Island. Source: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A Rhode Island CDL holder is convicted of DUI while driving their OWN personal (non-commercial) vehicle. What happens to their CDL?","options":["They are disqualified from driving a CMV for at least 1 year","Nothing, because it was not a commercial vehicle","They receive only a 60-day disqualification","They face only a serious-violation penalty"],"answer":0,"explanation":"In Rhode Island a DUI conviction in any vehicle, including a personal car, disqualifies a CDL holder from operating a CMV for at least 1 year as a major offense. Source: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which of the following is a MAJOR offense (1-year disqualification) for a Rhode Island CDL holder rather than a serious traffic violation?","options":["Using a CMV in the commission of a felony","Following too closely","An improper or erratic lane change","Driving a CMV without the proper class or endorsement"],"answer":0,"explanation":"Using a CMV to commit a felony is a major offense carrying a 1-year disqualification; the other choices are serious traffic violations. Source: R.I. Gen. Laws 31-10.3-31; RI CDL Manual, Section 2; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Rhode Island, at what distance from the nearest rail must a school bus carrying children, a bus carrying passengers for hire, or a vehicle hauling explosives or flammable liquids stop before crossing railroad tracks?","options":["Within 100 feet but not less than 50 feet","Within 50 feet but not less than 15 feet","Within 25 feet but not less than 10 feet","Within 75 feet but not less than 25 feet"],"answer":1,"explanation":"RI General Laws § 31-20-4 requires the driver of any motor vehicle carrying passengers for hire, any school bus carrying a school child, or any vehicle carrying explosive substances or flammable liquids to stop within fifty feet (50') but not less than fifteen feet (15') from the nearest rail. Source: RIGL § 31-20-4.","handbook":"","hbref":""},{"q":"Under Rhode Island law, the railroad-crossing stop required of buses-for-hire, school buses, and explosives/flammable-liquid carriers does NOT apply in which situation?","options":["Whenever the vehicle is empty of cargo or passengers","Any time the driver holds a hazardous materials endorsement","On any crossing equipped with automatic gates","At a crossing where an officer or traffic-control signal directs traffic to proceed, or at crossings within a business or residence district"],"answer":3,"explanation":"RIGL § 31-20-4 states no stop need be made where a police officer or traffic-control signal directs traffic to proceed, and the section does not apply at railroad grade crossings within a business or residence district. An empty bus or the presence of gates does not waive the rule. Source: RIGL § 31-20-4.","handbook":"","hbref":""},{"q":"On a divided highway in Rhode Island, when is a driver NOT required to stop for a stopped school bus displaying flashing red lights?","options":["Whenever the driver is traveling under 20 mph","When the driver is more than two car lengths from the bus","Never — all drivers must always stop in both directions","When the bus is stopped in the roadway on the other side of the divided highway from the driver"],"answer":3,"explanation":"RIGL § 31-20-13 provides that a driver need not stop where the highway is a divided highway and the bus is stopped in the roadway on one side of the divided highway while the driver is operating on the other side. The RI DMV defines a divided highway as one separated by a barrier, guardrail, or grass/cement median. Source: RIGL § 31-20-13; RI DMV School Buses page.","handbook":"","hbref":""},{"q":"Rhode Island defines a 'divided highway' for the school-bus stopping exception as a roadway separated by which of the following?","options":["A double-yellow centerline only","A center two-way left-turn lane","A Jersey barrier, guardrail, grass or cement median, trees, water, or similar separation between opposing lanes","Any roadway with three or more lanes total"],"answer":2,"explanation":"The RI DMV explains the divided-highway exception applies only where opposing directions are separated by a Jersey barrier, guardrail, grass or cement median, trees, water, etc. A painted centerline or turn lane is not a divider. Source: RI DMV School Buses page (interpreting RIGL § 31-20-13).","handbook":"","hbref":""},{"q":"When meeting or overtaking a Rhode Island school bus with its red lights flashing on an ordinary (undivided) two-lane road, what must a driver do?","options":["Slow to 15 mph and pass with caution","Stop only if approaching from behind the bus","Yield only to children actually in the roadway","Stop from either direction and not proceed until the bus moves or the flashing lights are turned off"],"answer":3,"explanation":"RIGL § 31-20-12 requires drivers meeting or overtaking from any direction a bus marked 'school bus' with flashing red lights to stop, and the driver shall not proceed until the bus resumes motion or the flashing lights are no longer actuated. Source: RIGL § 31-20-12.","handbook":"","hbref":""},{"q":"Rhode Island law prohibits the driver of any vehicle (other than an emergency vehicle on official business) from following a school bus more closely than what distance?","options":["100 feet","20 feet","50 feet","300 feet"],"answer":2,"explanation":"RIGL § 31-20-12 prohibits driving behind a school bus at a distance of less than fifty feet (50'), except for emergency vehicles on official business. Source: RIGL § 31-20-12.","handbook":"","hbref":""},{"q":"Under Rhode Island's Move Over law, what must a driver do when approaching a stopped emergency vehicle, tow truck, or highway-maintenance vehicle displaying flashing lights on a road with at least two lanes in the driver's direction?","options":["Come to a complete stop until the vehicle leaves","Sound the horn and continue at the posted speed","Move onto the right shoulder and stop","Move into a lane not nearest the stopped vehicle, when it can be done safely"],"answer":3,"explanation":"RIGL § 31-14-3 requires a driver to move into a lane not nearest the stopped authorized emergency vehicle, tow/transporter truck, roadside-assistance vehicle, or maintenance equipment displaying flashing lights — if the road has two or more lanes in that direction and the move can be made safely. Source: RIGL § 31-14-3.","handbook":"","hbref":""},{"q":"Under Rhode Island's Move Over law, what must a driver do when there is only one lane in the driver's direction or a lane change cannot be made safely?","options":["Stop completely in the travel lane","Maintain the posted speed limit","Pull off the road and wait five minutes","Slow to a safe, reduced speed and stay there until completely past the vehicle"],"answer":3,"explanation":"RIGL § 31-14-3 directs that where there is only one lane or lane-changing is unsafe, the driver must slow the vehicle to a safe speed for conditions and operate at that reduced speed until completely past the stopped vehicle. Source: RIGL § 31-14-3.","handbook":"","hbref":""},{"q":"Rhode Island's Move Over law protects which of the following stopped vehicles displaying warning lights?","options":["Only police cars and ambulances","Only vehicles owned by the state","Emergency vehicles, tow/transporter trucks, roadside-assistance vehicles, and highway-maintenance equipment","Only fire apparatus actively fighting a fire"],"answer":2,"explanation":"RIGL § 31-14-3 lists authorized emergency vehicles, tow trucks, transporter trucks, roadside-assistance vehicles, and highway-maintenance equipment displaying flashing lights as protected. The law is not limited to police and ambulances. Source: RIGL § 31-14-3.","handbook":"","hbref":""},{"q":"Absent a posted limit, the Rhode Island prima facie speed limit in any business or residence district is:","options":["25 mph","30 mph","20 mph","35 mph"],"answer":0,"explanation":"RIGL § 31-14-2 sets a prima facie limit of twenty-five miles per hour (25 mph) in any business or residence district. Source: RIGL § 31-14-2.","handbook":"","hbref":""},{"q":"Under Rhode Island's prima facie speed limits, what is the daytime limit in locations other than business/residence districts and school zones, where no other limit is posted?","options":["55 mph daytime","50 mph daytime","45 mph daytime","65 mph daytime"],"answer":1,"explanation":"RIGL § 31-14-2 sets a prima facie limit of fifty miles per hour (50 mph) in other locations during daytime, and forty-five (45 mph) during nighttime. Posted limits on the interstate may be higher. Source: RIGL § 31-14-2.","handbook":"","hbref":""},{"q":"Within 300 feet of a school's entrances and exits during school days, Rhode Island sets a prima facie speed limit of:","options":["15 mph at all times","20 mph during the daytime","25 mph during the daytime","10 mph when children are present"],"answer":1,"explanation":"RIGL § 31-14-2 sets twenty miles per hour (20 mph) within three hundred feet (300') of any schoolhouse grounds' entrances and exits during the daytime on days when schools are open. Source: RIGL § 31-14-2.","handbook":"","hbref":""},{"q":"On a Rhode Island highway, a commercial vehicle proceeding slower than the normal speed of traffic must:","options":["Drive in the right-hand lane or as close as practicable to the right edge of the roadway","Stay in the center lane to avoid merging traffic","Use the left lane to keep clear of entrance ramps","Use any lane as long as the four-way flashers are on"],"answer":0,"explanation":"RIGL § 31-15-2 ('Slow traffic to right') requires any vehicle proceeding slower than the normal speed of traffic to be driven in the right-hand lane available, or as close as practicable to the right curb or edge, except when overtaking, passing, or preparing for a left turn. Source: RIGL § 31-15-2.","handbook":"","hbref":""},{"q":"Without an oversize permit, the maximum legal width of a vehicle or its load in Rhode Island is:","options":["102 inches (8 feet 6 inches)","96 inches (8 feet)","108 inches (9 feet)","120 inches (10 feet)"],"answer":0,"explanation":"RIGL § 31-25-3 limits total outside width of a vehicle or its load to one hundred two inches (102\"), i.e., 8 feet 6 inches, before an oversize permit is required. Source: RIGL § 31-25-3; RIDOT Legal OSOW guide.","handbook":"","hbref":""},{"q":"Without an oversize permit, the maximum legal height of a vehicle including its load in Rhode Island is:","options":["168 inches (14 feet)","162 inches (13 feet 6 inches)","156 inches (13 feet)","150 inches (12 feet 6 inches)"],"answer":1,"explanation":"RIGL § 31-25-4 limits vehicle height including load to one hundred sixty-two inches (162\"), i.e., 13 feet 6 inches. RIDOT's Legal OSOW guide confirms 13'6\" as the legal height. Source: RIGL § 31-25-4; RIDOT Legal OSOW guide.","handbook":"","hbref":""},{"q":"In Rhode Island, a semitrailer longer than 48 feet 6 inches may operate only where?","options":["Anywhere in the state without restriction","Only on toll roads","On the interstate highway system and other highways designated by the RIDOT director","Only between sunrise and sunset on any road"],"answer":2,"explanation":"RIGL § 31-25-6 caps semitrailers at fifty-three feet (53') but permits those over forty-eight and one-half feet (48'6\") to operate only on the interstate system and on highways/streets/roads designated by the RIDOT director. Source: RIGL § 31-25-6.","handbook":"","hbref":""},{"q":"The maximum gross weight of any vehicle or combination of vehicles on Rhode Island highways, absent a permit, is:","options":["73,280 pounds","80,000 pounds","88,000 pounds","100,000 pounds"],"answer":1,"explanation":"RIGL § 31-25-14 limits overall gross weight to eighty thousand pounds (80,000 lbs), subject also to the federal bridge formula. Source: RIGL § 31-25-14.","handbook":"","hbref":""},{"q":"Under Rhode Island law, the maximum gross weight allowed on any single axle of a vehicle is:","options":["22,400 pounds","20,000 pounds","34,000 pounds","18,000 pounds"],"answer":0,"explanation":"RIGL § 31-25-14 limits the gross weight on the wheels of any one axle to twenty-two thousand four hundred (22,400) pounds; a tandem axle (spacing up to 8 feet) is limited to 36,000 pounds. Source: RIGL § 31-25-14.","handbook":"","hbref":""},{"q":"As of 2026, Rhode Island's RhodeWorks bridge tolling program is structured to charge tolls to which vehicles?","options":["Only Class 8 (and larger) tractor-trailers; passenger cars and pickups are exempt","All vehicles over 10,000 pounds","Every vehicle that crosses a tolled bridge","Only out-of-state commercial trucks"],"answer":0,"explanation":"Rhode Island's RhodeWorks program tolls only large commercial trucks — Class 8 and larger tractor-trailers — at bridge gantries, exempting passenger cars and smaller commercial vehicles. The First Circuit upheld the tractor-trailer-only structure (striking only the daily cap). Source: RIDOT/RhodeWorks; First Circuit RhodeWorks decision.","handbook":"","hbref":""},{"q":"When a Rhode Island commercial vehicle is stopped on the traveled portion of a two-lane, two-way road, where must the driver place the three required warning triangles?","options":["All three within 10 ft of the rear bumper","One at 200 ft and two at 100 ft, all behind the vehicle","About 10 ft behind the vehicle toward traffic, about 100 ft behind, and about 100 ft ahead of the vehicle","Only one triangle, placed 50 ft to the rear"],"answer":2,"explanation":"Rhode Island follows the federal standard (49 CFR 392.22) taught in the CDL manual: on a two-lane, two-way road place one triangle about 10 ft to the rear toward traffic, one about 100 ft to the rear, and one about 100 ft to the front. (On a divided or one-way road the rearward devices go at 10, 100, and 200 ft.) Source: RI CDL Manual; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"Which agency issues Commercial Driver Licenses (CDLs) in Rhode Island?","options":["The Rhode Island Division of Motor Vehicles (DMV)","The Rhode Island Department of Transportation (RIDOT)","The Rhode Island State Police Commercial Enforcement Unit","The Federal Motor Carrier Safety Administration (FMCSA)"],"answer":0,"explanation":"CDLs in Rhode Island are issued by the RI Division of Motor Vehicles (RI DMV). RIDOT handles roads and oversize/overweight permits, and the FMCSA sets federal standards but does not issue state licenses. Source: RI DMV, Commercial Driver License (CDL) pages.","handbook":"","hbref":""},{"q":"Where are in-person CDL skills (road) tests administered in Rhode Island?","options":["At the dedicated CDL test site at 400 Romano Vineyard Way, North Kingstown","At any AAA branch office statewide","At the Cranston DMV headquarters only","At RIDOT weigh stations along I-95"],"answer":0,"explanation":"RI commercial skills tests are given by appointment at the CDL test site, 400 Romano Vineyard Way, North Kingstown. The Cranston DMV handles in-person CDL counter transactions and knowledge testing, but the skills test is conducted at the North Kingstown site. Source: RI DMV, Commercial Skills Test page.","handbook":"","hbref":""},{"q":"How long must an applicant have held a regular (Class D) driver's license before applying for a Rhode Island CDL?","options":["At least 2 years","At least 6 months","At least 1 year","At least 3 years"],"answer":0,"explanation":"Rhode Island requires that a CDL applicant has been a licensed driver for a minimum of two (2) years at the time of application. Source: RI DMV, Commercial Driving License (CDL) / Commercial Learner's Permit and Exams pages.","handbook":"","hbref":""},{"q":"Under Rhode Island rules, what is the minimum age to obtain a CDL for intrastate (within-state only) driving?","options":["18 years old","16 years old","21 years old","25 years old"],"answer":0,"explanation":"At 18 you may receive a Rhode Island CDL for intrastate (within-state) travel only; you must be 21 to drive interstate (across state lines). Source: RI DMV, Commercial Driving License (CDL) page.","handbook":"","hbref":""},{"q":"What is the minimum age required in Rhode Island to drive a commercial vehicle interstate (across state lines)?","options":["21 years old","18 years old","19 years old","23 years old"],"answer":0,"explanation":"Rhode Island, following the federal standard, requires a driver to be 21 years old for interstate commercial operation; 18- to 20-year-olds are limited to intrastate driving. Source: RI DMV, Commercial Driving License (CDL) page.","handbook":"","hbref":""},{"q":"Which application form must be completed to apply for a Rhode Island CDL?","options":["The Application for Commercial Driver's License (CDL-1)","Form MCSA-5876","The Standard License Application (LI-1)","Form DL-44C"],"answer":0,"explanation":"Rhode Island applicants complete the Application for Commercial Driver's License (CDL-1), which also includes the driver-history affidavit. Source: RI DMV, Commercial Learner's Permit and Exams page (CDL-1 form).","handbook":"","hbref":""},{"q":"In Rhode Island, what proof of legal presence must a CDL applicant provide?","options":["Proof of U.S. citizenship or lawful permanent residency","A valid passport from any country","Only a Social Security card, with no further proof","A notarized statement of residency from an employer"],"answer":0,"explanation":"The RI DMV requires all CDL applicants to provide proof of status as a U.S. citizen or lawful permanent resident, along with proof of Rhode Island residency. Source: RI DMV, Commercial Driving License (CDL) page.","handbook":"","hbref":""},{"q":"Which knowledge exam is the minimum requirement to obtain a Rhode Island Commercial Learner's Permit (CLP)?","options":["The General Knowledge test","The Air Brakes test","The Combination Vehicles test","The Hazardous Materials test"],"answer":0,"explanation":"The General Knowledge exam is the minimum requirement for a CLP in Rhode Island; additional knowledge tests are required depending on the class and endorsements sought. Source: RI DMV, Commercial Learner's Permit and Exams page.","handbook":"","hbref":""},{"q":"On the Rhode Island General Knowledge CDL test (50 questions), what score is needed to pass?","options":["80% (40 of 50 correct)","70% (35 of 50 correct)","75% (38 of 50 correct)","90% (45 of 50 correct)"],"answer":0,"explanation":"Rhode Island follows the standard CDL passing threshold of 80%; on the 50-question General Knowledge test that means 40 correct answers. Source: RI CDL Manual / RI DMV knowledge-testing standards.","handbook":"","hbref":""},{"q":"How long is a Rhode Island Commercial Learner's Permit (CLP) valid, and can it be renewed?","options":["Valid for one year maximum and non-renewable","Valid for 180 days and renewable once","Valid for two years and renewable","Valid for 60 days and non-renewable"],"answer":0,"explanation":"A Rhode Island CLP is valid for one year maximum and is non-renewable; if it expires the applicant must retake all knowledge exams and repay fees. Source: RI DMV, Commercial Learner's Permit and Exams page.","handbook":"","hbref":""},{"q":"After obtaining a Rhode Island CLP, how long must it be held before the holder may take the CDL skills test?","options":["At least 14 days","At least 30 days","At least 7 days","At least 60 days"],"answer":0,"explanation":"Consistent with the federal rule it follows, Rhode Island requires the CLP to be held for at least 14 days before taking the CDL skills test. Source: RI DMV, Commercial Skills Test page (FMCSA 49 CFR 383 standard).","handbook":"","hbref":""},{"q":"What are the three parts of the Rhode Island CDL skills test?","options":["Vehicle Inspection, Basic Control Skills, and Road Test","Written test, Vision test, and Road Test","Air Brakes, Backing, and Highway Driving","Pre-trip, Hazardous Materials, and Night Driving"],"answer":0,"explanation":"The Rhode Island skills test has three parts: the Vehicle Inspection (pre-trip) Test, the Basic Control Skills Test, and the Road Test; an applicant must pass all three. Source: RI DMV, Commercial Skills Test page.","handbook":"","hbref":""},{"q":"Who must supply the vehicle used for the Rhode Island CDL skills test, and what condition must it be in?","options":["The applicant provides their own vehicle, which must arrive empty (no cargo)","The DMV provides a state-owned test vehicle for all applicants","The applicant's employer must provide a loaded test vehicle","Any rented box truck, regardless of weight class, is acceptable"],"answer":0,"explanation":"In Rhode Island the candidate must provide their own representative vehicle, and it must arrive empty (no cargo); tankers must be certified empty, cleaned, and purged. Source: RI DMV, Commercial Skills Test page.","handbook":"","hbref":""},{"q":"Besides the CLP and operator license, which documents must be presented for the Rhode Island skills test?","options":["Valid vehicle registration, proof of active insurance, and a valid inspection sticker","A high-school diploma and proof of employment","A passport and birth certificate only","A notarized letter from a CDL training school"],"answer":0,"explanation":"Rhode Island requires hard copies of the CLP and operator license plus valid vehicle (and trailer, if applicable) registration, proof of active insurance, and an active vehicle inspection sticker. Source: RI DMV, Commercial Skills Test page.","handbook":"","hbref":""},{"q":"Under Rhode Island rules, when must Entry-Level Driver Training (ELDT) be completed for a first-time Class A or Class B applicant?","options":["Before taking the CDL skills test","Within 30 days after passing the skills test","Only after the CDL has already been issued","It is optional and may be skipped with employer approval"],"answer":0,"explanation":"ELDT must be successfully completed with a registered provider before a first-time Class A/B applicant is permitted to take the CDL skills test. Source: RI DMV, ELDT page (federal ELDT rule, effective Feb 7, 2022).","handbook":"","hbref":""},{"q":"For which endorsement does Rhode Island require ELDT to be completed before the KNOWLEDGE test (not the skills test)?","options":["The Hazardous Materials (H) endorsement","The Passenger (P) endorsement","The School Bus (S) endorsement","The Doubles/Triples (T) endorsement"],"answer":0,"explanation":"For the Hazardous Materials (H) endorsement, ELDT must be completed before taking the knowledge test; for P and S endorsements ELDT is completed before the skills test. Source: RI DMV, ELDT page.","handbook":"","hbref":""},{"q":"Where should a Rhode Island applicant search to find an approved ELDT training provider?","options":["The FMCSA Training Provider Registry (TPR)","The RI DMV CLP wait-list portal","The National Registry of Certified Medical Examiners","The RIDOT permit office vendor list"],"answer":0,"explanation":"Approved ELDT providers are listed on the FMCSA Training Provider Registry (tpr.fmcsa.dot.gov); completion can also be verified there. Source: RI DMV, ELDT page.","handbook":"","hbref":""},{"q":"How many self-certification commerce categories must a Rhode Island CDL applicant choose from?","options":["Four categories","Two categories","Three categories","Six categories"],"answer":0,"explanation":"A Rhode Island applicant must self-certify into one of four categories: Interstate Non-Excepted, Interstate Excepted, Intrastate Non-Excepted, or Intrastate Excepted. Source: RI DMV, Medical Certification / Self-Certification page.","handbook":"","hbref":""},{"q":"A Rhode Island driver who certifies as 'Interstate Non-Excepted' must do what?","options":["Obtain and maintain a federal DOT Medical Examiner's Certificate","Avoid carrying any cargo across state lines","Renew the CDL annually instead of every five years","Skip the road test because of their interstate status"],"answer":0,"explanation":"Interstate Non-Excepted drivers operate within and outside Rhode Island and are required to obtain a federal DOT Medical Examiner's Certificate; excepted categories are not. Source: RI DMV, Medical Certification / Self-Certification page.","handbook":"","hbref":""},{"q":"How is a non-excepted Rhode Island CDL driver's DOT medical certification now transmitted to the DMV?","options":["The certified medical examiner electronically submits it to the FMCSA National Registry, which forwards it to the RI DMV","The driver mails a paper copy of the medical card directly to the RI DMV","The employer faxes the certificate to RIDOT for filing","The driver uploads it through the RI E-ZPass account portal"],"answer":0,"explanation":"The RI DMV no longer accepts medical certification directly; the certified medical examiner electronically submits the Medical Examiner's Certificate (Form MCSA-5876/5875) to the FMCSA National Registry, which forwards it to the DMV. Failure to keep it current results in a CDL downgrade. Source: RI DMV, Medical Certification page; National Registry of Certified Medical Examiners.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная разрешённая ширина коммерческого транспортного средства или его груза на автомагистралях Род-Айленда без специального разрешения?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"Свод законов Род-Айленда (Rhode Island General Laws) § 31-25-3 устанавливает максимальную ширину любого транспортного средства или его груза в 102 inches (8 feet 6 inches). Всё, что шире, требует получения разрешения на негабарит от RIDOT. Источник: R.I. Gen. Laws § 31-25-3."},"1":{"q":"Какова максимальная разрешённая высота транспортного средства, включая груз, на автомагистралях Род-Айленда без разрешения?","options":["162 inches (13 feet 6 inches)","156 inches (13 feet)","168 inches (14 feet)","150 inches (12 feet 6 inches)"],"explanation":"Свод законов Род-Айленда (Rhode Island General Laws) § 31-25-4 ограничивает высоту транспортного средства, включая груз, до 162 inches (13 feet 6 inches). Грузы, превышающие эту величину, требуют получения разрешения на превышение высоты от RIDOT. Источник: R.I. Gen. Laws § 31-25-4."},"2":{"q":"Какова максимальная общая полная масса в фунтах для транспортного средства или автопоезда на автомагистралях Род-Айленда без разрешения на перевес?","options":["73,280 pounds","80,000 pounds","88,000 pounds","100,000 pounds"],"explanation":"Род-Айленд ограничивает общую полную массу до 80,000 pounds, что соответствует федеральному стандарту для межштатных автомагистралей (Interstate), если только не получено специальное разрешение. Источник: R.I. Gen. Laws § 31-25-14; RIDOT Manual for Overweight and Oversize Vehicle Permits."},"3":{"q":"В Род-Айленде полная масса, передаваемая на дорогу колёсами любой одиночной оси, не может превышать сколько фунтов?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"Свод законов Род-Айленда (Rhode Island General Laws) § 31-25-13 устанавливает предел для одиночной оси в 22,400 pounds. Это выше федерального стандарта для одиночной оси на межштатных автомагистралях (Interstate), составляющего 20,000 pounds, — это специфическая для штата Род-Айленд величина. Источник: R.I. Gen. Laws § 31-25-13."},"4":{"q":"Какова максимальная разрешённая масса на сдвоенную группу осей в Род-Айленде, когда расстояние между осями не превышает 8 feet?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Свод законов Род-Айленда (Rhode Island General Laws) § 31-25-14 ограничивает сдвоенную группу осей до 36,000 pounds, когда расстояние между осями не превышает 8 feet. Источник: R.I. Gen. Laws § 31-25-14."},"5":{"q":"Как по закону Род-Айленда определяется одиночная «осевая нагрузка» (axle load) для целей ограничения массы?","options":["Суммарная нагрузка на все колёса, расположенные между двумя параллельными поперечными вертикальными плоскостями на расстоянии 40 inches друг от друга","Суммарная нагрузка на все колёса, расположенные между двумя плоскостями на расстоянии 96 inches друг от друга","Нагрузка, приходящаяся на любую одну шину транспортного средства","Половина зарегистрированной полной массы транспортного средства"],"explanation":"Свод законов Род-Айленда (Rhode Island General Laws) § 31-25-13 определяет осевую нагрузку как суммарную нагрузку, передаваемую на дорогу всеми колёсами, центры которых расположены между двумя параллельными поперечными вертикальными плоскостями на расстоянии 40 inches друг от друга, по всей ширине транспортного средства. Источник: R.I. Gen. Laws § 31-25-13."},"6":{"q":"Какова максимальная длина одиночного транспортного средства (не автопоезда), включая груз и бамперы, на автомагистралях Род-Айленда?","options":["35 feet","40 feet","48 feet","53 feet"],"explanation":"Свод законов Род-Айленда (Rhode Island General Laws) § 31-25-5 ограничивает одиночное транспортное средство, включая любой груз, до 40 feet в общей длине (45 feet для автобуса, моторизованного автодома или кемпингового рекреационного транспортного средства). Источник: R.I. Gen. Laws § 31-25-5."},"7":{"q":"В Род-Айленде какова максимальная длина одиночного автобуса, моторизованного автодома или кемпингового рекреационного транспортного средства?","options":["40 feet","42 feet","45 feet","48 feet"],"explanation":"Свод законов Род-Айленда (Rhode Island General Laws) § 31-25-5 разрешает автобусу, моторизованному автодому или кемпинговому рекреационному транспортному средству достигать 45 feet, тогда как другие одиночные транспортные средства ограничены до 40 feet. Источник: R.I. Gen. Laws § 31-25-5."},"8":{"q":"Какова максимальная длина полуприцепа, эксплуатируемого в Род-Айленде, без учёта бамперов и принадлежностей?","options":["48 feet 6 inches","51 feet","53 feet","57 feet"],"explanation":"Свод законов Род-Айленда (Rhode Island General Laws) § 31-25-6 разрешает полуприцепы длиной до 53 feet, без учёта бамперов и принадлежностей. Источник: R.I. Gen. Laws § 31-25-6."},"9":{"q":"В Род-Айленде полуприцепы длиннее какой величины могут эксплуатироваться только на системе межштатных автомагистралей (Interstate) и на дорогах, специально назначенных директором?","options":["45 feet","48 feet 6 inches","50 feet","53 feet"],"explanation":"Свод законов Род-Айленда (Rhode Island General Laws) § 31-25-6 ограничивает эксплуатацию полуприцепов, превышающих 48 feet 6 inches, системой межштатных автомагистралей (Interstate) и автомагистралями, улицами и дорогами, назначенными директором. Источник: R.I. Gen. Laws § 31-25-6."},"10":{"q":"Какое ведомство выдаёт разрешения на негабаритные и перевесные транспортные средства в Род-Айленде?","options":["Департамент транспорта Род-Айленда (RIDOT)","Полиция штата Род-Айленд","Федеральное управление автомобильных дорог (Federal Highway Administration)","Местный городской клерк или клерк населённого пункта, где начинается поездка"],"explanation":"Специальные разрешения для транспортных средств, превышающих установленные пределы по габаритам или массе, выдаются Департаментом транспорта штата (RIDOT). Источник: RIDOT Manual for Overweight and Oversize Vehicle Permits; R.I. Gen. Laws § 31-25-18."},"11":{"q":"Какую формулу использует Род-Айленд для определения допустимой полной массы на любую группу последовательных осей?","options":["Федеральную мостовую формулу (Bridge Formula): W = 500[(LN/(N-1)) + 12N + 36]","Полная масса = 1,000 pounds на каждый дюйм ширины шины","Полная масса = 34,000 pounds на группу осей, фиксированно","Полная масса = 80,000, делённое на число осей"],"explanation":"Свод законов Род-Айленда (Rhode Island General Laws) § 31-25-14 применяет федеральную мостовую формулу (Bridge Formula), W = 500[(LN/(N-1)) + 12N + 36], где W — полная масса на группу последовательных осей, L — расстояние в футах между крайними осями группы, а N — число осей. Источник: R.I. Gen. Laws § 31-25-14."},"12":{"q":"В мостовой формуле Род-Айленда W = 500[(LN/(N-1)) + 12N + 36] что обозначает переменная «N»?","options":["Число осей в рассматриваемой группе","Чистую массу только груза","Число шин на ведущей оси","Номинальную ширину транспортного средства в футах"],"explanation":"В мостовой формуле (Bridge Formula), принятой Род-Айлендом, N — это число осей в группе, L — расстояние в футах между крайними осями, а W — максимально допустимая полная масса на эту группу. Источник: R.I. Gen. Laws § 31-25-14."},"13":{"q":"Согласно правилам Род-Айленда о массе, если мостовая формула даёт для сдвоенной оси предел ниже 36,000 pounds, какое значение используется как законный предел?","options":["Должен использоваться меньший результат формулы","Используется 34,000 pounds","За законный предел принимается 36,000 pounds","Перед загрузкой группу осей необходимо переразместить"],"explanation":"Свод законов Род-Айленда (Rhode Island General Laws) § 31-25-14 предусматривает, что когда мостовая формула (Bridge Formula) даёт для сдвоенной оси величину ниже 36,000 pounds, законным пределом считается 36,000 pounds. Источник: R.I. Gen. Laws § 31-25-14."},"14":{"q":"Перевозчику необходимо переместить неделимый груз шириной 11 feet по автомагистрали Род-Айленда. Что должен сделать перевозчик?","options":["Ничего; 11 feet находится в пределах разрешённой ширины","Получить разрешение на негабарит от RIDOT перед перемещением","Уведомить только местный полицейский участок","Сначала уменьшить груз до 96 inches"],"explanation":"Поскольку 11 feet (132 inches) превышает разрешённую ширину в 102 inches по § 31-25-3, перевозчик должен получить разрешение на негабарит от RIDOT перед перемещением груза. Источник: R.I. Gen. Laws § 31-25-3 и § 31-25-18; RIDOT Permit Manual."},"15":{"q":"Какова стандартная плата RIDOT за одну поездку для перемещения неделимого негабаритного или перевесного транспортного средства или груза в Род-Айленде?","options":["$10.00 per trip","$20.00 per trip","$50.00 per trip","$100.00 per trip"],"explanation":"RIDOT Manual for Overweight and Oversize Vehicle Permits взимает плату $20.00 за поездку для перемещения неделимых транспортных средств или грузов. Источник: RIDOT Manual for Overweight and Oversize Vehicle Permits, Sec. 4.4."},"16":{"q":"Вместо оплаты поездок по отдельности перевозчик, совершающий повторяющиеся внутриштатные негабаритные/перевесные перемещения в Род-Айленде, может получить генеральное (blanket) разрешение за какую плату?","options":["$50.00","$100.00","$250.00","$500.00"],"explanation":"RIDOT permit manual допускает получение генерального (blanket) разрешения для внутриштатных перемещений за $100.00 вместо оплаты поездок по отдельности. Источник: RIDOT Manual for Overweight and Oversize Vehicle Permits, Sec. 4.4."},"17":{"q":"Согласно разрешительному руководству Род-Айленда, сколько сопровождающих (лидирующих) транспортных средств требуется для груза с общей шириной более 14 feet 6 inches?","options":["Сопровождение не требуется","Одно сопровождающее транспортное средство","Два сопровождающих транспортных средства","Четыре сопровождающих транспортных средства"],"explanation":"RIDOT permit manual требует одно сопровождение для ширины от 12 feet 0 inches до 14 feet 6 inches и два сопровождающих транспортных средства для ширины более 14 feet 6 inches. Источник: RIDOT Manual for Overweight and Oversize Vehicle Permits, Sec. 5.4."},"18":{"q":"Согласно разрешительному руководству Род-Айленда, когда разрешённые негабаритные/перевесные перемещения, как правило, НЕ допускаются?","options":["С заката в пятницу до рассвета в понедельник и в перечисленные праздничные дни","Только с полуночи до 4:00 a.m. ежедневно","Только в течение первой недели каждого месяца","Никогда; разрешённые перемещения могут выполняться в любое время"],"explanation":"RIDOT permit manual запрещает перемещения, если не указано иное, с заката в пятницу до рассвета в понедельник и в перечисленные официальные праздничные дни. Источник: RIDOT Manual for Overweight and Oversize Vehicle Permits, Sec. 4.15 / 5.7."},"19":{"q":"Как закон Род-Айленда трактует сельскохозяйственные транспортные средства, сельскохозяйственные тракторы, дорожную технику и пожарную технику применительно к ограничениям по габаритам и массе главы 31-25?","options":["Они освобождены от ограничений по габаритам и массе","Они ограничены 50% от обычных пределов массы","Они должны постоянно иметь годовое разрешение на негабарит","Им запрещён выезд на все нумерованные автомагистрали штата"],"explanation":"Свод законов Род-Айленда (Rhode Island General Laws) § 31-25-2 освобождает пожарную технику, дорожную технику и сельскохозяйственные транспортные средства (включая сельскохозяйственные тракторы), временно перемещаемые по автомагистрали, от ограничений по габаритам и массе главы 31-25. Источник: R.I. Gen. Laws § 31-25-2."},"20":{"q":"В Род-Айленде каков минимальный возраст для получения CDL, действительного только для ВНУТРИШТАТНОЙ (в пределах штата) эксплуатации?","options":["16 лет","18 лет","21 год","25 лет"],"explanation":"RI CDL Manual (Guidelines for CDL Applicants) указывает, что вы должны иметь действующее водительское удостоверение не менее двух лет и быть не моложе 18 лет для CDL ТОЛЬКО для ВНУТРИШТАТНОЙ эксплуатации; для межштатной требуется 21 год. Источник: RI DMV Commercial Driver License Manual (AAMVA 2005, Rev. July 2014)."},"21":{"q":"Каков минимальный возраст, требуемый в Род-Айленде для управления коммерческим транспортным средством в МЕЖШТАТНОЙ торговле (с пересечением границ штатов)?","options":["18 лет","19 лет","21 год","23 года"],"explanation":"RI DMV требует, чтобы водителю был 21 год для получения права на межштатную (с пересечением границ штатов) эксплуатацию CDL; 18 лет дают право только на внутриштатную. Источник: RI DMV CDL page и RI Commercial Driver License Manual (Rev. July 2014)."},"22":{"q":"Согласно классификации CDL Род-Айленда, какой класс даёт право управлять любым СОСТАВОМ (автопоездом) транспортных средств с GCWR 26,001 lbs или более, при условии, что GVWR буксируемой(ых) единицы(единиц) превышает 10,000 lbs?","options":["Class A","Class B","Class C","Class D"],"explanation":"Согласно RI CDL Manual, CDL класса Class A даёт право управлять любым составом транспортных средств с GCWR 26,001 фунтов или более при условии, что GVWR буксируемого(ых) транспортного(ых) средства(средств) превышает 10,000 фунтов. Источник: RI Commercial Driver License Manual, License Classes."},"23":{"q":"В Род-Айленде CDL, дающий право на ОДИНОЧНОЕ транспортное средство с GVWR 26,001 lbs или более (или на такое транспортное средство, буксирующее единицу с GVWR не более 10,000 lbs), относится к какому классу?","options":["Class A","Class B","Class C","Class E"],"explanation":"RI CDL Manual определяет Class B как любое одиночное транспортное средство с GVWR 26,001 фунтов или более, или такое транспортное средство, буксирующее транспортное средство с GVWR не более 10,000 фунтов. Источник: RI Commercial Driver License Manual, License Classes."},"24":{"q":"Какой класс CDL Род-Айленда охватывает транспортное средство (не отвечающее требованиям Class A или B), предназначенное для перевозки 16 или более пассажиров, включая водителя, либо снабжённое табличками для опасных материалов?","options":["Class A","Class B","Class C","Class M"],"explanation":"RI CDL Manual определяет Class C как любое транспортное средство, не отвечающее требованиям Class A или B, но предназначенное для перевозки 16 или более пассажиров, включая водителя, либо снабжённое табличками для опасных материалов. Источник: RI Commercial Driver License Manual, License Classes."},"25":{"q":"На CDL Род-Айленда какой код дополнения (endorsement) требуется для перевозки опасных материалов в количествах, требующих установки табличек согласно федеральным правилам DOT?","options":["Code N","Code H","Code T","Code P"],"explanation":"Согласно RI CDL Manual, дополнение H (HazMat) требуется для ЛЮБОГО класса лицензии при перевозке опасных материалов в любом количестве, требующем установки табличек согласно федеральным правилам DOT. Источник: RI Commercial Driver License Manual, Endorsements."},"26":{"q":"Какое дополнение требует Род-Айленд для управления цистерной, перевозящей жидкий или газообразный материал, либо переносной цистерной вместимостью 1,000 gallons или более?","options":["N - Tank Vehicles","T - Double/Triple Trailers","P - Passenger","S - School Bus"],"explanation":"RI CDL Manual указывает, что дополнение N (Tank Vehicles) требуется для любого класса лицензии при перевозке жидкого или газообразного материала в цистерне, либо в любой переносной цистерне вместимостью 1,000 gallons или более. Источник: RI Commercial Driver License Manual, Endorsements."},"27":{"q":"В Род-Айленде дополнение T (Double/Triple Trailers) может быть получено только водителями, имеющими какой класс CDL?","options":["Водители Class C","Водители Class B","Водители Class A","Водители любого класса"],"explanation":"RI CDL Manual указывает, что дополнение T (Double/Triple Trailers) требуется для водителей Class A, которые перевозят двойные/тройные прицепы там, где такая эксплуатация разрешена законом. Источник: RI Commercial Driver License Manual, Endorsements."},"28":{"q":"Перед тестированием какой дополнительный шаг требует Род-Айленд для дополнения школьного автобуса (S) помимо письменного экзамена и теста навыков?","options":["Оценку угрозы безопасности TSA (security threat assessment)","Сертификат школьного автобуса Род-Айленда (RI School Bus Certificate) через DMV School Bus Safety Office","Заявление на зелёную лицензию шофёра (green chauffeur license)","Тест на знание двойных/тройных прицепов"],"explanation":"RI CDL Manual указывает, что водители с дополнением S (School Bus) должны сначала получить Сертификат школьного автобуса Род-Айленда (RI School Bus Certificate) через DMV School Bus Safety Office. Источник: RI Commercial Driver License Manual, Endorsements."},"29":{"q":"Согласно RI CDL Manual, дополнение P (Passenger) требуется, когда транспортное средство предназначено для сидячих мест более чем на скольких человек, включая водителя?","options":["8","12","15","16"],"explanation":"RI CDL Manual указывает, что дополнение P требуется для любого класса лицензии, когда транспортное средство предназначено для сидячих мест более чем на 16 пассажиров, включая водителя; также необходимо заполнить заявление на зелёную лицензию шофёра (green chauffeur license). Источник: RI Commercial Driver License Manual, Endorsements."},"30":{"q":"Какое дополнение CDL Род-Айленда объединяет дополнения HazMat и Tank Vehicle, требуя сдачи обоих экзаменов на знание?","options":["Code S","Code T","Code X","Code P"],"explanation":"RI CDL Manual описывает дополнение X как сочетание H (HazMat) и N (Tank); должны быть сданы оба экзамена. Источник: RI Commercial Driver License Manual, Endorsements."},"31":{"q":"Согласно федеральным правилам, применяемым в Род-Айленде, как долго необходимо удерживать ученическое коммерческое разрешение (Commercial Learner's Permit), прежде чем его обладатель сможет сдавать тест навыков CDL?","options":["7 days","14 days","30 days","60 days"],"explanation":"Федеральное правило 49 CFR 383.25, применяемое RI DMV, запрещает обладателю CLP сдавать тест навыков CDL в течение первых 14 days после первоначальной выдачи CLP. Источник: 49 CFR 383.25; RI DMV CLP requirements."},"32":{"q":"Какой тест на знание должен сдать КАЖДЫЙ заявитель на CDL в Род-Айленде, независимо от запрашиваемого класса или дополнения?","options":["Тест по воздушным тормозам (Air Brakes)","Тест по составным транспортным средствам (Combination Vehicles)","Тест на общие знания (General Knowledge)","Тест по перевозке пассажиров (Passenger Transport)"],"explanation":"RI CDL Manual указывает, что тест на общие знания (General Knowledge) сдают все заявители; остальные тесты зависят от класса и дополнений. Источник: RI Commercial Driver License Manual, Section 1, Knowledge Tests."},"33":{"q":"На экзамене CDL Род-Айленда по общим знаниям (General Knowledge), на сколько из 50 вопросов нужно ответить правильно, чтобы сдать (80%)?","options":["30","40","44","45"],"explanation":"Расписание электронных/ручных тестов в RI CDL Manual указывает тест на общие знания как 50 вопросов, требующий 40 правильных ответов (80%) для сдачи. Источник: RI Commercial Driver License Manual, Electronic/Manual Tests."},"34":{"q":"Какое ведомство проводит и назначает дорожный тест (тест навыков) CDL для заявителей в Род-Айленде?","options":["Главный офис RI DMV в Крэнстоне","Общественный колледж Род-Айленда (CCRI)","Полиция штата Род-Айленд","Офис разрешений DOT Род-Айленда"],"explanation":"RI CDL Manual указывает, что дорожные тесты проводятся Общественным колледжем Род-Айленда (CCRI) и должны быть назначены через него. Источник: RI Commercial Driver License Manual, Road Tests."},"35":{"q":"Какой из следующих документов является обязательным для заявителя на CDL в Род-Айленде согласно руководству RI DMV по CLP?","options":["Действующая карточка социального страхования (Social Security card)","Нотариально заверенное письмо работодателя","Титул на коммерческое транспортное средство","Мотоциклетное дополнение"],"explanation":"RI CDL Manual требует, чтобы все заявители предъявили действующую карточку социального страхования (Social Security card), действующую медицинскую карту (Medical Card) (если они не относятся к исключённым) и подтверждение личности/места жительства. Источник: RI Commercial Driver License Manual, Guidelines for CDL Applicants."},"36":{"q":"Федеральная подготовка водителей начального уровня (ELDT), действующая в Род-Айленде, должна быть пройдена через провайдера, внесённого в какой реестр?","options":["Базу данных по обучению DMV штата","Реестр провайдеров обучения FMCSA (Training Provider Registry, TPR)","Список водительского образования AAMVA","Список одобренных TSA школ"],"explanation":"С 7 февраля 2022 года заявители на Class A/B впервые, переходящие с B на A, а также новые соискатели дополнений P/S/H должны пройти ELDT у провайдера, внесённого в FMCSA Training Provider Registry, перед тестом навыков (тестом на знание для H). Источник: FMCSA ELDT rule; FMCSA Training Provider Registry."},"37":{"q":"При самостоятельном подтверждении медицинского статуса в RI DMV какая из следующих категорий является одной из четырёх допустимых, из которых должен выбрать обладатель CDL?","options":["Межштатная торговля, не исключённая (Interstate Commerce Non-excepted)","Рекреационная торговля, освобождённая (Recreational Commerce Exempt)","Иностранная торговля, сертифицированная (Foreign Commerce Certified)","Сельскохозяйственная торговля, с отказом (Agricultural Commerce Waived)"],"explanation":"RI CDL Manual перечисляет четыре категории самостоятельного подтверждения: Interstate Excepted, Interstate Non-excepted, Intrastate Excepted и Intrastate Non-excepted. Не исключённые (Non-excepted) водители должны предъявить действующую медицинскую карту (49 CFR 391.45). Источник: RI Commercial Driver License Manual, Self-Certification."},"38":{"q":"Согласно RI CDL Manual, в течение скольких дней обладатель CDL должен предъявить в DMV новую медицинскую карту (Medical Card) после её выдачи?","options":["10 days","15 days","30 days","45 days"],"explanation":"RI CDL Manual указывает, что вы должны предъявить в DMV вашу новую медицинскую карту (Medical Card) в течение 15 days с момента выдачи; несоблюдение этого может привести к понижению класса вашей лицензии. Источник: RI Commercial Driver License Manual, Medical Certification."},"39":{"q":"При управлении коммерческим транспортным средством в Род-Айленде какова концентрация алкоголя в крови (BAC), при которой и выше которой водитель считается юридически опьянённым применительно к CMV?","options":["0.04%","0.08%","0.02%","0.10%"],"explanation":"В Род-Айленде управление CMV с BAC 0.04% или выше является серьёзным нарушением (major offense), что составляет половину предела 0.08%, применяемого к некоммерческим водителям. Источник: R.I. Gen. Laws 31-10.3-31; RI CDL Manual, Section 2."},"40":{"q":"Согласно закону Род-Айленда о предполагаемом согласии (implied consent), обладатель CDL, который отказывается пройти химический анализ дыхания, крови или мочи при законном требовании, рассматривается как совершивший что?","options":["Серьёзное нарушение (major offense), как и осуждение за DUI","Только серьёзное нарушение правил дорожного движения (serious traffic violation)","Нарушение приказа о выводе из эксплуатации (out-of-service order)","Не подлежащий учёту административный вопрос"],"explanation":"В Род-Айленде отказ от обязательного химического анализа является серьёзным нарушением (major offense), влекущим такую же дисквалификацию, как осуждение за DUI. Источник: R.I. Gen. Laws 31-10.3-31; RI CDL Manual, Section 2."},"41":{"q":"В Род-Айленде каков минимальный срок дисквалификации обладателя CDL за ПЕРВОЕ серьёзное нарушение (major offense), такое как DUI на CMV, когда НЕ перевозятся опасные материалы, требующие табличек?","options":["1 год","60 days","3 года","6 месяцев"],"explanation":"Род-Айленд дисквалифицирует водителя не менее чем на 1 год за первое серьёзное нарушение (major offense) (DUI, BAC 0.04+, отказ от анализа, оставление места происшествия или использование CMV в совершении тяжкого преступления). Источник: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"42":{"q":"В Род-Айленде, если водитель совершает первое серьёзное нарушение (major offense) во время перевозки опасных материалов, требующих табличек, минимальный срок дисквалификации увеличивается до:","options":["3 года","1 год","120 days","5 лет"],"explanation":"Первое серьёзное нарушение (major offense) при управлении транспортным средством с табличками опасных грузов влечёт минимальную дисквалификацию на 3 года в Род-Айленде вместо стандартного 1 года. Источник: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"43":{"q":"В Род-Айленде обладатель CDL, осуждённый за ВТОРОЕ серьёзное нарушение (major offense) в течение жизни, сталкивается с какой дисквалификацией?","options":["Пожизненная дисквалификация","Дисквалификация на 10 лет","Дисквалификация на 3 года","Дисквалификация на 1 год"],"explanation":"Второе серьёзное нарушение (major offense) в течение жизни влечёт пожизненную дисквалификацию в Род-Айленде (которая при определённых условиях может быть сокращена минимум до 10 лет). Источник: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"44":{"q":"Сколько серьёзных нарушений правил дорожного движения (serious traffic violations) в течение периода 3 years (возникших в результате отдельных происшествий) влекут дисквалификацию CDL на 60 days в Род-Айленде?","options":["2","3","4","1"],"explanation":"Два серьёзных нарушения правил дорожного движения (serious traffic violations) на CMV в течение 3 years влекут дисквалификацию на 60 days в Род-Айленде. Источник: R.I. Gen. Laws 31-10.3-31; RI CDL Manual, Section 2."},"45":{"q":"В Род-Айленде три серьёзных нарушения правил дорожного движения (serious traffic violations) в течение периода 3 years влекут дисквалификацию CDL на какой срок?","options":["120 days","60 days","90 days","1 год"],"explanation":"Три серьёзных нарушения правил дорожного движения (serious traffic violations) на CMV в течение 3 years влекут дисквалификацию на 120 days в Род-Айленде. Источник: R.I. Gen. Laws 31-10.3-31; RI CDL Manual, Section 2."},"46":{"q":"Какое из следующих относится к СЕРЬЁЗНЫМ нарушениям правил дорожного движения (serious traffic violation) для обладателя CDL в Род-Айленде?","options":["Слишком близкое следование за идущим впереди транспортным средством","Управление CMV с BAC 0.04%","Отказ от химического анализа","Нарушение приказа о выводе из эксплуатации (out-of-service order)"],"explanation":"Слишком близкое следование является одним из перечисленных серьёзных нарушений правил дорожного движения (serious traffic violations); остальные варианты — это серьёзные нарушения (major offenses) или нарушения вывода из эксплуатации (out-of-service) с отдельными наказаниями. Источник: RI CDL Manual, Section 2; 49 CFR 383.51."},"47":{"q":"Применительно к серьёзному нарушению правил дорожного движения (serious traffic violation) в Род-Айленде, чрезмерное превышение скорости определяется как движение на сколько миль в час или более выше установленного ограничения скорости?","options":["15 mph или более","10 mph или более","20 mph или более","25 mph или более"],"explanation":"Превышение скорости на 15 mph или более сверх установленного ограничения является серьёзным нарушением правил дорожного движения (serious traffic violation) применительно к CDL в Род-Айленде. Источник: RI CDL Manual, Section 2; 49 CFR 383.51."},"48":{"q":"Согласно федеральным правилам, принятым в Род-Айленде, использование ручного мобильного телефона или отправка текстовых сообщений при управлении CMV считается каким типом нарушения для целей дисквалификации?","options":["Серьёзным нарушением правил дорожного движения (serious traffic violation)","Серьёзным нарушением (major offense)","Нарушением приказа о выводе из эксплуатации (out-of-service order)","Нарушением на железнодорожном переезде"],"explanation":"Отправка текстовых сообщений или использование ручного телефона при управлении CMV является серьёзным нарушением правил дорожного движения (serious traffic violation) в Род-Айленде, засчитываемым в счёт дисквалификаций на 60 days/120 days. Источник: 49 CFR 383.51, 392.80-392.82; RI CDL Manual."},"49":{"q":"Сколько нарушений по отправке текстовых сообщений/использованию ручного телефона в течение периода 3 years влекут дисквалификацию CDL на 120 days в Род-Айленде?","options":["3 или более","2","5","4"],"explanation":"Поскольку отправка текстовых сообщений/использование ручного телефона являются серьёзными нарушениями правил дорожного движения (serious traffic violations), три или более в течение 3 years влекут дисквалификацию на 120 days (два влекут 60 days). Источник: 49 CFR 383.51, 392.82; RI CDL Manual."},"50":{"q":"В Род-Айленде ТРЕТЬЕ или последующее нарушение приказа о выводе из эксплуатации (out-of-service order) в течение периода 10 years (стандартная эксплуатация) влечёт какую дисквалификацию?","options":["3 года","1 год","5 лет","Пожизненную"],"explanation":"Третье или последующее нарушение приказа OOS в течение 10 years влечёт дисквалификацию на 3 года в Род-Айленде. Источник: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"51":{"q":"Если обладатель CDL в Род-Айленде нарушает приказ о выводе из эксплуатации (out-of-service order) во время перевозки опасных материалов, требующих табличек, либо при управлении транспортным средством, предназначенным для перевозки 16 или более пассажиров, дисквалификация за ПЕРВОЕ нарушение составляет не менее:","options":["180 days","90 days","1 год","60 days"],"explanation":"Первое нарушение OOS при перевозке опасных грузов или 16+ пассажиров повышает минимальную дисквалификацию до 180 days в Род-Айленде. Источник: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"52":{"q":"В Род-Айленде какова минимальная дисквалификация за ПЕРВОЕ нарушение обладателем CDL правил на железнодорожном переезде?","options":["60 days","30 days","90 days","120 days"],"explanation":"Первое нарушение на железнодорожном переезде влечёт минимальную дисквалификацию на 60 days в Род-Айленде. Источник: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"53":{"q":"В Род-Айленде ВТОРОЕ нарушение на железнодорожном переезде в течение периода 3 years влечёт минимальную дисквалификацию на:","options":["120 days","60 days","1 год","90 days"],"explanation":"Второе нарушение на железнодорожном переезде в течение 3 years влечёт минимальную дисквалификацию на 120 days в Род-Айленде. Источник: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"54":{"q":"В Род-Айленде ТРЕТЬЕ или последующее нарушение на железнодорожном переезде в течение периода 3 years влечёт минимальную дисквалификацию на:","options":["1 год","120 days","60 days","3 года"],"explanation":"Третье или последующее нарушение на железнодорожном переезде в течение 3 years влечёт минимальную дисквалификацию на 1 год в Род-Айленде. Источник: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"55":{"q":"Обладатель CDL в Род-Айленде осуждён за DUI при управлении СВОИМ собственным личным (некоммерческим) транспортным средством. Что происходит с его CDL?","options":["Он дисквалифицируется от управления CMV не менее чем на 1 год","Ничего, потому что это было не коммерческое транспортное средство","Он получает дисквалификацию только на 60 days","Ему грозит только наказание за серьёзное нарушение (serious violation)"],"explanation":"В Род-Айленде осуждение за DUI на любом транспортном средстве, включая личный автомобиль, дисквалифицирует обладателя CDL от управления CMV не менее чем на 1 год как серьёзное нарушение (major offense). Источник: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"56":{"q":"Какое из следующих является СЕРЬЁЗНЫМ нарушением (major offense) (дисквалификация на 1 год) для обладателя CDL в Род-Айленде, а не серьёзным нарушением правил дорожного движения (serious traffic violation)?","options":["Использование CMV в совершении тяжкого преступления (felony)","Слишком близкое следование","Неправильное или беспорядочное перестроение","Управление CMV без надлежащего класса или дополнения"],"explanation":"Использование CMV для совершения тяжкого преступления (felony) является серьёзным нарушением (major offense), влекущим дисквалификацию на 1 год; остальные варианты — это серьёзные нарушения правил дорожного движения (serious traffic violations). Источник: R.I. Gen. Laws 31-10.3-31; RI CDL Manual, Section 2; 49 CFR 383.51."},"57":{"q":"В Род-Айленде на каком расстоянии от ближайшего рельса школьный автобус с детьми, автобус с платными пассажирами или транспортное средство, перевозящее взрывчатые вещества либо легковоспламеняющиеся жидкости, должны остановиться перед пересечением железнодорожных путей?","options":["В пределах 100 футов, но не ближе 50 футов","В пределах 50 футов, но не ближе 15 футов","В пределах 25 футов, но не ближе 10 футов","В пределах 75 футов, но не ближе 25 футов"],"explanation":"RI General Laws § 31-20-4 требует, чтобы водитель любого автомобиля, перевозящего платных пассажиров, любого школьного автобуса со школьником или любого транспортного средства, перевозящего взрывчатые вещества либо легковоспламеняющиеся жидкости, остановился в пределах пятидесяти футов (50'), но не ближе пятнадцати футов (15') от ближайшего рельса. Источник: RIGL § 31-20-4."},"58":{"q":"Согласно законодательству Род-Айленда, требование об остановке на железнодорожном переезде для платных автобусов, школьных автобусов и перевозчиков взрывчатых веществ/легковоспламеняющихся жидкостей НЕ применяется в какой из ситуаций?","options":["Каждый раз, когда транспортное средство без груза или пассажиров","В любое время, когда у водителя есть допуск на перевозку опасных материалов","На любом переезде, оборудованном автоматическими шлагбаумами","На переезде, где сотрудник полиции или сигнал регулирования движения дает указание продолжать движение, либо на переездах в пределах делового или жилого района"],"explanation":"RIGL § 31-20-4 гласит, что остановку делать не нужно там, где сотрудник полиции или сигнал регулирования движения дает указание продолжать движение, и эта статья не применяется на железнодорожных переездах в одном уровне в пределах делового или жилого района. Пустой автобус или наличие шлагбаумов не отменяют это правило. Источник: RIGL § 31-20-4."},"59":{"q":"На разделенном шоссе в Род-Айленде в каком случае водитель НЕ обязан останавливаться перед остановившимся школьным автобусом с включенными мигающими красными огнями?","options":["Каждый раз, когда водитель движется со скоростью менее 20 mph","Когда водитель находится более чем в двух корпусах автомобиля от автобуса","Никогда — все водители всегда должны останавливаться в обоих направлениях","Когда автобус остановился на проезжей части по другую сторону разделенного шоссе относительно водителя"],"explanation":"RIGL § 31-20-13 предусматривает, что водителю не нужно останавливаться, если шоссе является разделенным и автобус остановился на проезжей части по одну сторону разделенного шоссе, тогда как водитель движется по другой стороне. RI DMV определяет разделенное шоссе как шоссе, разделенное барьером, отбойником или травяной/бетонной разделительной полосой. Источник: RIGL § 31-20-13; страница RI DMV School Buses."},"60":{"q":"Род-Айленд определяет «разделенное шоссе» для исключения об остановке перед школьным автобусом как проезжую часть, разделенную чем из перечисленного?","options":["Только двойной желтой осевой линией","Центральной двусторонней полосой для левых поворотов","Барьером типа Jersey, отбойником, травяной или бетонной разделительной полосой, деревьями, водой или подобным разделением между встречными полосами","Любой проезжей частью с тремя или более полосами в общей сложности"],"explanation":"RI DMV поясняет, что исключение для разделенного шоссе применяется только там, где встречные направления разделены барьером типа Jersey, отбойником, травяной или бетонной разделительной полосой, деревьями, водой и т. д. Нарисованная осевая линия или полоса для поворота разделителем не являются. Источник: страница RI DMV School Buses (толкование RIGL § 31-20-13)."},"61":{"q":"При встречном движении или обгоне школьного автобуса Род-Айленда с включенными мигающими красными огнями на обычной (неразделенной) двухполосной дороге что должен сделать водитель?","options":["Снизить скорость до 15 mph и проехать с осторожностью","Останавливаться только при приближении сзади автобуса","Уступать дорогу только детям, находящимся непосредственно на проезжей части","Остановиться с любого направления и не продолжать движение, пока автобус не тронется или мигающие огни не будут выключены"],"explanation":"RIGL § 31-20-12 требует, чтобы водители, движущиеся навстречу или обгоняющие с любого направления автобус с маркировкой «school bus» и мигающими красными огнями, остановились, и водитель не должен продолжать движение, пока автобус не возобновит движение или мигающие огни больше не будут включены. Источник: RIGL § 31-20-12."},"62":{"q":"Законодательство Род-Айленда запрещает водителю любого транспортного средства (кроме автомобиля экстренных служб при исполнении служебных обязанностей) следовать за школьным автобусом ближе какого расстояния?","options":["100 футов","20 футов","50 футов","300 футов"],"explanation":"RIGL § 31-20-12 запрещает движение за школьным автобусом на расстоянии менее пятидесяти футов (50'), за исключением автомобилей экстренных служб при исполнении служебных обязанностей. Источник: RIGL § 31-20-12."},"63":{"q":"Согласно закону Род-Айленда «Move Over», что должен сделать водитель при приближении к остановившемуся автомобилю экстренных служб, эвакуатору или машине дорожно-эксплуатационной службы с включенными мигающими огнями на дороге, имеющей не менее двух полос в направлении движения водителя?","options":["Полностью остановиться, пока транспортное средство не уедет","Подать звуковой сигнал и продолжить движение с установленной скоростью","Съехать на правую обочину и остановиться","Перестроиться в полосу, не ближайшую к остановившемуся транспортному средству, если это можно сделать безопасно"],"explanation":"RIGL § 31-14-3 требует, чтобы водитель перестроился в полосу, не ближайшую к остановившемуся уполномоченному автомобилю экстренных служб, эвакуатору/транспортировщику, машине помощи на дороге или дорожно-эксплуатационной технике с включенными мигающими огнями — если дорога имеет две или более полос в этом направлении и маневр можно выполнить безопасно. Источник: RIGL § 31-14-3."},"64":{"q":"Согласно закону Род-Айленда «Move Over», что должен сделать водитель, когда в его направлении только одна полоса или перестроение невозможно выполнить безопасно?","options":["Полностью остановиться на полосе движения","Поддерживать установленное ограничение скорости","Съехать с дороги и подождать пять минут","Снизить скорость до безопасной, сниженной и держать ее, пока полностью не минует транспортное средство"],"explanation":"RIGL § 31-14-3 предписывает, что там, где есть только одна полоса или перестроение небезопасно, водитель должен снизить скорость транспортного средства до безопасной для условий и двигаться с этой сниженной скоростью, пока полностью не минует остановившееся транспортное средство. Источник: RIGL § 31-14-3."},"65":{"q":"Закон Род-Айленда «Move Over» защищает какие из перечисленных остановившихся транспортных средств с включенными предупредительными огнями?","options":["Только полицейские машины и кареты скорой помощи","Только транспортные средства, принадлежащие штату","Автомобили экстренных служб, эвакуаторы/транспортировщики, машины помощи на дороге и дорожно-эксплуатационную технику","Только пожарную технику, активно тушащую пожар"],"explanation":"RIGL § 31-14-3 перечисляет в качестве защищенных уполномоченные автомобили экстренных служб, эвакуаторы, транспортировщики, машины помощи на дороге и дорожно-эксплуатационную технику с включенными мигающими огнями. Закон не ограничивается полицией и скорой помощью. Источник: RIGL § 31-14-3."},"66":{"q":"При отсутствии установленного знака предельная скорость prima facie в Род-Айленде в любом деловом или жилом районе составляет:","options":["25 mph","30 mph","20 mph","35 mph"],"explanation":"RIGL § 31-14-2 устанавливает предельную скорость prima facie в двадцать пять миль в час (25 mph) в любом деловом или жилом районе. Источник: RIGL § 31-14-2."},"67":{"q":"Согласно предельным скоростям prima facie Род-Айленда, какова дневная предельная скорость в местах, отличных от деловых/жилых районов и школьных зон, где не установлено иное ограничение?","options":["55 mph днем","50 mph днем","45 mph днем","65 mph днем"],"explanation":"RIGL § 31-14-2 устанавливает предельную скорость prima facie в пятьдесят миль в час (50 mph) в прочих местах в дневное время и сорок пять (45 mph) в ночное время. Установленные ограничения на межштатной автомагистрали могут быть выше. Источник: RIGL § 31-14-2."},"68":{"q":"В пределах 300 футов от входов и выходов школы в учебные дни Род-Айленд устанавливает предельную скорость prima facie:","options":["15 mph в любое время","20 mph в дневное время","25 mph в дневное время","10 mph при наличии детей"],"explanation":"RIGL § 31-14-2 устанавливает двадцать миль в час (20 mph) в пределах трехсот футов (300') от входов и выходов на территорию школьного здания в дневное время в дни, когда школы работают. Источник: RIGL § 31-14-2."},"69":{"q":"На шоссе Род-Айленда коммерческое транспортное средство, движущееся медленнее обычной скорости потока, должно:","options":["Двигаться по правой полосе или как можно ближе к правому краю проезжей части","Держаться центральной полосы, чтобы избегать вливающегося потока","Использовать левую полосу, чтобы не мешать на въездных съездах","Использовать любую полосу при условии включенной аварийной сигнализации"],"explanation":"RIGL § 31-15-2 («Медленный поток вправо») требует, чтобы любое транспортное средство, движущееся медленнее обычной скорости потока, двигалось по крайней правой доступной полосе или как можно ближе к правому бордюру или краю, за исключением случаев обгона, опережения или подготовки к левому повороту. Источник: RIGL § 31-15-2."},"70":{"q":"Без разрешения на негабаритный груз максимальная допустимая ширина транспортного средства или его груза в Род-Айленде составляет:","options":["102 inches (8 feet 6 inches)","96 inches (8 feet)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"RIGL § 31-25-3 ограничивает общую наружную ширину транспортного средства или его груза до ста двух дюймов (102\"), то есть 8 футов 6 дюймов, прежде чем потребуется разрешение на негабаритный груз. Источник: RIGL § 31-25-3; руководство RIDOT Legal OSOW."},"71":{"q":"Без разрешения на негабаритный груз максимальная допустимая высота транспортного средства, включая его груз, в Род-Айленде составляет:","options":["168 inches (14 feet)","162 inches (13 feet 6 inches)","156 inches (13 feet)","150 inches (12 feet 6 inches)"],"explanation":"RIGL § 31-25-4 ограничивает высоту транспортного средства, включая груз, до ста шестидесяти двух дюймов (162\"), то есть 13 футов 6 дюймов. Руководство RIDOT Legal OSOW подтверждает 13'6\" в качестве допустимой высоты. Источник: RIGL § 31-25-4; руководство RIDOT Legal OSOW."},"72":{"q":"В Род-Айленде полуприцеп длиннее 48 футов 6 дюймов может эксплуатироваться только где?","options":["Где угодно в штате без ограничений","Только на платных дорогах","На системе межштатных автомагистралей и других шоссе, определенных директором RIDOT","Только между восходом и закатом солнца на любой дороге"],"explanation":"RIGL § 31-25-6 ограничивает полуприцепы пятьюдесятью тремя футами (53'), но позволяет тем, что длиннее сорока восьми с половиной футов (48'6\"), эксплуатироваться только на системе межштатных автомагистралей и на шоссе/улицах/дорогах, определенных директором RIDOT. Источник: RIGL § 31-25-6."},"73":{"q":"Максимальная полная масса любого транспортного средства или сочетания транспортных средств на шоссе Род-Айленда при отсутствии разрешения составляет:","options":["73,280 pounds","80,000 pounds","88,000 pounds","100,000 pounds"],"explanation":"RIGL § 31-25-14 ограничивает общую полную массу восемьюдесятью тысячами фунтов (80,000 lbs), с учетом также федеральной мостовой формулы. Источник: RIGL § 31-25-14."},"74":{"q":"Согласно законодательству Род-Айленда, максимальная полная масса, допустимая на любую одиночную ось транспортного средства, составляет:","options":["22,400 pounds","20,000 pounds","34,000 pounds","18,000 pounds"],"explanation":"RIGL § 31-25-14 ограничивает полную массу на колеса любой одной оси двадцатью двумя тысячами четырьмястами (22,400) фунтами; сдвоенная ось (с расстоянием до 8 футов) ограничена 36,000 фунтами. Источник: RIGL § 31-25-14."},"75":{"q":"По состоянию на 2026 год программа мостовых платных сборов Род-Айленда RhodeWorks устроена так, чтобы взимать плату с каких транспортных средств?","options":["Только с тягачей с полуприцепом класса 8 (и крупнее); легковые автомобили и пикапы освобождены","Со всех транспортных средств тяжелее 10,000 фунтов","С каждого транспортного средства, пересекающего платный мост","Только с коммерческих грузовиков из других штатов"],"explanation":"Программа Род-Айленда RhodeWorks взимает плату только с крупных коммерческих грузовиков — тягачей с полуприцепом класса 8 и крупнее — на мостовых рамках, освобождая легковые автомобили и меньшие коммерческие транспортные средства. Первый окружной апелляционный суд (First Circuit) поддержал структуру «только для тягачей с полуприцепом» (отменив лишь дневной лимит). Источник: RIDOT/RhodeWorks; решение First Circuit по RhodeWorks."},"76":{"q":"Когда коммерческое транспортное средство Род-Айленда остановлено на проезжей части двухполосной двусторонней дороги, где водитель должен разместить три обязательных предупредительных треугольника?","options":["Все три в пределах 10 ft от заднего бампера","Один на 200 ft и два на 100 ft, все позади транспортного средства","Примерно в 10 ft позади транспортного средства в сторону потока, примерно в 100 ft позади и примерно в 100 ft впереди транспортного средства","Только один треугольник, размещенный в 50 ft сзади"],"explanation":"Род-Айленд следует федеральному стандарту (49 CFR 392.22), изложенному в руководстве CDL: на двухполосной двусторонней дороге разместите один треугольник примерно в 10 ft сзади в сторону потока, один примерно в 100 ft сзади и один примерно в 100 ft спереди. (На разделенной или односторонней дороге устройства сзади ставятся на 10, 100 и 200 ft.) Источник: руководство RI CDL; 49 CFR 392.22."},"77":{"q":"Какое ведомство выдает коммерческие водительские удостоверения (CDL) в Род-Айленде?","options":["Rhode Island Division of Motor Vehicles (DMV)","Rhode Island Department of Transportation (RIDOT)","Подразделение по контролю коммерческого транспорта полиции штата Род-Айленд","Federal Motor Carrier Safety Administration (FMCSA)"],"explanation":"CDL в Род-Айленде выдаются RI Division of Motor Vehicles (RI DMV). RIDOT занимается дорогами и разрешениями на негабаритные/сверхтяжелые грузы, а FMCSA устанавливает федеральные стандарты, но не выдает удостоверения штата. Источник: страницы RI DMV, Commercial Driver License (CDL)."},"78":{"q":"Где в Род-Айленде проводятся очные экзамены по практическим навыкам CDL (дорожные испытания)?","options":["На специализированной площадке для экзаменов CDL по адресу 400 Romano Vineyard Way, North Kingstown","В любом отделении AAA по всему штату","Только в штаб-квартире DMV в Cranston","На весовых станциях RIDOT вдоль I-95"],"explanation":"Экзамены по коммерческим навыкам в Род-Айленде проводятся по предварительной записи на площадке для экзаменов CDL по адресу 400 Romano Vineyard Way, North Kingstown. DMV в Cranston занимается очными операциями по CDL у стойки и экзаменами на знания, но экзамен по навыкам проводится на площадке в North Kingstown. Источник: страница RI DMV, Commercial Skills Test."},"79":{"q":"Сколько времени заявитель должен иметь обычное водительское удостоверение (класса D), прежде чем подать заявление на CDL в Род-Айленде?","options":["Не менее 2 лет","Не менее 6 месяцев","Не менее 1 года","Не менее 3 лет"],"explanation":"Род-Айленд требует, чтобы на момент подачи заявления заявитель на CDL был лицензированным водителем не менее двух (2) лет. Источник: страницы RI DMV, Commercial Driving License (CDL) / Commercial Learner's Permit and Exams."},"80":{"q":"Согласно правилам Род-Айленда, каков минимальный возраст для получения CDL для внутриштатного (только в пределах штата) вождения?","options":["18 лет","16 лет","21 год","25 лет"],"explanation":"В 18 лет вы можете получить CDL Род-Айленда только для внутриштатных (в пределах штата) поездок; для межштатного вождения (через границы штатов) вам должен быть 21 год. Источник: страница RI DMV, Commercial Driving License (CDL)."},"81":{"q":"Какой минимальный возраст требуется в Род-Айленде для вождения коммерческого транспортного средства между штатами (через границы штатов)?","options":["21 год","18 лет","19 лет","23 года"],"explanation":"Род-Айленд, следуя федеральному стандарту, требует, чтобы водителю был 21 год для межштатной коммерческой деятельности; лица в возрасте от 18 до 20 лет ограничены внутриштатным вождением. Источник: страница RI DMV, Commercial Driving License (CDL)."},"82":{"q":"Какую форму заявления необходимо заполнить, чтобы подать заявление на CDL в Род-Айленде?","options":["Application for Commercial Driver's License (CDL-1)","Форму MCSA-5876","Standard License Application (LI-1)","Форму DL-44C"],"explanation":"Заявители в Род-Айленде заполняют Application for Commercial Driver's License (CDL-1), которая также включает аффидевит об истории вождения. Источник: страница RI DMV, Commercial Learner's Permit and Exams (форма CDL-1)."},"83":{"q":"В Род-Айленде какое подтверждение законного нахождения должен предоставить заявитель на CDL?","options":["Подтверждение гражданства США или законного постоянного проживания","Действующий паспорт любой страны","Только карту социального страхования, без дальнейших подтверждений","Нотариально заверенное заявление о месте жительства от работодателя"],"explanation":"RI DMV требует, чтобы все заявители на CDL предоставили подтверждение статуса гражданина США или законного постоянного жителя, а также подтверждение проживания в Род-Айленде. Источник: страница RI DMV, Commercial Driving License (CDL)."},"84":{"q":"Какой экзамен на знания является минимальным требованием для получения Commercial Learner's Permit (CLP) в Род-Айленде?","options":["Экзамен General Knowledge","Экзамен Air Brakes","Экзамен Combination Vehicles","Экзамен Hazardous Materials"],"explanation":"Экзамен General Knowledge является минимальным требованием для CLP в Род-Айленде; дополнительные экзамены на знания требуются в зависимости от класса и запрашиваемых допусков. Источник: страница RI DMV, Commercial Learner's Permit and Exams."},"85":{"q":"На экзамене CDL General Knowledge в Род-Айленде (50 вопросов) какой результат необходим для прохождения?","options":["80% (40 из 50 правильных)","70% (35 из 50 правильных)","75% (38 из 50 правильных)","90% (45 из 50 правильных)"],"explanation":"Род-Айленд следует стандартному порогу прохождения CDL в 80%; на экзамене General Knowledge из 50 вопросов это означает 40 правильных ответов. Источник: руководство RI CDL / стандарты экзаменов на знания RI DMV."},"86":{"q":"Сколько действует Commercial Learner's Permit (CLP) Род-Айленда и можно ли его продлить?","options":["Действует максимум один год и не подлежит продлению","Действует 180 дней и продлевается один раз","Действует два года и подлежит продлению","Действует 60 дней и не подлежит продлению"],"explanation":"CLP Род-Айленда действует максимум один год и не подлежит продлению; если он истекает, заявитель должен пересдать все экзамены на знания и повторно оплатить сборы. Источник: страница RI DMV, Commercial Learner's Permit and Exams."},"87":{"q":"После получения CLP в Род-Айленде сколько времени его необходимо иметь, прежде чем владелец сможет сдать экзамен на навыки CDL?","options":["Не менее 14 days","Не менее 30 days","Не менее 7 days","Не менее 60 days"],"explanation":"В соответствии с федеральным правилом, которому он следует, Род-Айленд требует, чтобы CLP имелся не менее 14 days, прежде чем сдавать экзамен на навыки CDL. Источник: страница RI DMV, Commercial Skills Test (стандарт FMCSA 49 CFR 383)."},"88":{"q":"Каковы три части экзамена на навыки CDL в Род-Айленде?","options":["Vehicle Inspection, Basic Control Skills и Road Test","Письменный тест, тест на зрение и Road Test","Air Brakes, Backing и Highway Driving","Pre-trip, Hazardous Materials и Night Driving"],"explanation":"Экзамен на навыки Род-Айленда состоит из трех частей: Vehicle Inspection (pre-trip) Test, Basic Control Skills Test и Road Test; заявитель должен пройти все три. Источник: страница RI DMV, Commercial Skills Test."},"89":{"q":"Кто должен предоставить транспортное средство, используемое для экзамена на навыки CDL в Род-Айленде, и в каком состоянии оно должно быть?","options":["Заявитель предоставляет собственное транспортное средство, которое должно прибыть пустым (без груза)","DMV предоставляет всем заявителям государственное экзаменационное транспортное средство","Работодатель заявителя должен предоставить загруженное экзаменационное транспортное средство","Подходит любой арендованный фургон-будка, независимо от весового класса"],"explanation":"В Род-Айленде кандидат должен предоставить собственное репрезентативное транспортное средство, и оно должно прибыть пустым (без груза); цистерны должны быть сертифицированы как пустые, очищенные и продутые. Источник: страница RI DMV, Commercial Skills Test."},"90":{"q":"Помимо CLP и водительского удостоверения, какие документы необходимо предъявить для экзамена на навыки в Род-Айленде?","options":["Действующую регистрацию транспортного средства, подтверждение действующей страховки и действующий стикер техосмотра","Аттестат об окончании средней школы и подтверждение трудоустройства","Только паспорт и свидетельство о рождении","Нотариально заверенное письмо из школы подготовки CDL"],"explanation":"Род-Айленд требует бумажные копии CLP и водительского удостоверения, а также действующую регистрацию транспортного средства (и прицепа, если применимо), подтверждение действующей страховки и действующий стикер техосмотра транспортного средства. Источник: страница RI DMV, Commercial Skills Test."},"91":{"q":"Согласно правилам Род-Айленда, когда должна быть пройдена Entry-Level Driver Training (ELDT) для впервые подающего заявление на класс A или класс B?","options":["Перед сдачей экзамена на навыки CDL","В течение 30 дней после прохождения экзамена на навыки","Только после того, как CDL уже выдан","Это необязательно и может быть пропущено с одобрения работодателя"],"explanation":"ELDT должна быть успешно пройдена у зарегистрированного провайдера, прежде чем впервые подающему заявление на класс A/B будет разрешено сдавать экзамен на навыки CDL. Источник: страница RI DMV, ELDT (федеральное правило ELDT, действует с 7 февраля 2022 года)."},"92":{"q":"Для какого допуска Род-Айленд требует прохождения ELDT перед экзаменом на ЗНАНИЯ (а не перед экзаменом на навыки)?","options":["Допуск Hazardous Materials (H)","Допуск Passenger (P)","Допуск School Bus (S)","Допуск Doubles/Triples (T)"],"explanation":"Для допуска Hazardous Materials (H) ELDT должна быть пройдена перед сдачей экзамена на знания; для допусков P и S ELDT проходится перед экзаменом на навыки. Источник: страница RI DMV, ELDT."},"93":{"q":"Где заявителю в Род-Айленде следует искать утвержденного провайдера обучения ELDT?","options":["FMCSA Training Provider Registry (TPR)","Портал листа ожидания CLP RI DMV","National Registry of Certified Medical Examiners","Список поставщиков офиса разрешений RIDOT"],"explanation":"Утвержденные провайдеры ELDT перечислены в FMCSA Training Provider Registry (tpr.fmcsa.dot.gov); прохождение также можно подтвердить там. Источник: страница RI DMV, ELDT."},"94":{"q":"Из скольких категорий коммерческой деятельности самосертификации должен выбрать заявитель на CDL в Род-Айленде?","options":["Четыре категории","Две категории","Три категории","Шесть категорий"],"explanation":"Заявитель в Род-Айленде должен самосертифицироваться в одной из четырех категорий: Interstate Non-Excepted, Interstate Excepted, Intrastate Non-Excepted или Intrastate Excepted. Источник: страница RI DMV, Medical Certification / Self-Certification."},"95":{"q":"Водитель в Род-Айленде, сертифицирующийся как «Interstate Non-Excepted», должен сделать что?","options":["Получить и поддерживать федеральный DOT Medical Examiner's Certificate","Избегать перевозки любого груза через границы штатов","Продлевать CDL ежегодно вместо каждых пяти лет","Пропустить дорожный экзамен из-за своего межштатного статуса"],"explanation":"Водители Interstate Non-Excepted работают как в пределах Род-Айленда, так и за его пределами и обязаны получить федеральный DOT Medical Examiner's Certificate; для категорий excepted это не требуется. Источник: страница RI DMV, Medical Certification / Self-Certification."},"96":{"q":"Как теперь передается в DMV медицинская сертификация DOT для водителя CDL категории non-excepted в Род-Айленде?","options":["Сертифицированный медицинский эксперт в электронном виде подает ее в FMCSA National Registry, который пересылает ее в RI DMV","Водитель отправляет бумажную копию медицинской карты напрямую в RI DMV по почте","Работодатель отправляет сертификат по факсу в RIDOT для регистрации","Водитель загружает ее через портал учетной записи RI E-ZPass"],"explanation":"RI DMV больше не принимает медицинскую сертификацию напрямую; сертифицированный медицинский эксперт в электронном виде подает Medical Examiner's Certificate (форма MCSA-5876/5875) в FMCSA National Registry, который пересылает ее в DMV. Несоблюдение требования о поддержании ее в актуальном состоянии приводит к понижению CDL. Источник: страница RI DMV, Medical Certification; National Registry of Certified Medical Examiners."}},"tr":{"0":{"q":"Rhode Island karayollarında, özel bir izin olmadan ticari bir aracın veya yükünün yasal azami genişliği nedir?","options":["96 inç (8 feet)","102 inç (8 feet 6 inç)","108 inç (9 feet)","120 inç (10 feet)"],"explanation":"Rhode Island General Laws § 31-25-3, herhangi bir aracın veya yükünün azami genişliğini 102 inç (8 feet 6 inç) olarak belirler. Bundan daha geniş olan her şey bir RIDOT aşırı boyut izni gerektirir. Kaynak: R.I. Gen. Laws § 31-25-3."},"1":{"q":"Rhode Island karayollarında, izin olmadan bir aracın yükü dahil yasal azami yüksekliği nedir?","options":["162 inç (13 feet 6 inç)","156 inç (13 feet)","168 inç (14 feet)","150 inç (12 feet 6 inç)"],"explanation":"Rhode Island General Laws § 31-25-4, yük dahil araç yüksekliğini 162 inç (13 feet 6 inç) ile sınırlar. Bunu aşan yükler bir RIDOT aşırı yükseklik izni gerektirir. Kaynak: R.I. Gen. Laws § 31-25-4."},"2":{"q":"Rhode Island karayollarında, aşırı ağırlık izni olmadan bir araç veya araç kombinasyonu için pound cinsinden azami toplam brüt ağırlık nedir?","options":["73,280 pound","80,000 pound","88,000 pound","100,000 pound"],"explanation":"Rhode Island, özel bir izin alınmadığı sürece, toplam brüt ağırlığı federal Interstate standardıyla uyumlu olarak 80,000 pound ile sınırlar. Kaynak: R.I. Gen. Laws § 31-25-14; RIDOT Manual for Overweight and Oversize Vehicle Permits."},"3":{"q":"Rhode Island'da, herhangi bir tek dingilin tekerlekleri tarafından karayoluna uygulanan brüt ağırlık kaç pound'u aşamaz?","options":["18,000 pound","20,000 pound","22,400 pound","24,000 pound"],"explanation":"Rhode Island General Laws § 31-25-13, tek dingil sınırını 22,400 pound olarak belirler. Bu, 20,000 pound'luk federal Interstate tek dingil standardından daha yüksektir ve Rhode Island'a özgü bir değerdir. Kaynak: R.I. Gen. Laws § 31-25-13."},"4":{"q":"Rhode Island'da dingil aralığı 8 feet'i aşmadığında bir tandem dingil grubundaki yasal azami ağırlık nedir?","options":["32,000 pound","34,000 pound","36,000 pound","40,000 pound"],"explanation":"Rhode Island General Laws § 31-25-14, dingil aralığı 8 feet'i aşmadığında bir tandem dingil grubunu 36,000 pound ile sınırlar. Kaynak: R.I. Gen. Laws § 31-25-14."},"5":{"q":"Rhode Island yasalarına göre, ağırlık sınırı amaçları için tek bir \"dingil yükü\" nasıl tanımlanır?","options":["Birbirinden 40 inç uzaklıkta olan iki paralel enine dikey düzlem içindeki tüm tekerleklere binen toplam yük","Birbirinden 96 inç uzaklıkta olan iki düzlem içindeki tüm tekerleklere binen toplam yük","Araçtaki herhangi bir lastiğin taşıdığı yük","Aracın tescilli brüt ağırlığının yarısı"],"explanation":"Rhode Island General Laws § 31-25-13, bir dingil yükünü, merkezleri birbirinden 40 inç uzaklıkta olan iki paralel enine dikey düzlem arasında yer alan ve aracın tüm genişliği boyunca uzanan tüm tekerlekler tarafından yola aktarılan toplam yük olarak tanımlar. Kaynak: R.I. Gen. Laws § 31-25-13."},"6":{"q":"Rhode Island karayollarında tek bir aracın (kombinasyon değil) yük ve tamponlar dahil azami uzunluğu nedir?","options":["35 feet","40 feet","48 feet","53 feet"],"explanation":"Rhode Island General Laws § 31-25-5, herhangi bir yük dahil tek bir aracı toplam 40 feet ile sınırlar (otobüs, motorlu kamp aracı veya kamp amaçlı eğlence aracı için 45 feet). Kaynak: R.I. Gen. Laws § 31-25-5."},"7":{"q":"Rhode Island'da tek bir otobüsün, motorlu kamp aracının veya kamp amaçlı eğlence aracının azami uzunluğu nedir?","options":["40 feet","42 feet","45 feet","48 feet"],"explanation":"Rhode Island General Laws § 31-25-5, bir otobüse, motorlu kamp aracına veya kamp amaçlı eğlence aracına 45 feet'e ulaşma izni verirken, diğer tek araçlar 40 feet ile sınırlıdır. Kaynak: R.I. Gen. Laws § 31-25-5."},"8":{"q":"Rhode Island'da faaliyet gösteren bir yarı römorkun, tamponlar ve aksesuarlar hariç azami uzunluğu nedir?","options":["48 feet 6 inç","51 feet","53 feet","57 feet"],"explanation":"Rhode Island General Laws § 31-25-6, tamponlar ve aksesuarlar hariç yarı römorklara 53 feet'e kadar izin verir. Kaynak: R.I. Gen. Laws § 31-25-6."},"9":{"q":"Rhode Island'da, hangi uzunluğun üzerindeki yarı römorklar yalnızca Interstate karayolu sisteminde ve müdür tarafından özel olarak belirlenmiş karayollarında faaliyet gösterebilir?","options":["45 feet","48 feet 6 inç","50 feet","53 feet"],"explanation":"Rhode Island General Laws § 31-25-6, 48 feet 6 inç'i aşan yarı römorkları Interstate karayolu sistemine ve müdür tarafından belirlenen karayolları, sokaklar ve yollara kısıtlar. Kaynak: R.I. Gen. Laws § 31-25-6."},"10":{"q":"Rhode Island'da aşırı boyut ve aşırı ağırlık araç izinlerini hangi kurum verir?","options":["Rhode Island Ulaştırma Departmanı (RIDOT)","Rhode Island Eyalet Polisi","Federal Karayolu İdaresi","Seyahatin başladığı yerel şehir veya kasaba kâtibi"],"explanation":"Yasal boyut veya ağırlık sınırlarını aşan araçlar için özel izinler, Eyalet Ulaştırma Departmanı (RIDOT) tarafından verilir. Kaynak: RIDOT Manual for Overweight and Oversize Vehicle Permits; R.I. Gen. Laws § 31-25-18."},"11":{"q":"Rhode Island, ardışık herhangi bir dingil grubundaki izin verilen brüt ağırlığı belirlemek için hangi formülü kullanır?","options":["Federal Köprü Formülü: W = 500[(LN/(N-1)) + 12N + 36]","Brüt ağırlık = lastik genişliğinin her inçi başına 1,000 pound","Brüt ağırlık = dingil grubu başına sabit 34,000 pound","Brüt ağırlık = 80,000 bölü dingil sayısı"],"explanation":"Rhode Island General Laws § 31-25-14, federal Köprü Formülünü uygular: W = 500[(LN/(N-1)) + 12N + 36], burada W ardışık dingil grubu üzerindeki brüt ağırlık, L grubun dış dingilleri arasındaki feet cinsinden mesafe ve N dingil sayısıdır. Kaynak: R.I. Gen. Laws § 31-25-14."},"12":{"q":"Rhode Island Köprü Formülü W = 500[(LN/(N-1)) + 12N + 36]'da \"N\" değişkeni neyi temsil eder?","options":["Dikkate alınan gruptaki dingil sayısı","Yalnızca kargonun net ağırlığı","Çekiş dingilindeki lastik sayısı","Aracın feet cinsinden nominal genişliği"],"explanation":"Rhode Island tarafından benimsenen Köprü Formülünde N gruptaki dingil sayısı, L en uçtaki dingiller arasındaki feet cinsinden mesafe ve W o grup üzerindeki izin verilen azami brüt ağırlıktır. Kaynak: R.I. Gen. Laws § 31-25-14."},"13":{"q":"Rhode Island'ın ağırlık kurallarına göre, Köprü Formülü 36,000 pound'un altında bir tandem dingil sınırı üretirse, yasal sınır olarak hangi değer kullanılır?","options":["Daha düşük formül sonucu kullanılmalıdır","34,000 pound kullanılır","36,000 pound yasal sınır olarak kabul edilir","Dingil grubu yüklemeden önce yeniden aralandırılmalıdır"],"explanation":"Rhode Island General Laws § 31-25-14, Köprü Formülü 36,000 pound'un altında bir tandem dingil rakamı verdiğinde, 36,000 pound'un yasal sınır olarak kabul edileceğini öngörür. Kaynak: R.I. Gen. Laws § 31-25-14."},"14":{"q":"Bir taşıyıcının Rhode Island karayolunda 11 feet genişliğinde bölünemez bir yükü taşıması gerekiyor. Taşıyıcı ne yapmalıdır?","options":["Hiçbir şey; 11 feet yasal genişlik dahilindedir","Taşımadan önce RIDOT'tan bir aşırı boyut izni almalı","Yalnızca yerel polis departmanını bilgilendirmeli","Önce yükü 96 inç'e düşürmeli"],"explanation":"11 feet (132 inç), § 31-25-3 uyarınca 102 inç'lik yasal genişliği aştığı için, taşıyıcı yükü taşımadan önce RIDOT'tan bir aşırı boyut izni almalıdır. Kaynak: R.I. Gen. Laws § 31-25-3 ve § 31-25-18; RIDOT Permit Manual."},"15":{"q":"Rhode Island'da bölünemez aşırı boyutlu veya aşırı ağırlıklı bir aracın veya yükün taşınması için standart RIDOT tek seferlik ücreti nedir?","options":["Sefer başına $10.00","Sefer başına $20.00","Sefer başına $50.00","Sefer başına $100.00"],"explanation":"RIDOT Manual for Overweight and Oversize Vehicle Permits, bölünemez araçların veya yüklerin hareketi için sefer başına $20.00 ücret alır. Kaynak: RIDOT Manual for Overweight and Oversize Vehicle Permits, Sec. 4.4."},"16":{"q":"Sefer başına ücret ödemek yerine, Rhode Island'da tekrarlanan eyalet içi aşırı boyut/aşırı ağırlık hareketleri yapan bir taşıyıcı, hangi ücret karşılığında genel bir izin (blanket permit) alabilir?","options":["$50.00","$100.00","$250.00","$500.00"],"explanation":"RIDOT izin kılavuzu, sefer başına ücret ödemek yerine eyalet içi hareketler için genel bir iznin $100.00 karşılığında alınmasına izin verir. Kaynak: RIDOT Manual for Overweight and Oversize Vehicle Permits, Sec. 4.4."},"17":{"q":"Rhode Island izin kılavuzuna göre, toplam genişliği 14 feet 6 inç'in üzerinde olan bir yük için kaç refakat (kılavuz) aracı gereklidir?","options":["Refakat aracı gerekli değildir","Bir refakat aracı","İki refakat aracı","Dört refakat aracı"],"explanation":"RIDOT izin kılavuzu, 12 feet 0 inç ile 14 feet 6 inç arasındaki genişlikler için bir refakat aracı ve 14 feet 6 inç'in üzerindeki genişlikler için iki refakat aracı gerektirir. Kaynak: RIDOT Manual for Overweight and Oversize Vehicle Permits, Sec. 5.4."},"18":{"q":"Rhode Island izin kılavuzuna göre, izinli aşırı boyut/aşırı ağırlık hareketlerine genellikle NE ZAMAN izin verilmez?","options":["Cuma gün batımından Pazartesi gün doğumuna kadar ve listelenen tatil günlerinde","Yalnızca her gün gece yarısı ile 4:00 a.m. arasında","Yalnızca her ayın ilk haftasında","Asla; izinli hareketler herhangi bir zamanda yapılabilir"],"explanation":"RIDOT izin kılavuzu, aksi belirtilmediği sürece, Cuma gün batımından Pazartesi gün doğumuna kadar ve listelenen resmi tatil günlerinde hareketleri yasaklar. Kaynak: RIDOT Manual for Overweight and Oversize Vehicle Permits, Sec. 4.15 / 5.7."},"19":{"q":"Rhode Island yasaları, çiftlik araçlarını, çiftlik traktörlerini, yol makinelerini ve itfaiye araçlarını Bölüm 31-25 boyut ve ağırlık sınırları açısından nasıl ele alır?","options":["Boyut ve ağırlık sınırlamalarından muaftırlar","Normal ağırlık sınırlarının %50'si ile sınırlıdırlar","Her zaman yıllık bir aşırı boyut izni taşımalıdırlar","Tüm numaralı eyalet karayollarından men edilmişlerdir"],"explanation":"Rhode Island General Laws § 31-25-2, bir karayolunda geçici olarak hareket ettirilen itfaiye araçlarını, yol makinelerini ve çiftlik araçlarını (çiftlik traktörleri dahil) Bölüm 31-25 boyut ve ağırlık sınırlamalarından muaf tutar. Kaynak: R.I. Gen. Laws § 31-25-2."},"20":{"q":"Rhode Island'da, yalnızca EYALET İÇİ (eyalet içinde) faaliyet için geçerli bir CDL almak için asgari yaş nedir?","options":["16 yaşında","18 yaşında","21 yaşında","25 yaşında"],"explanation":"RI CDL Manual (Guidelines for CDL Applicants), yalnızca EYALET İÇİ bir CDL için en az iki yıldır geçerli bir sürücü belgesine sahip olmanız ve en az 18 yaşında olmanız gerektiğini belirtir; eyaletler arası için 21 gereklidir. Kaynak: RI DMV Commercial Driver License Manual (AAMVA 2005, Rev. July 2014)."},"21":{"q":"Rhode Island'da EYALETLER ARASI ticarette (eyalet sınırlarını geçerek) bir ticari motorlu aracı kullanmak için gereken asgari yaş nedir?","options":["18 yaşında","19 yaşında","21 yaşında","23 yaşında"],"explanation":"RI DMV, eyaletler arası (eyalet sınırlarını geçerek) CDL faaliyeti için bir sürücünün 21 yaşında olmasını gerektirir; 18 yaş yalnızca eyalet içi için uygundur. Kaynak: RI DMV CDL sayfası ve RI Commercial Driver License Manual (Rev. July 2014)."},"22":{"q":"Rhode Island'ın CDL sınıflandırmasına göre, çekilen birim(ler)in GVWR'si 10,000 lbs'yi aştığı sürece, GCWR'si 26,001 lbs veya daha fazla olan herhangi bir araç KOMBİNASYONUNU kullanma yetkisi veren sınıf hangisidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"RI CDL Manual'a göre, bir Class A CDL, çekilen aracın/araçların GVWR'si 10,000 pound'u aştığı sürece, GCWR'si 26,001 veya daha fazla pound olan herhangi bir araç kombinasyonunun kullanımına yetki verir. Kaynak: RI Commercial Driver License Manual, License Classes."},"23":{"q":"Rhode Island'da, GVWR'si 26,001 lbs veya daha fazla olan TEK bir araca (veya 10,000 lbs GVWR'yi aşmayan bir birimi çeken böyle bir araca) yetki veren bir CDL hangi sınıftır?","options":["Class A","Class B","Class C","Class E"],"explanation":"RI CDL Manual, Class B'yi GVWR'si 26,001 veya daha fazla pound olan herhangi bir tek araç ya da GVWR'si 10,000 pound'u aşmayan bir aracı çeken böyle bir araç olarak tanımlar. Kaynak: RI Commercial Driver License Manual, License Classes."},"24":{"q":"Hangi Rhode Island CDL sınıfı, Class A veya B'yi karşılamayan, sürücü dahil 16 veya daha fazla yolcu taşımak için tasarlanmış ya da tehlikeli maddeler için plakart taşıyan bir aracı kapsar?","options":["Class A","Class B","Class C","Class M"],"explanation":"RI CDL Manual, Class C'yi Class A veya B'yi karşılamayan ancak sürücü dahil 16 veya daha fazla yolcu taşımak için tasarlanmış ya da tehlikeli maddeler için plakart taşıyan herhangi bir araç olarak tanımlar. Kaynak: RI Commercial Driver License Manual, License Classes."},"25":{"q":"Bir Rhode Island CDL'de, federal DOT düzenlemeleri uyarınca plakart gerektiren miktarlarda tehlikeli madde taşımak için hangi onay (endorsement) kodu gereklidir?","options":["Kod N","Kod H","Kod T","Kod P"],"explanation":"RI CDL Manual'a göre, federal DOT düzenlemeleri tarafından plakart gerektiren herhangi bir miktarda tehlikeli madde taşırken HERHANGİ bir lisans sınıfında H (HazMat) onayı gereklidir. Kaynak: RI Commercial Driver License Manual, Endorsements."},"26":{"q":"Rhode Island, sıvı veya gaz halinde madde taşıyan bir tank aracı ya da 1,000 galon veya daha fazla kapasiteli taşınabilir bir tankı kullanmak için hangi onayı gerektirir?","options":["N - Tank Araçları","T - İkili/Üçlü Römorklar","P - Yolcu","S - Okul Otobüsü"],"explanation":"RI CDL Manual, bir tank aracında sıvı veya gaz halinde madde ya da 1,000 galon veya daha fazla kapasiteli herhangi bir taşınabilir tankı taşırken herhangi bir lisans sınıfında N (Tank Araçları) onayının gerekli olduğunu belirtir. Kaynak: RI Commercial Driver License Manual, Endorsements."},"27":{"q":"Rhode Island'da, T (İkili/Üçlü Römorklar) onayı yalnızca hangi CDL sınıfına sahip sürücüler tarafından alınabilir?","options":["Class C sürücüleri","Class B sürücüleri","Class A sürücüleri","Herhangi bir sınıf sürücüsü"],"explanation":"RI CDL Manual, T (İkili/Üçlü Römorklar) onayının, yasaların izin verdiği yerlerde ikili/üçlü römork çeken Class A sürücüleri için gerekli olduğunu belirtir. Kaynak: RI Commercial Driver License Manual, Endorsements."},"28":{"q":"Test öncesinde, Rhode Island bir okul otobüsü (S) onayı için yazılı sınav ve beceri testinin ötesinde hangi ek adımı gerektirir?","options":["Bir TSA güvenlik tehdidi değerlendirmesi","DMV School Bus Safety Office aracılığıyla bir RI Okul Otobüsü Sertifikası","Yeşil bir şoför lisansı başvurusu","Bir ikili/üçlü bilgi testi"],"explanation":"RI CDL Manual, S (Okul Otobüsü) onayı sürücülerinin önce DMV School Bus Safety Office aracılığıyla bir RI Okul Otobüsü Sertifikası almaları gerektiğini belirtir. Kaynak: RI Commercial Driver License Manual, Endorsements."},"29":{"q":"Rhode Island CDL Manual'a göre, P (Yolcu) onayı, bir araç sürücü dahil kaç kişiden fazlasını oturtacak şekilde tasarlandığında gereklidir?","options":["8","12","15","16"],"explanation":"RI CDL Manual, araç sürücü dahil 16'dan fazla yolcu oturtacak şekilde tasarlandığında herhangi bir lisans sınıfında P onayının gerekli olduğunu belirtir; ayrıca bir yeşil şoför lisansı başvurusu da tamamlanmalıdır. Kaynak: RI Commercial Driver License Manual, Endorsements."},"30":{"q":"Hangi Rhode Island CDL onayı, HazMat ve Tank Aracı onaylarını birleştirir ve her iki bilgi sınavının da geçilmesini gerektirir?","options":["Kod S","Kod T","Kod X","Kod P"],"explanation":"RI CDL Manual, X onayını H (HazMat) ve N (Tank) kombinasyonu olarak tanımlar; her iki sınav da yapılmalıdır. Kaynak: RI Commercial Driver License Manual, Endorsements."},"31":{"q":"Rhode Island'da uygulanan federal kurallara göre, sahibi CDL beceri testini alabilmeden önce bir Ticari Öğrenci Belgesi (Commercial Learner's Permit) ne kadar süre tutulmalıdır?","options":["7 gün","14 gün","30 gün","60 gün"],"explanation":"RI DMV tarafından uygulanan 49 CFR 383.25 federal düzenlemesi, bir CLP sahibinin CLP ilk verildikten sonraki ilk 14 gün içinde CDL beceri testini almasını yasaklar. Kaynak: 49 CFR 383.25; RI DMV CLP gereklilikleri."},"32":{"q":"Aranan sınıf veya onay ne olursa olsun, HER Rhode Island CDL başvuru sahibinin geçmesi gereken bilgi testi hangisidir?","options":["Hava Frenleri testi","Kombinasyon Araçları testi","Genel Bilgi testi","Yolcu Taşıma testi"],"explanation":"RI CDL Manual, Genel Bilgi testinin tüm başvuru sahipleri tarafından alındığını belirtir; diğer testler sınıfa ve onaylara bağlıdır. Kaynak: RI Commercial Driver License Manual, Section 1, Knowledge Tests."},"33":{"q":"Rhode Island Genel Bilgi CDL sınavında, geçmek için 50 sorudan kaçının doğru yanıtlanması gerekir (%80)?","options":["30","40","44","45"],"explanation":"RI CDL Manual'ın elektronik/manuel test programı, Genel Bilgi testini geçmek için 50 soru olarak listeler ve 40 doğru (%80) gerektirir. Kaynak: RI Commercial Driver License Manual, Electronic/Manual Tests."},"34":{"q":"Rhode Island başvuru sahipleri için CDL yol (beceri) testini hangi kurum yürütür ve planlar?","options":["Cranston'daki RI DMV ana ofisi","Community College of Rhode Island (CCRI)","RI Eyalet Polisi","Rhode Island DOT izin ofisi"],"explanation":"RI CDL Manual, yol testlerinin Community College of Rhode Island (CCRI) tarafından verildiğini ve bu kurum ile planlanması gerektiğini belirtir. Kaynak: RI Commercial Driver License Manual, Road Tests."},"35":{"q":"RI DMV'nin CLP kurallarına göre, bir Rhode Island CDL başvuru sahibi için aşağıdakilerden hangisi gerekli bir belgedir?","options":["Geçerli bir Sosyal Güvenlik kartı","Noter onaylı bir işveren mektubu","Bir ticari araç tapusu","Bir motosiklet onayı"],"explanation":"RI CDL Manual, tüm başvuru sahiplerinin geçerli bir Sosyal Güvenlik kartı, geçerli bir Tıbbi Kart (muaf değilse) ve kimlik/ikamet kanıtı sunmasını gerektirir. Kaynak: RI Commercial Driver License Manual, Guidelines for CDL Applicants."},"36":{"q":"Rhode Island'da uygulanan Federal Giriş Seviyesi Sürücü Eğitimi (ELDT), hangi kayıt sisteminde listelenen bir sağlayıcı aracılığıyla tamamlanmalıdır?","options":["Eyalet DMV eğitim veritabanı","FMCSA Training Provider Registry (TPR)","AAMVA sürücü eğitimi listesi","TSA onaylı okullar listesi"],"explanation":"7 Şubat 2022'den bu yana, ilk kez Class A/B başvuru sahipleri, B'den A'ya yükseltmeler ve yeni P/S/H onayı arayanlar, beceri testinden (H için bilgi testinden) önce ELDT'yi FMCSA Training Provider Registry'deki bir sağlayıcıyla tamamlamalıdır. Kaynak: FMCSA ELDT kuralı; FMCSA Training Provider Registry."},"37":{"q":"Rhode Island DMV'ye tıbbi durumu öz beyan ederken, bir CDL sahibinin seçmesi gereken dört geçerli kategoriden biri aşağıdakilerden hangisidir?","options":["Interstate Commerce Non-excepted","Recreational Commerce Exempt","Foreign Commerce Certified","Agricultural Commerce Waived"],"explanation":"RI CDL Manual dört öz beyan kategorisini listeler: Interstate Excepted, Interstate Non-excepted, Intrastate Excepted ve Intrastate Non-excepted. Muaf olmayan (Non-excepted) sürücüler geçerli bir tıbbi kart sunmalıdır (49 CFR 391.45). Kaynak: RI Commercial Driver License Manual, Self-Certification."},"38":{"q":"Rhode Island CDL Manual'a göre, bir CDL sahibi yeni bir Tıbbi Kartı verildikten sonra kaç gün içinde DMV'ye sunmalıdır?","options":["10 gün","15 gün","30 gün","45 gün"],"explanation":"RI CDL Manual, yeni Tıbbi Kartınızı verildikten sonra 15 gün içinde DMV'ye sunmanız gerektiğini belirtir; uymamak lisansınızın düşürülmesiyle sonuçlanabilir. Kaynak: RI Commercial Driver License Manual, Medical Certification."},"39":{"q":"Rhode Island'da bir ticari motorlu aracı kullanırken, bir sürücünün CMV amaçları için yasal olarak sarhoş kabul edildiği kan alkol konsantrasyonu (BAC) hangi değer veya üzerindedir?","options":["0.04%","0.08%","0.02%","0.10%"],"explanation":"Rhode Island'da, bir CMV'yi 0.04% veya daha yüksek bir BAC ile kullanmak, ticari olmayan sürücülere uygulanan 0.08% sınırının yarısı olan büyük bir suçtur. Kaynak: R.I. Gen. Laws 31-10.3-31; RI CDL Manual, Section 2."},"40":{"q":"Rhode Island'ın zımni rıza (implied consent) yasası uyarınca, yasal olarak talep edildiğinde nefes, kan veya idrarın kimyasal testine girmeyi reddeden bir CDL sahibi neyi işlemiş kabul edilir?","options":["DUI mahkumiyeti gibi büyük bir suç","Yalnızca ciddi bir trafik ihlali","Bir hizmet dışı (out-of-service) emri ihlali","Bildirimi zorunlu olmayan idari bir mesele"],"explanation":"Rhode Island'da, gerekli bir kimyasal testi reddetmek, bir DUI mahkumiyetiyle aynı diskalifiyeyi taşıyan büyük bir suçtur. Kaynak: R.I. Gen. Laws 31-10.3-31; RI CDL Manual, Section 2."},"41":{"q":"Rhode Island'da, plakart taşıyan tehlikeli madde taşımazken bir CDL sahibinin İLK büyük suçu (örneğin bir CMV'de DUI) için asgari diskalifiye süresi nedir?","options":["1 yıl","60 gün","3 yıl","6 ay"],"explanation":"Rhode Island, bir ilk büyük suç (DUI, 0.04+ BAC, ret, olay yerini terk etme veya bir CMV'yi bir suçta kullanma) için bir sürücüyü en az 1 yıl diskalifiye eder. Kaynak: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"42":{"q":"Rhode Island'da, bir sürücü plakart gerektiren tehlikeli madde taşırken ilk büyük suçu işlerse, asgari diskalifiye süresi şuna yükselir:","options":["3 yıl","1 yıl","120 gün","5 yıl"],"explanation":"Plakart taşıyan bir hazmat aracını kullanırken işlenen bir ilk büyük suç, Rhode Island'da standart 1 yıl yerine asgari 3 yıllık bir diskalifiye ile sonuçlanır. Kaynak: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"43":{"q":"Rhode Island'da, yaşamı boyunca İKİNCİ bir büyük suçtan mahkum edilen bir CDL sahibi hangi diskalifiyeyle karşı karşıya kalır?","options":["Ömür boyu diskalifiye","10 yıllık diskalifiye","3 yıllık diskalifiye","1 yıllık diskalifiye"],"explanation":"Yaşam boyunca ikinci bir büyük suç, Rhode Island'da ömür boyu diskalifiye ile sonuçlanır (belirli koşullar altında en az 10 yıla indirilebilir). Kaynak: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"44":{"q":"Rhode Island'da 3 yıllık bir süre içinde (ayrı olaylardan kaynaklanan) kaç ciddi trafik ihlali, 60 günlük bir CDL diskalifiyesini tetikler?","options":["2","3","4","1"],"explanation":"3 yıl içinde bir CMV'de iki ciddi trafik ihlali, Rhode Island'da 60 günlük bir diskalifiyeye yol açar. Kaynak: R.I. Gen. Laws 31-10.3-31; RI CDL Manual, Section 2."},"45":{"q":"Rhode Island'da, 3 yıllık bir süre içinde üç ciddi trafik ihlali ne kadar süreyle bir CDL diskalifiyesiyle sonuçlanır?","options":["120 gün","60 gün","90 gün","1 yıl"],"explanation":"3 yıl içinde bir CMV'de üç ciddi trafik ihlali, Rhode Island'da 120 günlük bir diskalifiyeye yol açar. Kaynak: R.I. Gen. Laws 31-10.3-31; RI CDL Manual, Section 2."},"46":{"q":"Bir Rhode Island CDL sahibi için aşağıdakilerden hangisi CİDDİ bir trafik ihlali olarak sınıflandırılır?","options":["Önündeki aracı çok yakından takip etmek","Bir CMV'yi 0.04% BAC ile kullanmak","Bir kimyasal testi reddetmek","Bir hizmet dışı (out-of-service) emrini ihlal etmek"],"explanation":"Çok yakından takip etmek, listelenen ciddi trafik ihlallerinden biridir; diğer seçenekler ayrı cezaları olan büyük suçlar veya hizmet dışı ihlalleridir. Kaynak: RI CDL Manual, Section 2; 49 CFR 383.51."},"47":{"q":"Rhode Island'da bir ciddi trafik ihlali için aşırı hız, ilan edilen hız sınırının kaç mil veya daha fazla üzerinde sürmek olarak tanımlanır?","options":["15 mph veya daha fazla","10 mph veya daha fazla","20 mph veya daha fazla","25 mph veya daha fazla"],"explanation":"İlan edilen sınırın 15 mph veya daha fazla üzerinde hız yapmak, Rhode Island'da CDL amaçları için ciddi bir trafik ihlalidir. Kaynak: RI CDL Manual, Section 2; 49 CFR 383.51."},"48":{"q":"Rhode Island'da benimsenen federal kurallara göre, bir CMV kullanırken elde tutulan bir cep telefonu kullanmak veya mesaj yazmak, diskalifiye amaçları için ne tür bir ihlal sayılır?","options":["Ciddi bir trafik ihlali","Büyük bir suç","Bir hizmet dışı (out-of-service) emri ihlali","Bir demiryolu geçidi ihlali"],"explanation":"Bir CMV kullanırken mesaj yazmak veya elde tutulan bir telefon kullanmak, Rhode Island'da ciddi bir trafik ihlalidir ve 60 gün/120 günlük diskalifiyelere doğru sayılır. Kaynak: 49 CFR 383.51, 392.80-392.82; RI CDL Manual."},"49":{"q":"Rhode Island'da 3 yıllık bir süre içinde kaç mesaj yazma/elde tutulan telefon kullanma ihlali, 120 günlük bir CDL diskalifiyesiyle sonuçlanır?","options":["3 veya daha fazla","2","5","4"],"explanation":"Mesaj yazma/elde tutulan telefon kullanma ciddi trafik ihlalleri olduğundan, 3 yıl içinde üç veya daha fazlası 120 günlük bir diskalifiyeye neden olur (iki tanesi 60 güne neden olur). Kaynak: 49 CFR 383.51, 392.82; RI CDL Manual."},"50":{"q":"Rhode Island'da, 10 yıllık bir süre içinde ÜÇÜNCÜ veya sonraki bir hizmet dışı emri ihlali (standart faaliyetler) hangi diskalifiyeyle sonuçlanır?","options":["3 yıl","1 yıl","5 yıl","Ömür boyu"],"explanation":"10 yıl içinde üçüncü veya sonraki bir OOS emri ihlali, Rhode Island'da 3 yıllık bir diskalifiye taşır. Kaynak: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"51":{"q":"Bir Rhode Island CDL sahibi, plakart taşıyan tehlikeli madde taşırken veya 16 ya da daha fazla yolcu taşımak için tasarlanmış bir aracı kullanırken bir hizmet dışı emrini ihlal ederse, İLK ihlal diskalifiyesi en az:","options":["180 gün","90 gün","1 yıl","60 gün"],"explanation":"Hazmat taşırken veya 16+ yolcu taşırken işlenen bir ilk OOS ihlali, Rhode Island'da asgari diskalifiyeyi 180 güne yükseltir. Kaynak: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"52":{"q":"Rhode Island'da, bir CDL sahibinin İLK demiryolu hemzemin geçidi ihlali için asgari diskalifiye nedir?","options":["60 gün","30 gün","90 gün","120 gün"],"explanation":"Bir ilk demiryolu hemzemin geçidi ihlali, Rhode Island'da asgari 60 günlük bir diskalifiye ile sonuçlanır. Kaynak: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"53":{"q":"Rhode Island'da, 3 yıllık bir süre içinde İKİNCİ bir demiryolu hemzemin geçidi ihlali, hangi asgari diskalifiyeyle sonuçlanır:","options":["120 gün","60 gün","1 yıl","90 gün"],"explanation":"3 yıl içinde ikinci bir demiryolu geçidi ihlali, Rhode Island'da asgari 120 günlük bir diskalifiye taşır. Kaynak: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"54":{"q":"Rhode Island'da, 3 yıllık bir süre içinde ÜÇÜNCÜ veya sonraki bir demiryolu hemzemin geçidi ihlali, hangi asgari diskalifiyeyle sonuçlanır:","options":["1 yıl","120 gün","60 gün","3 yıl"],"explanation":"3 yıl içinde üçüncü veya sonraki bir demiryolu geçidi ihlali, Rhode Island'da asgari 1 yıllık bir diskalifiye taşır. Kaynak: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"55":{"q":"Bir Rhode Island CDL sahibi, KENDİ kişisel (ticari olmayan) aracını kullanırken DUI'den mahkum edilir. CDL'sine ne olur?","options":["En az 1 yıl boyunca bir CMV kullanmaktan diskalifiye edilir","Hiçbir şey, çünkü bu bir ticari araç değildi","Yalnızca 60 günlük bir diskalifiye alır","Yalnızca bir ciddi ihlal cezasıyla karşı karşıya kalır"],"explanation":"Rhode Island'da herhangi bir araçta, kişisel bir otomobil dahil, bir DUI mahkumiyeti, bir CDL sahibini büyük bir suç olarak en az 1 yıl boyunca bir CMV kullanmaktan diskalifiye eder. Kaynak: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"56":{"q":"Aşağıdakilerden hangisi, bir Rhode Island CDL sahibi için ciddi bir trafik ihlali yerine BÜYÜK bir suçtur (1 yıllık diskalifiye)?","options":["Bir CMV'yi bir suçun işlenmesinde kullanmak","Çok yakından takip etmek","Uygunsuz veya düzensiz şerit değiştirme","Uygun sınıf veya onay olmadan bir CMV kullanmak"],"explanation":"Bir suç işlemek için bir CMV kullanmak, 1 yıllık diskalifiye taşıyan büyük bir suçtur; diğer seçenekler ciddi trafik ihlalleridir. Kaynak: R.I. Gen. Laws 31-10.3-31; RI CDL Manual, Section 2; 49 CFR 383.51."},"57":{"q":"Rhode Island'da çocuk taşıyan bir okul otobüsü, ücret karşılığı yolcu taşıyan bir otobüs veya patlayıcı ya da yanıcı sıvı taşıyan bir araç, demiryolu raylarını geçmeden önce en yakın raya ne kadar mesafede durmalıdır?","options":["100 feet içinde ancak 50 feet'ten az olmamak üzere","50 feet içinde ancak 15 feet'ten az olmamak üzere","25 feet içinde ancak 10 feet'ten az olmamak üzere","75 feet içinde ancak 25 feet'ten az olmamak üzere"],"explanation":"RI General Laws § 31-20-4, ücret karşılığı yolcu taşıyan herhangi bir motorlu aracın, okul çocuğu taşıyan herhangi bir okul otobüsünün veya patlayıcı maddeler ya da yanıcı sıvılar taşıyan herhangi bir aracın sürücüsünün en yakın raya elli feet (50') içinde ancak on beş feet'ten (15') az olmamak üzere durmasını gerektirir. Kaynak: RIGL § 31-20-4."},"58":{"q":"Rhode Island yasalarına göre, ücretli otobüsler, okul otobüsleri ve patlayıcı/yanıcı sıvı taşıyıcılarından istenen demiryolu geçidinde durma kuralı hangi durumda UYGULANMAZ?","options":["Araç kargosuz veya yolcusuz olduğunda her zaman","Sürücünün tehlikeli madde onayına sahip olduğu herhangi bir zamanda","Otomatik bariyerlerle donatılmış herhangi bir geçitte","Bir görevlinin veya trafik kontrol sinyalinin trafiğe devam etmesini yönlendirdiği bir geçitte ya da ticari veya yerleşim bölgesi içindeki geçitlerde"],"explanation":"RIGL § 31-20-4, bir polis memurunun veya trafik kontrol sinyalinin trafiğe devam etmesini yönlendirdiği yerde durulmasına gerek olmadığını belirtir ve bu madde ticari ya da yerleşim bölgesi içindeki demiryolu hemzemin geçitlerinde uygulanmaz. Boş bir otobüs veya bariyerlerin bulunması kuralı geçersiz kılmaz. Kaynak: RIGL § 31-20-4."},"59":{"q":"Rhode Island'da bölünmüş bir karayolunda, bir sürücü yanıp sönen kırmızı ışıklar gösteren durmuş bir okul otobüsü için ne zaman durmak zorunda DEĞİLDİR?","options":["Sürücü 20 mph altında seyrettiği her durumda","Sürücü otobüsten iki araç boyundan daha uzakta olduğunda","Asla — tüm sürücüler her iki yönde de her zaman durmalıdır","Otobüs, sürücüden bölünmüş karayolunun karşı tarafındaki yolda durduğunda"],"explanation":"RIGL § 31-20-13, karayolunun bölünmüş bir karayolu olduğu ve sürücü diğer tarafta seyrederken otobüsün bölünmüş karayolunun bir tarafındaki yolda durduğu durumda sürücünün durmasına gerek olmadığını öngörür. RI DMV, bölünmüş karayolunu bir bariyer, koruyucu küpeşte ya da çim/beton refüj ile ayrılmış bir karayolu olarak tanımlar. Kaynak: RIGL § 31-20-13; RI DMV School Buses sayfası."},"60":{"q":"Rhode Island, okul otobüsü durma istisnası için 'bölünmüş karayolu'nu aşağıdakilerden hangisiyle ayrılmış bir yol olarak tanımlar?","options":["Yalnızca çift sarı orta çizgi","Ortada iki yönlü bir sola dönüş şeridi","Karşı yönlü şeritler arasında bir Jersey bariyeri, koruyucu küpeşte, çim ya da beton refüj, ağaçlar, su veya benzeri bir ayırma","Toplam üç veya daha fazla şeride sahip herhangi bir yol"],"explanation":"RI DMV, bölünmüş karayolu istisnasının yalnızca karşı yönlerin bir Jersey bariyeri, koruyucu küpeşte, çim ya da beton refüj, ağaçlar, su vb. ile ayrıldığı yerlerde uygulandığını açıklar. Boyalı bir orta çizgi veya dönüş şeridi bir ayırıcı değildir. Kaynak: RI DMV School Buses sayfası (RIGL § 31-20-13'ü yorumlayarak)."},"61":{"q":"Sıradan (bölünmemiş) iki şeritli bir yolda kırmızı ışıkları yanıp sönen bir Rhode Island okul otobüsüyle karşılaşırken veya onu geçerken, bir sürücü ne yapmalıdır?","options":["15 mph'ye yavaşlayıp dikkatle geçmeli","Yalnızca otobüsün arkasından yaklaşıyorsa durmalı","Yalnızca fiilen yolda olan çocuklara yol vermeli","Her iki yönden de durmalı ve otobüs hareket edene ya da yanıp sönen ışıklar kapatılana kadar devam etmemeli"],"explanation":"RIGL § 31-20-12, yanıp sönen kırmızı ışıklarla 'okul otobüsü' olarak işaretlenmiş bir otobüsle herhangi bir yönden karşılaşan veya onu geçen sürücülerin durmasını gerektirir ve sürücü, otobüs harekete devam edene ya da yanıp sönen ışıklar artık çalıştırılmayana kadar devam etmemelidir. Kaynak: RIGL § 31-20-12."},"62":{"q":"Rhode Island yasaları, herhangi bir aracın (resmi görevdeki bir acil durum aracı dışında) sürücüsünün bir okul otobüsünü hangi mesafeden daha yakından takip etmesini yasaklar?","options":["100 feet","20 feet","50 feet","300 feet"],"explanation":"RIGL § 31-20-12, resmi görevdeki acil durum araçları hariç, bir okul otobüsünün arkasından elli feet'ten (50') daha az bir mesafede sürmeyi yasaklar. Kaynak: RIGL § 31-20-12."},"63":{"q":"Rhode Island'ın Move Over (Şerit Değiştir) yasası kapsamında, sürücünün yönünde en az iki şeritli bir yolda yanıp sönen ışıklar gösteren durmuş bir acil durum aracına, çekiciye veya karayolu bakım aracına yaklaşırken sürücü ne yapmalıdır?","options":["Araç ayrılana kadar tamamen durmalı","Korna çalıp belirlenen hızda devam etmeli","Sağ banket üzerine geçip durmalı","Güvenli bir şekilde yapılabildiğinde, durmuş araca en yakın olmayan bir şeride geçmeli"],"explanation":"RIGL § 31-14-3, yol o yönde iki veya daha fazla şeride sahipse ve manevra güvenli bir şekilde yapılabiliyorsa, sürücünün yanıp sönen ışıklar gösteren durmuş yetkili acil durum aracına, çekici/taşıyıcı kamyona, yol yardımı aracına ya da bakım ekipmanına en yakın olmayan bir şeride geçmesini gerektirir. Kaynak: RIGL § 31-14-3."},"64":{"q":"Rhode Island'ın Move Over (Şerit Değiştir) yasası kapsamında, sürücünün yönünde yalnızca bir şerit olduğunda veya şerit değişikliği güvenli bir şekilde yapılamadığında sürücü ne yapmalıdır?","options":["Seyir şeridinde tamamen durmalı","Belirlenen hız sınırını korumalı","Yoldan çekilip beş dakika beklemeli","Güvenli, azaltılmış bir hıza yavaşlamalı ve aracı tamamen geçene kadar o hızda kalmalı"],"explanation":"RIGL § 31-14-3, yalnızca bir şerit olduğu veya şerit değiştirmenin güvensiz olduğu yerde sürücünün aracı koşullara göre güvenli bir hıza yavaşlatmasını ve durmuş aracı tamamen geçene kadar o azaltılmış hızda seyretmesini yönlendirir. Kaynak: RIGL § 31-14-3."},"65":{"q":"Rhode Island'ın Move Over (Şerit Değiştir) yasası, uyarı ışıkları gösteren aşağıdaki durmuş araçlardan hangilerini korur?","options":["Yalnızca polis arabaları ve ambulanslar","Yalnızca eyalete ait araçlar","Acil durum araçları, çekici/taşıyıcı kamyonlar, yol yardımı araçları ve karayolu bakım ekipmanları","Yalnızca aktif olarak yangınla mücadele eden itfaiye araçları"],"explanation":"RIGL § 31-14-3, yanıp sönen ışıklar gösteren yetkili acil durum araçlarını, çekicileri, taşıyıcı kamyonları, yol yardımı araçlarını ve karayolu bakım ekipmanlarını korunan olarak listeler. Yasa yalnızca polis ve ambulanslarla sınırlı değildir. Kaynak: RIGL § 31-14-3."},"66":{"q":"Belirlenmiş bir sınır yoksa, Rhode Island'da herhangi bir ticari veya yerleşim bölgesindeki ilk bakışta (prima facie) hız sınırı şudur:","options":["25 mph","30 mph","20 mph","35 mph"],"explanation":"RIGL § 31-14-2, herhangi bir ticari veya yerleşim bölgesinde saatte yirmi beş mil (25 mph) prima facie bir sınır belirler. Kaynak: RIGL § 31-14-2."},"67":{"q":"Rhode Island'ın prima facie hız sınırları kapsamında, ticari/yerleşim bölgeleri ve okul bölgeleri dışındaki, başka bir sınırın belirlenmediği yerlerde gündüz sınırı nedir?","options":["55 mph gündüz","50 mph gündüz","45 mph gündüz","65 mph gündüz"],"explanation":"RIGL § 31-14-2, diğer yerlerde gündüz saatte elli mil (50 mph) ve gece saatte kırk beş mil (45 mph) prima facie bir sınır belirler. Eyaletler arası karayolundaki belirlenmiş sınırlar daha yüksek olabilir. Kaynak: RIGL § 31-14-2."},"68":{"q":"Okul günlerinde bir okulun giriş ve çıkışlarının 300 feet içinde, Rhode Island şu prima facie hız sınırını belirler:","options":["Her zaman 15 mph","Gündüz saatlerinde 20 mph","Gündüz saatlerinde 25 mph","Çocuklar mevcut olduğunda 10 mph"],"explanation":"RIGL § 31-14-2, okulların açık olduğu günlerde gündüz saatlerinde herhangi bir okul binası arazisinin giriş ve çıkışlarının üç yüz feet (300') içinde saatte yirmi mil (20 mph) belirler. Kaynak: RIGL § 31-14-2."},"69":{"q":"Rhode Island karayolunda, trafiğin normal hızından daha yavaş seyreden bir ticari araç şunu yapmalıdır:","options":["Sağ şeritte ya da mümkün olduğunca yolun sağ kenarına yakın sürmek","Birleşen trafikten kaçınmak için orta şeritte kalmak","Giriş rampalarından uzak durmak için sol şeridi kullanmak","Dörtlü flaşörler açık olduğu sürece herhangi bir şeridi kullanmak"],"explanation":"RIGL § 31-15-2 ('Yavaş trafik sağa'), trafiğin normal hızından daha yavaş seyreden herhangi bir aracın, geçme, sollama veya sola dönüşe hazırlanma haricinde, mevcut sağ şeritte ya da mümkün olduğunca sağ bordüre ya da kenara yakın sürülmesini gerektirir. Kaynak: RIGL § 31-15-2."},"70":{"q":"Büyük boy izni olmadan, Rhode Island'da bir aracın veya yükünün azami yasal genişliği şudur:","options":["102 inches (8 feet 6 inches)","96 inches (8 feet)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"RIGL § 31-25-3, bir büyük boy izni gerekli olmadan önce bir aracın veya yükünün toplam dış genişliğini yüz iki inch (102\"), yani 8 feet 6 inches ile sınırlar. Kaynak: RIGL § 31-25-3; RIDOT Legal OSOW kılavuzu."},"71":{"q":"Büyük boy izni olmadan, Rhode Island'da yükü dahil bir aracın azami yasal yüksekliği şudur:","options":["168 inches (14 feet)","162 inches (13 feet 6 inches)","156 inches (13 feet)","150 inches (12 feet 6 inches)"],"explanation":"RIGL § 31-25-4, yük dahil araç yüksekliğini yüz altmış iki inch (162\"), yani 13 feet 6 inches ile sınırlar. RIDOT'un Legal OSOW kılavuzu yasal yükseklik olarak 13'6\"yı doğrular. Kaynak: RIGL § 31-25-4; RIDOT Legal OSOW kılavuzu."},"72":{"q":"Rhode Island'da, 48 feet 6 inches'tan daha uzun bir yarı römork yalnızca nerede çalışabilir?","options":["Eyalette herhangi bir yerde, kısıtlama olmaksızın","Yalnızca paralı yollarda","Eyaletler arası karayolu sisteminde ve RIDOT direktörü tarafından belirlenen diğer karayollarında","Yalnızca herhangi bir yolda gün doğumu ile gün batımı arasında"],"explanation":"RIGL § 31-25-6, yarı römorkları elli üç feet (53') ile sınırlar ancak kırk sekiz buçuk feet'ten (48'6\") uzun olanların yalnızca eyaletler arası sistemde ve RIDOT direktörü tarafından belirlenen karayollarında/sokaklarda/yollarda çalışmasına izin verir. Kaynak: RIGL § 31-25-6."},"73":{"q":"İzin olmaksızın, Rhode Island karayollarında herhangi bir aracın veya araç kombinasyonunun azami brüt ağırlığı şudur:","options":["73,280 pounds","80,000 pounds","88,000 pounds","100,000 pounds"],"explanation":"RIGL § 31-25-14, toplam brüt ağırlığı seksen bin pound (80,000 lbs) ile sınırlar, ayrıca federal köprü formülüne de tabidir. Kaynak: RIGL § 31-25-14."},"74":{"q":"Rhode Island yasalarına göre, bir aracın herhangi bir tek dingilinde izin verilen azami brüt ağırlık şudur:","options":["22,400 pounds","20,000 pounds","34,000 pounds","18,000 pounds"],"explanation":"RIGL § 31-25-14, herhangi bir dingilin tekerleklerindeki brüt ağırlığı yirmi iki bin dört yüz (22,400) pound ile sınırlar; bir tandem dingil (8 feet'e kadar aralık) 36,000 pound ile sınırlıdır. Kaynak: RIGL § 31-25-14."},"75":{"q":"2026 itibarıyla, Rhode Island'ın RhodeWorks köprü ücretlendirme programı hangi araçlardan ücret alacak şekilde yapılandırılmıştır?","options":["Yalnızca Class 8 (ve daha büyük) çekici-römorklar; binek otomobiller ve kamyonetler muaftır","10,000 pound üzerindeki tüm araçlar","Ücretli bir köprüyü geçen her araç","Yalnızca eyalet dışı ticari kamyonlar"],"explanation":"Rhode Island'ın RhodeWorks programı, köprü geçiş kapılarında yalnızca büyük ticari kamyonlardan — Class 8 ve daha büyük çekici-römorklardan — ücret alır ve binek otomobilleri ile daha küçük ticari araçları muaf tutar. First Circuit, yalnızca çekici-römork yapısını onayladı (yalnızca günlük üst sınırı iptal etti). Kaynak: RIDOT/RhodeWorks; First Circuit RhodeWorks kararı."},"76":{"q":"Bir Rhode Island ticari aracı, iki şeritli, iki yönlü bir yolun seyir kısmında durduğunda, sürücü gerekli üç uyarı üçgenini nereye yerleştirmelidir?","options":["Üçünü de arka tamponun 10 ft içinde","Biri 200 ft'te ve ikisi 100 ft'te, hepsi aracın arkasında","Trafiğe doğru aracın yaklaşık 10 ft arkasına, yaklaşık 100 ft arkasına ve aracın yaklaşık 100 ft önüne","Yalnızca bir üçgen, arkaya 50 ft mesafede yerleştirilmiş"],"explanation":"Rhode Island, CDL kılavuzunda öğretilen federal standardı (49 CFR 392.22) izler: iki şeritli, iki yönlü bir yolda trafiğe doğru bir üçgeni aracın yaklaşık 10 ft arkasına, birini yaklaşık 100 ft arkasına ve birini yaklaşık 100 ft önüne yerleştirin. (Bölünmüş veya tek yönlü bir yolda arkadaki cihazlar 10, 100 ve 200 ft'e konur.) Kaynak: RI CDL Manual; 49 CFR 392.22."},"77":{"q":"Rhode Island'da Ticari Sürücü Belgelerini (CDL) hangi kurum verir?","options":["Rhode Island Division of Motor Vehicles (DMV)","Rhode Island Department of Transportation (RIDOT)","Rhode Island State Police Commercial Enforcement Unit","Federal Motor Carrier Safety Administration (FMCSA)"],"explanation":"Rhode Island'da CDL'ler RI Division of Motor Vehicles (RI DMV) tarafından verilir. RIDOT yolları ve büyük boy/aşırı yük izinlerini yönetir, FMCSA ise federal standartları belirler ancak eyalet belgeleri vermez. Kaynak: RI DMV, Commercial Driver License (CDL) sayfaları."},"78":{"q":"Rhode Island'da yüz yüze CDL beceri (yol) testleri nerede uygulanır?","options":["400 Romano Vineyard Way, North Kingstown adresindeki özel CDL test alanında","Eyalet genelindeki herhangi bir AAA şube ofisinde","Yalnızca Cranston DMV merkezinde","I-95 boyunca RIDOT tartı istasyonlarında"],"explanation":"RI ticari beceri testleri, 400 Romano Vineyard Way, North Kingstown adresindeki CDL test alanında randevu ile verilir. Cranston DMV, yüz yüze CDL gişe işlemlerini ve bilgi testini yürütür, ancak beceri testi North Kingstown alanında yapılır. Kaynak: RI DMV, Commercial Skills Test sayfası."},"79":{"q":"Bir başvuru sahibi, Rhode Island CDL'sine başvurmadan önce normal bir (Class D) sürücü belgesine ne kadar süre sahip olmuş olmalıdır?","options":["En az 2 yıl","En az 6 ay","En az 1 yıl","En az 3 yıl"],"explanation":"Rhode Island, bir CDL başvuru sahibinin başvuru anında en az iki (2) yıl belgeli bir sürücü olmuş olmasını gerektirir. Kaynak: RI DMV, Commercial Driving License (CDL) / Commercial Learner's Permit and Exams sayfaları."},"80":{"q":"Rhode Island kuralları kapsamında, eyalet içi (yalnızca eyalet sınırları içinde) sürüş için bir CDL almanın asgari yaşı nedir?","options":["18 yaşında","16 yaşında","21 yaşında","25 yaşında"],"explanation":"18 yaşında yalnızca eyalet içi (eyalet sınırları içinde) seyahat için bir Rhode Island CDL alabilirsiniz; eyaletler arası (eyalet sınırlarını aşan) sürüş için 21 yaşında olmalısınız. Kaynak: RI DMV, Commercial Driving License (CDL) sayfası."},"81":{"q":"Rhode Island'da eyaletler arası (eyalet sınırlarını aşan) bir ticari araç sürmek için gereken asgari yaş nedir?","options":["21 yaşında","18 yaşında","19 yaşında","23 yaşında"],"explanation":"Rhode Island, federal standardı izleyerek, eyaletler arası ticari operasyon için bir sürücünün 21 yaşında olmasını gerektirir; 18-20 yaş arası kişiler eyalet içi sürüşle sınırlıdır. Kaynak: RI DMV, Commercial Driving License (CDL) sayfası."},"82":{"q":"Bir Rhode Island CDL'sine başvurmak için hangi başvuru formu doldurulmalıdır?","options":["Application for Commercial Driver's License (CDL-1)","Form MCSA-5876","Standard License Application (LI-1)","Form DL-44C"],"explanation":"Rhode Island başvuru sahipleri, sürücü geçmişi beyanını da içeren Application for Commercial Driver's License (CDL-1)'i doldurur. Kaynak: RI DMV, Commercial Learner's Permit and Exams sayfası (CDL-1 formu)."},"83":{"q":"Rhode Island'da bir CDL başvuru sahibi hangi yasal varlık kanıtını sunmalıdır?","options":["ABD vatandaşlığı veya yasal daimi ikamet kanıtı","Herhangi bir ülkeden geçerli bir pasaport","Yalnızca bir Social Security kartı, başka kanıt olmaksızın","Bir işverenden noter onaylı bir ikamet beyanı"],"explanation":"RI DMV, tüm CDL başvuru sahiplerinin ABD vatandaşı veya yasal daimi ikamet sahibi olarak durum kanıtı ile birlikte Rhode Island ikamet kanıtı sunmasını gerektirir. Kaynak: RI DMV, Commercial Driving License (CDL) sayfası."},"84":{"q":"Rhode Island Commercial Learner's Permit (CLP) almak için asgari gereklilik olan bilgi sınavı hangisidir?","options":["General Knowledge testi","Air Brakes testi","Combination Vehicles testi","Hazardous Materials testi"],"explanation":"General Knowledge sınavı, Rhode Island'da bir CLP için asgari gerekliliktir; aranan sınıfa ve onaylara bağlı olarak ek bilgi testleri gereklidir. Kaynak: RI DMV, Commercial Learner's Permit and Exams sayfası."},"85":{"q":"Rhode Island General Knowledge CDL testinde (50 soru), geçmek için hangi puan gereklidir?","options":["%80 (50 sorudan 40'ı doğru)","%70 (50 sorudan 35'i doğru)","%75 (50 sorudan 38'i doğru)","%90 (50 sorudan 45'i doğru)"],"explanation":"Rhode Island, standart CDL geçme eşiği olan %80'i izler; 50 soruluk General Knowledge testinde bu 40 doğru cevap anlamına gelir. Kaynak: RI CDL Manual / RI DMV bilgi testi standartları."},"86":{"q":"Bir Rhode Island Commercial Learner's Permit (CLP) ne kadar süre geçerlidir ve yenilenebilir mi?","options":["Azami bir yıl geçerli ve yenilenemez","180 gün geçerli ve bir kez yenilenebilir","İki yıl geçerli ve yenilenebilir","60 gün geçerli ve yenilenemez"],"explanation":"Bir Rhode Island CLP azami bir yıl geçerlidir ve yenilenemez; süresi dolarsa başvuru sahibi tüm bilgi sınavlarını yeniden yapmalı ve ücretleri yeniden ödemelidir. Kaynak: RI DMV, Commercial Learner's Permit and Exams sayfası."},"87":{"q":"Bir Rhode Island CLP'si aldıktan sonra, sahibinin CDL beceri testine girebilmesi için CLP'nin ne kadar süre elde tutulması gerekir?","options":["En az 14 gün","En az 30 gün","En az 7 gün","En az 60 gün"],"explanation":"İzlediği federal kurala uygun olarak, Rhode Island, CDL beceri testine girmeden önce CLP'nin en az 14 gün elde tutulmasını gerektirir. Kaynak: RI DMV, Commercial Skills Test sayfası (FMCSA 49 CFR 383 standardı)."},"88":{"q":"Rhode Island CDL beceri testinin üç bölümü nedir?","options":["Vehicle Inspection, Basic Control Skills ve Road Test","Yazılı test, Görme testi ve Road Test","Air Brakes, Geri manevra ve Karayolu Sürüşü","Pre-trip, Hazardous Materials ve Gece Sürüşü"],"explanation":"Rhode Island beceri testinin üç bölümü vardır: Vehicle Inspection (pre-trip) Testi, Basic Control Skills Testi ve Road Test; bir başvuru sahibi üçünü de geçmelidir. Kaynak: RI DMV, Commercial Skills Test sayfası."},"89":{"q":"Rhode Island CDL beceri testi için kullanılan aracı kim sağlamalıdır ve araç hangi durumda olmalıdır?","options":["Başvuru sahibi kendi aracını sağlar ve araç boş (kargosuz) gelmelidir","DMV tüm başvuru sahipleri için eyalete ait bir test aracı sağlar","Başvuru sahibinin işvereni yüklü bir test aracı sağlamalıdır","Ağırlık sınıfından bağımsız olarak herhangi bir kiralık kapalı kasa kamyon kabul edilir"],"explanation":"Rhode Island'da aday kendi temsili aracını sağlamalı ve araç boş (kargosuz) gelmelidir; tankerler boş, temizlenmiş ve tahliye edilmiş olarak belgelenmelidir. Kaynak: RI DMV, Commercial Skills Test sayfası."},"90":{"q":"CLP ve sürücü belgesinin yanı sıra, Rhode Island beceri testi için hangi belgeler sunulmalıdır?","options":["Geçerli araç tescili, aktif sigorta kanıtı ve geçerli bir muayene etiketi","Bir lise diploması ve istihdam kanıtı","Yalnızca bir pasaport ve doğum belgesi","Bir CDL eğitim okulundan noter onaylı bir mektup"],"explanation":"Rhode Island, CLP ve sürücü belgesinin basılı kopyalarının yanı sıra geçerli araç (ve varsa römork) tescili, aktif sigorta kanıtı ve aktif bir araç muayene etiketi gerektirir. Kaynak: RI DMV, Commercial Skills Test sayfası."},"91":{"q":"Rhode Island kuralları kapsamında, ilk kez başvuran bir Class A veya Class B başvuru sahibi için Entry-Level Driver Training (ELDT) ne zaman tamamlanmalıdır?","options":["CDL beceri testine girmeden önce","Beceri testini geçtikten sonra 30 gün içinde","Yalnızca CDL zaten verildikten sonra","İsteğe bağlıdır ve işveren onayıyla atlanabilir"],"explanation":"ELDT, ilk kez başvuran bir Class A/B başvuru sahibinin CDL beceri testine girmesine izin verilmeden önce kayıtlı bir sağlayıcı ile başarıyla tamamlanmalıdır. Kaynak: RI DMV, ELDT sayfası (7 Şubat 2022'de yürürlüğe giren federal ELDT kuralı)."},"92":{"q":"Rhode Island hangi onay için ELDT'nin beceri testinden değil, BİLGİ testinden önce tamamlanmasını gerektirir?","options":["Hazardous Materials (H) onayı","Passenger (P) onayı","School Bus (S) onayı","Doubles/Triples (T) onayı"],"explanation":"Hazardous Materials (H) onayı için ELDT, bilgi testine girmeden önce tamamlanmalıdır; P ve S onayları için ELDT beceri testinden önce tamamlanır. Kaynak: RI DMV, ELDT sayfası."},"93":{"q":"Bir Rhode Island başvuru sahibi, onaylı bir ELDT eğitim sağlayıcısı bulmak için nerede aramalıdır?","options":["FMCSA Training Provider Registry (TPR)","RI DMV CLP bekleme listesi portalı","National Registry of Certified Medical Examiners","RIDOT izin ofisi tedarikçi listesi"],"explanation":"Onaylı ELDT sağlayıcıları FMCSA Training Provider Registry'de (tpr.fmcsa.dot.gov) listelenir; tamamlanma da orada doğrulanabilir. Kaynak: RI DMV, ELDT sayfası."},"94":{"q":"Bir Rhode Island CDL başvuru sahibi kaç tane öz-belgelendirme ticaret kategorisinden seçim yapmalıdır?","options":["Dört kategori","İki kategori","Üç kategori","Altı kategori"],"explanation":"Bir Rhode Island başvuru sahibi dört kategoriden birine öz-belgelendirme yapmalıdır: Interstate Non-Excepted, Interstate Excepted, Intrastate Non-Excepted veya Intrastate Excepted. Kaynak: RI DMV, Medical Certification / Self-Certification sayfası."},"95":{"q":"'Interstate Non-Excepted' olarak belgelendirme yapan bir Rhode Island sürücüsü ne yapmalıdır?","options":["Bir federal DOT Medical Examiner's Certificate edinmeli ve sürdürmeli","Eyalet sınırları boyunca herhangi bir kargo taşımaktan kaçınmalı","CDL'yi beş yılda bir yerine her yıl yenilemeli","Eyaletler arası durumları nedeniyle yol testini atlamalı"],"explanation":"Interstate Non-Excepted sürücüleri Rhode Island içinde ve dışında çalışır ve bir federal DOT Medical Examiner's Certificate edinmek zorundadır; excepted kategorileri zorunlu değildir. Kaynak: RI DMV, Medical Certification / Self-Certification sayfası."},"96":{"q":"Excepted olmayan bir Rhode Island CDL sürücüsünün DOT tıbbi belgelendirmesi artık DMV'ye nasıl iletilir?","options":["Belgeli tıbbi muayene uzmanı bunu elektronik olarak FMCSA National Registry'ye gönderir, o da RI DMV'ye iletir","Sürücü tıbbi kartın bir kağıt kopyasını doğrudan RI DMV'ye postalar","İşveren belgeyi dosyalanması için RIDOT'a fakslar","Sürücü bunu RI E-ZPass hesap portalı üzerinden yükler"],"explanation":"RI DMV artık tıbbi belgelendirmeyi doğrudan kabul etmez; belgeli tıbbi muayene uzmanı, Medical Examiner's Certificate (Form MCSA-5876/5875) belgesini elektronik olarak FMCSA National Registry'ye gönderir, o da DMV'ye iletir. Belgeyi güncel tutmamak CDL düşürülmesiyle sonuçlanır. Kaynak: RI DMV, Medical Certification sayfası; National Registry of Certified Medical Examiners."}},"es":{"0":{"q":"En las carreteras de Rhode Island, ¿cuál es el ancho máximo legal de un vehículo comercial o su carga, sin un permiso especial?","options":["96 pulgadas (8 pies)","102 pulgadas (8 pies 6 pulgadas)","108 pulgadas (9 pies)","120 pulgadas (10 pies)"],"explanation":"Las Leyes Generales de Rhode Island § 31-25-3 establecen el ancho máximo de cualquier vehículo o su carga en 102 pulgadas (8 pies 6 pulgadas). Cualquier cosa más ancha requiere un permiso de sobredimensión de RIDOT. Fuente: R.I. Gen. Laws § 31-25-3."},"1":{"q":"¿Cuál es la altura máxima legal de un vehículo, incluida su carga, en las carreteras de Rhode Island sin un permiso?","options":["162 pulgadas (13 pies 6 pulgadas)","156 pulgadas (13 pies)","168 pulgadas (14 pies)","150 pulgadas (12 pies 6 pulgadas)"],"explanation":"Las Leyes Generales de Rhode Island § 31-25-4 limitan la altura del vehículo, incluida la carga, a 162 pulgadas (13 pies 6 pulgadas). Las cargas que excedan esto requieren un permiso de sobrealtura de RIDOT. Fuente: R.I. Gen. Laws § 31-25-4."},"2":{"q":"¿Cuál es el peso bruto total máximo, en libras, para un vehículo o combinación de vehículos en las carreteras de Rhode Island sin un permiso de sobrepeso?","options":["73,280 libras","80,000 libras","88,000 libras","100,000 libras"],"explanation":"Rhode Island limita el peso bruto total a 80,000 libras, igualando el estándar federal interestatal, a menos que se obtenga un permiso especial. Fuente: R.I. Gen. Laws § 31-25-14; Manual de RIDOT para Permisos de Vehículos con Sobrepeso y Sobredimensión."},"3":{"q":"En Rhode Island, el peso bruto que ejercen sobre la carretera las ruedas de cualquier eje individual no puede exceder ¿cuántas libras?","options":["18,000 libras","20,000 libras","22,400 libras","24,000 libras"],"explanation":"Las Leyes Generales de Rhode Island § 31-25-13 establecen un límite de eje individual de 22,400 libras. Esto es mayor que el estándar federal interestatal de eje individual de 20,000 libras, una cifra específica del estado de Rhode Island. Fuente: R.I. Gen. Laws § 31-25-13."},"4":{"q":"¿Cuál es el peso máximo legal en un grupo de ejes en tándem en Rhode Island cuando la separación entre ejes no excede los 8 pies?","options":["32,000 libras","34,000 libras","36,000 libras","40,000 libras"],"explanation":"Las Leyes Generales de Rhode Island § 31-25-14 limitan un grupo de ejes en tándem a 36,000 libras cuando la separación entre ejes no excede los 8 pies. Fuente: R.I. Gen. Laws § 31-25-14."},"5":{"q":"Según la ley de Rhode Island, ¿cómo se define una sola \"carga por eje\" para efectos de los límites de peso?","options":["La carga total sobre todas las ruedas situadas entre dos planos verticales transversales paralelos separados 40 pulgadas","La carga total sobre todas las ruedas situadas entre dos planos separados 96 pulgadas","La carga soportada por cualquier neumático individual del vehículo","La mitad del peso bruto registrado del vehículo"],"explanation":"Las Leyes Generales de Rhode Island § 31-25-13 definen una carga por eje como la carga total transmitida a la carretera por todas las ruedas cuyos centros se encuentran entre dos planos verticales transversales paralelos separados 40 pulgadas, extendiéndose a lo ancho de todo el vehículo. Fuente: R.I. Gen. Laws § 31-25-13."},"6":{"q":"¿Cuál es la longitud máxima de un vehículo individual (no una combinación), incluida la carga y los parachoques, en las carreteras de Rhode Island?","options":["35 pies","40 pies","48 pies","53 pies"],"explanation":"Las Leyes Generales de Rhode Island § 31-25-5 limitan un vehículo individual, incluida cualquier carga, a 40 pies en total (45 pies para un autobús, una autocaravana motorizada o un vehículo recreativo de campamento). Fuente: R.I. Gen. Laws § 31-25-5."},"7":{"q":"En Rhode Island, ¿cuál es la longitud máxima de un solo autobús, autocaravana motorizada o vehículo recreativo de campamento?","options":["40 pies","42 pies","45 pies","48 pies"],"explanation":"Las Leyes Generales de Rhode Island § 31-25-5 permiten que un autobús, una autocaravana motorizada o un vehículo recreativo de campamento alcance los 45 pies, mientras que otros vehículos individuales están limitados a 40 pies. Fuente: R.I. Gen. Laws § 31-25-5."},"8":{"q":"¿Cuál es la longitud máxima de un semirremolque que opera en Rhode Island, excluyendo parachoques y accesorios?","options":["48 pies 6 pulgadas","51 pies","53 pies","57 pies"],"explanation":"Las Leyes Generales de Rhode Island § 31-25-6 permiten semirremolques de hasta 53 pies, excluyendo parachoques y accesorios. Fuente: R.I. Gen. Laws § 31-25-6."},"9":{"q":"En Rhode Island, los semirremolques más largos de qué longitud pueden operar únicamente en el sistema de carreteras interestatales y en las carreteras específicamente designadas por el director?","options":["45 pies","48 pies 6 pulgadas","50 pies","53 pies"],"explanation":"Las Leyes Generales de Rhode Island § 31-25-6 restringen los semirremolques que exceden los 48 pies 6 pulgadas al sistema de carreteras interestatales y a las carreteras, calles y caminos designados por el director. Fuente: R.I. Gen. Laws § 31-25-6."},"10":{"q":"¿Qué agencia emite los permisos para vehículos de sobredimensión y sobrepeso en Rhode Island?","options":["El Departamento de Transporte de Rhode Island (RIDOT)","La Policía Estatal de Rhode Island","La Administración Federal de Carreteras","El secretario de la ciudad o el pueblo local donde comienza el viaje"],"explanation":"Los permisos especiales para vehículos que exceden los límites legales de tamaño o peso son emitidos por el Departamento de Transporte del Estado (RIDOT). Fuente: Manual de RIDOT para Permisos de Vehículos con Sobrepeso y Sobredimensión; R.I. Gen. Laws § 31-25-18."},"11":{"q":"¿Qué fórmula utiliza Rhode Island para determinar el peso bruto permitido en cualquier grupo de ejes consecutivos?","options":["La Fórmula Federal de Puentes: W = 500[(LN/(N-1)) + 12N + 36]","Peso bruto = 1,000 libras por pulgada de ancho de neumático","Peso bruto = 34,000 libras por grupo de ejes, fijo","Peso bruto = 80,000 dividido entre el número de ejes"],"explanation":"Las Leyes Generales de Rhode Island § 31-25-14 aplican la Fórmula Federal de Puentes, W = 500[(LN/(N-1)) + 12N + 36], donde W es el peso bruto sobre un grupo de ejes consecutivos, L es la distancia en pies entre los ejes exteriores del grupo y N es el número de ejes. Fuente: R.I. Gen. Laws § 31-25-14."},"12":{"q":"En la Fórmula de Puentes de Rhode Island W = 500[(LN/(N-1)) + 12N + 36], ¿qué representa la variable \"N\"?","options":["El número de ejes en el grupo que se está considerando","El peso neto únicamente de la carga","El número de neumáticos en el eje de tracción","El ancho nominal del vehículo en pies"],"explanation":"En la Fórmula de Puentes adoptada por Rhode Island, N es el número de ejes del grupo, L es la distancia en pies entre los ejes extremos y W es el peso bruto máximo permitido en ese grupo. Fuente: R.I. Gen. Laws § 31-25-14."},"13":{"q":"Según las reglas de peso de Rhode Island, si la Fórmula de Puentes produce un límite de eje en tándem inferior a 36,000 libras, ¿qué valor se usa como límite legal?","options":["Debe usarse el resultado más bajo de la fórmula","Se usan 34,000 libras","Se considera 36,000 libras como el límite legal","El grupo de ejes debe reespaciarse antes de cargar"],"explanation":"Las Leyes Generales de Rhode Island § 31-25-14 establecen que cuando la Fórmula de Puentes arroja una cifra de eje en tándem inferior a 36,000 libras, se considera 36,000 libras como el límite legal. Fuente: R.I. Gen. Laws § 31-25-14."},"14":{"q":"Un transportista necesita mover una carga indivisible de 11 pies de ancho en una carretera de Rhode Island. ¿Qué debe hacer el transportista?","options":["Nada; 11 pies está dentro del ancho legal","Obtener un permiso de sobredimensión de RIDOT antes de mover la carga","Notificar únicamente al departamento de policía local","Reducir primero la carga a 96 pulgadas"],"explanation":"Debido a que 11 pies (132 pulgadas) excede el ancho legal de 102 pulgadas según el § 31-25-3, el transportista debe obtener un permiso de sobredimensión de RIDOT antes de mover la carga. Fuente: R.I. Gen. Laws § 31-25-3 y § 31-25-18; Manual de Permisos de RIDOT."},"15":{"q":"¿Cuál es la tarifa estándar de RIDOT por viaje único para mover un vehículo o carga no divisible de sobredimensión o sobrepeso en Rhode Island?","options":["$10.00 por viaje","$20.00 por viaje","$50.00 por viaje","$100.00 por viaje"],"explanation":"El Manual de RIDOT para Permisos de Vehículos con Sobrepeso y Sobredimensión cobra una tarifa de $20.00 por viaje para el movimiento de vehículos o cargas no divisibles. Fuente: Manual de RIDOT para Permisos de Vehículos con Sobrepeso y Sobredimensión, Sec. 4.4."},"16":{"q":"En lugar de pagar tarifas por viaje, un transportista que realiza movimientos intraestatales repetidos de sobredimensión/sobrepeso en Rhode Island puede obtener un permiso general por qué tarifa?","options":["$50.00","$100.00","$250.00","$500.00"],"explanation":"El manual de permisos de RIDOT permite obtener un permiso general para movimientos intraestatales por $100.00 en lugar de pagar tarifas por viaje. Fuente: Manual de RIDOT para Permisos de Vehículos con Sobrepeso y Sobredimensión, Sec. 4.4."},"17":{"q":"Según el manual de permisos de Rhode Island, ¿cuántos vehículos de escolta (vehículos piloto) se requieren para una carga con un ancho total superior a 14 pies 6 pulgadas?","options":["No se requiere escolta","Un vehículo de escolta","Dos vehículos de escolta","Cuatro vehículos de escolta"],"explanation":"El manual de permisos de RIDOT requiere una escolta para anchos entre 12 pies 0 pulgadas y 14 pies 6 pulgadas, y dos vehículos de escolta para anchos superiores a 14 pies 6 pulgadas. Fuente: Manual de RIDOT para Permisos de Vehículos con Sobrepeso y Sobredimensión, Sec. 5.4."},"18":{"q":"Según el manual de permisos de Rhode Island, ¿cuándo NO están autorizados generalmente los movimientos permitidos de sobredimensión/sobrepeso?","options":["Desde el atardecer del viernes hasta el amanecer del lunes y en los días festivos enumerados","Solo entre la medianoche y las 4:00 a.m. todos los días","Solo durante la primera semana de cada mes","Nunca; los movimientos permitidos pueden realizarse en cualquier momento"],"explanation":"El manual de permisos de RIDOT prohíbe los movimientos, salvo que se indique lo contrario, desde el atardecer del viernes hasta el amanecer del lunes y en los días festivos legales enumerados. Fuente: Manual de RIDOT para Permisos de Vehículos con Sobrepeso y Sobredimensión, Sec. 4.15 / 5.7."},"19":{"q":"¿Cómo trata la ley de Rhode Island a los vehículos agrícolas, tractores agrícolas, maquinaria vial y equipos contra incendios con respecto a los límites de tamaño y peso del Capítulo 31-25?","options":["Están exentos de las limitaciones de tamaño y peso","Están limitados al 50% de los límites de peso normales","Deben portar un permiso anual de sobredimensión en todo momento","Tienen prohibido el acceso a todas las carreteras estatales numeradas"],"explanation":"Las Leyes Generales de Rhode Island § 31-25-2 eximen a los equipos contra incendios, la maquinaria vial y los vehículos agrícolas (incluidos los tractores agrícolas) que se desplazan temporalmente por una carretera de las limitaciones de tamaño y peso del Capítulo 31-25. Fuente: R.I. Gen. Laws § 31-25-2."},"20":{"q":"En Rhode Island, ¿cuál es la edad mínima para obtener una CDL válida únicamente para operación INTRAESTATAL (dentro del estado)?","options":["16 años","18 años","21 años","25 años"],"explanation":"El Manual de CDL de RI (Guías para Solicitantes de CDL) indica que debes tener una licencia de conducir válida durante al menos dos años y tener al menos 18 años para una CDL SOLO INTRAESTATAL; se requieren 21 años para la operación interestatal. Fuente: Manual de Licencia de Conducir Comercial del RI DMV (AAMVA 2005, Rev. julio de 2014)."},"21":{"q":"¿Cuál es la edad mínima requerida en Rhode Island para operar un vehículo motorizado comercial en el comercio INTERESTATAL (cruzando límites estatales)?","options":["18 años","19 años","21 años","23 años"],"explanation":"El RI DMV requiere que un conductor tenga 21 años para ser elegible para la operación de CDL interestatal (cruzando límites estatales); con 18 años solo califica para operación intraestatal. Fuente: página de CDL del RI DMV y Manual de Licencia de Conducir Comercial de RI (Rev. julio de 2014)."},"22":{"q":"Según la clasificación de CDL de Rhode Island, ¿qué clase autoriza operar cualquier COMBINACIÓN de vehículos con un GCWR de 26,001 lbs o más, siempre que el GVWR de la(s) unidad(es) remolcada(s) exceda las 10,000 lbs?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"Según el Manual de CDL de RI, una CDL Clase A autoriza la operación de cualquier combinación de vehículos con un GCWR de 26,001 libras o más, siempre que el GVWR del/los vehículo(s) remolcado(s) exceda las 10,000 libras. Fuente: Manual de Licencia de Conducir Comercial de RI, Clases de Licencia."},"23":{"q":"En Rhode Island, una CDL que autoriza un vehículo INDIVIDUAL con un GVWR de 26,001 lbs o más (o ese vehículo remolcando una unidad que no exceda las 10,000 lbs de GVWR) ¿es de qué clase?","options":["Clase A","Clase B","Clase C","Clase E"],"explanation":"El Manual de CDL de RI define la Clase B como cualquier vehículo individual con un GVWR de 26,001 libras o más, o ese vehículo remolcando un vehículo que no exceda las 10,000 libras de GVWR. Fuente: Manual de Licencia de Conducir Comercial de RI, Clases de Licencia."},"24":{"q":"¿Qué clase de CDL de Rhode Island cubre un vehículo (que no cumple con la Clase A o B) diseñado para transportar 16 o más pasajeros incluido el conductor, o uno con placas de materiales peligrosos?","options":["Clase A","Clase B","Clase C","Clase M"],"explanation":"El Manual de CDL de RI define la Clase C como cualquier vehículo que no cumple con la Clase A o B pero que está diseñado para transportar 16 o más pasajeros incluido el conductor, o que lleva placas de materiales peligrosos. Fuente: Manual de Licencia de Conducir Comercial de RI, Clases de Licencia."},"25":{"q":"En una CDL de Rhode Island, ¿qué código de endoso se requiere para transportar materiales peligrosos en cantidades que requieran placas según las regulaciones federales del DOT?","options":["Código N","Código H","Código T","Código P"],"explanation":"Según el Manual de CDL de RI, el endoso H (HazMat) se requiere en CUALQUIER clase de licencia al transportar materiales peligrosos en cualquier cantidad que requiera placas según las regulaciones federales del DOT. Fuente: Manual de Licencia de Conducir Comercial de RI, Endosos."},"26":{"q":"¿Qué endoso requiere Rhode Island para operar un vehículo cisterna que transporta material líquido o gaseoso, o un tanque portátil con capacidad de 1,000 galones o más?","options":["N - Vehículos Cisterna","T - Remolques Dobles/Triples","P - Pasajeros","S - Autobús Escolar"],"explanation":"El Manual de CDL de RI indica que el endoso N (Vehículos Cisterna) se requiere en cualquier clase de licencia al transportar material líquido o gaseoso en un vehículo cisterna, o cualquier tanque portátil con capacidad de 1,000 galones o más. Fuente: Manual de Licencia de Conducir Comercial de RI, Endosos."},"27":{"q":"En Rhode Island, el endoso T (Remolques Dobles/Triples) solo puede ser obtenido por operadores que posean ¿qué clase de CDL?","options":["Operadores de Clase C","Operadores de Clase B","Operadores de Clase A","Operadores de cualquier clase"],"explanation":"El Manual de CDL de RI indica que el endoso T (Remolques Dobles/Triples) se requiere para los operadores de Clase A que transportan remolques dobles/triples donde la operación está permitida por la ley. Fuente: Manual de Licencia de Conducir Comercial de RI, Endosos."},"28":{"q":"Antes del examen, ¿qué paso adicional requiere Rhode Island para un endoso de autobús escolar (S) además del examen escrito y la prueba de habilidades?","options":["Una evaluación de amenaza de seguridad de la TSA","Un Certificado de Autobús Escolar de RI a través de la Oficina de Seguridad de Autobuses Escolares del DMV","Una solicitud de licencia de chofer verde","Una prueba de conocimientos de dobles/triples"],"explanation":"El Manual de CDL de RI indica que los operadores con endoso S (Autobús Escolar) primero deben obtener un Certificado de Autobús Escolar de RI a través de la Oficina de Seguridad de Autobuses Escolares del DMV. Fuente: Manual de Licencia de Conducir Comercial de RI, Endosos."},"29":{"q":"Según el Manual de CDL de Rhode Island, el endoso P (Pasajeros) se requiere cuando un vehículo está diseñado para sentar a más de cuántas personas incluido el operador?","options":["8","12","15","16"],"explanation":"El Manual de CDL de RI indica que el endoso P se requiere en cualquier clase de licencia cuando el vehículo está diseñado para sentar a más de 16 pasajeros incluido el operador; también se debe completar una solicitud de licencia de chofer verde. Fuente: Manual de Licencia de Conducir Comercial de RI, Endosos."},"30":{"q":"¿Qué endoso de CDL de Rhode Island combina los endosos de HazMat y Vehículo Cisterna, requiriendo aprobar ambos exámenes de conocimientos?","options":["Código S","Código T","Código X","Código P"],"explanation":"El Manual de CDL de RI describe el endoso X como la combinación de H (HazMat) y N (Cisterna); se deben presentar ambos exámenes. Fuente: Manual de Licencia de Conducir Comercial de RI, Endosos."},"31":{"q":"Según las reglas federales aplicadas en Rhode Island, ¿cuánto tiempo se debe tener un Permiso de Aprendiz Comercial (CLP) antes de que el titular pueda presentar la prueba de habilidades de la CDL?","options":["7 días","14 días","30 días","60 días"],"explanation":"La regulación federal 49 CFR 383.25, aplicada por el RI DMV, prohíbe que el titular de un CLP presente la prueba de habilidades de la CDL durante los primeros 14 días después de que el CLP se emite inicialmente. Fuente: 49 CFR 383.25; requisitos de CLP del RI DMV."},"32":{"q":"¿Qué prueba de conocimientos debe aprobar TODO solicitante de CDL de Rhode Island, independientemente de la clase o el endoso que busque?","options":["Prueba de Frenos de Aire","Prueba de Vehículos Combinados","Prueba de Conocimientos Generales","Prueba de Transporte de Pasajeros"],"explanation":"El Manual de CDL de RI indica que la prueba de Conocimientos Generales la presentan todos los solicitantes; las demás pruebas dependen de la clase y los endosos. Fuente: Manual de Licencia de Conducir Comercial de RI, Sección 1, Pruebas de Conocimientos."},"33":{"q":"En el examen de Conocimientos Generales de la CDL de Rhode Island, ¿cuántas de las 50 preguntas deben responderse correctamente para aprobar (80%)?","options":["30","40","44","45"],"explanation":"El programa de pruebas electrónicas/manuales del Manual de CDL de RI indica que la prueba de Conocimientos Generales consta de 50 preguntas y requiere 40 correctas (80%) para aprobar. Fuente: Manual de Licencia de Conducir Comercial de RI, Pruebas Electrónicas/Manuales."},"34":{"q":"¿Qué agencia administra y programa la prueba de manejo (de habilidades) de la CDL para los solicitantes de Rhode Island?","options":["La oficina principal del RI DMV en Cranston","El Community College of Rhode Island (CCRI)","La Policía Estatal de RI","La oficina de permisos del DOT de Rhode Island"],"explanation":"El Manual de CDL de RI indica que las pruebas de manejo las imparte y deben programarse con el Community College of Rhode Island (CCRI). Fuente: Manual de Licencia de Conducir Comercial de RI, Pruebas de Manejo."},"35":{"q":"¿Cuál de los siguientes es un documento requerido para un solicitante de CDL de Rhode Island, según las pautas de CLP del RI DMV?","options":["Una tarjeta de Seguro Social válida","Una carta notariada del empleador","Un título de vehículo comercial","Un endoso de motocicleta"],"explanation":"El Manual de CDL de RI requiere que todos los solicitantes presenten una tarjeta de Seguro Social válida, una Tarjeta Médica válida (si no están exentos) y prueba de identidad/residencia. Fuente: Manual de Licencia de Conducir Comercial de RI, Guías para Solicitantes de CDL."},"36":{"q":"La Capacitación Federal para Conductores de Nivel Inicial (ELDT), aplicada en Rhode Island, debe completarse a través de un proveedor incluido en ¿qué registro?","options":["La base de datos de capacitación del DMV estatal","El Registro de Proveedores de Capacitación (TPR) de la FMCSA","La lista de educación vial de AAMVA","La lista de escuelas aprobadas por la TSA"],"explanation":"Desde el 7 de febrero de 2022, los solicitantes de Clase A/B por primera vez, los ascensos de B a A y los nuevos solicitantes de endosos P/S/H deben completar la ELDT con un proveedor en el Registro de Proveedores de Capacitación de la FMCSA antes de la prueba de habilidades (prueba de conocimientos para H). Fuente: regla ELDT de la FMCSA; Registro de Proveedores de Capacitación de la FMCSA."},"37":{"q":"Al autocertificar el estado médico ante el DMV de Rhode Island, ¿cuál de las siguientes es una de las cuatro categorías válidas entre las que un titular de CDL debe elegir?","options":["Comercio Interestatal No Exento","Comercio Recreativo Exento","Comercio Extranjero Certificado","Comercio Agrícola Eximido"],"explanation":"El Manual de CDL de RI enumera cuatro categorías de autocertificación: Interestatal Exento, Interestatal No Exento, Intraestatal Exento e Intraestatal No Exento. Los conductores no exentos deben presentar una tarjeta médica válida (49 CFR 391.45). Fuente: Manual de Licencia de Conducir Comercial de RI, Autocertificación."},"38":{"q":"Según el Manual de CDL de Rhode Island, ¿dentro de cuántos días debe un titular de CDL presentar una nueva Tarjeta Médica al DMV después de que se emite?","options":["10 días","15 días","30 días","45 días"],"explanation":"El Manual de CDL de RI indica que debes presentar tu nueva Tarjeta Médica al DMV dentro de los 15 días posteriores a su emisión; el incumplimiento puede resultar en una degradación de tu licencia. Fuente: Manual de Licencia de Conducir Comercial de RI, Certificación Médica."},"39":{"q":"Al operar un vehículo motorizado comercial en Rhode Island, ¿cuál es la concentración de alcohol en la sangre (BAC) igual o superior a la cual un conductor se considera legalmente intoxicado para efectos de un CMV?","options":["0.04%","0.08%","0.02%","0.10%"],"explanation":"En Rhode Island, operar un CMV con un BAC de 0.04% o más es una infracción grave, la mitad del límite de 0.08% que aplica a los conductores no comerciales. Fuente: R.I. Gen. Laws 31-10.3-31; Manual de CDL de RI, Sección 2."},"40":{"q":"Según la ley de consentimiento implícito de Rhode Island, un titular de CDL que se niega a someterse a una prueba química de aliento, sangre u orina cuando se le solicita legalmente se considera que ha cometido ¿qué?","options":["Una infracción grave, como una condena por DUI","Solo una violación de tránsito seria","Una violación de una orden de fuera de servicio","Un asunto administrativo no reportable"],"explanation":"En Rhode Island, negarse a una prueba química requerida es una infracción grave que conlleva la misma descalificación que una condena por DUI. Fuente: R.I. Gen. Laws 31-10.3-31; Manual de CDL de RI, Sección 2."},"41":{"q":"En Rhode Island, ¿cuál es el período mínimo de descalificación para la PRIMERA infracción grave de un titular de CDL (como un DUI en un CMV) cuando NO se transportan materiales peligrosos con placas?","options":["1 año","60 días","3 años","6 meses"],"explanation":"Rhode Island descalifica a un conductor por al menos 1 año por una primera infracción grave (DUI, BAC de 0.04+, negativa, abandono de la escena o uso de un CMV en un delito grave). Fuente: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"42":{"q":"En Rhode Island, si un conductor comete una primera infracción grave mientras transporta materiales peligrosos que requieren placas, el período mínimo de descalificación aumenta a:","options":["3 años","1 año","120 días","5 años"],"explanation":"Una primera infracción grave mientras se opera un vehículo con placas de hazmat resulta en una descalificación mínima de 3 años en Rhode Island, en lugar del estándar de 1 año. Fuente: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"43":{"q":"En Rhode Island, un titular de CDL que es condenado por una SEGUNDA infracción grave durante su vida enfrenta ¿qué descalificación?","options":["Descalificación de por vida","Descalificación de 10 años","Descalificación de 3 años","Descalificación de 1 año"],"explanation":"Una segunda infracción grave en la vida resulta en una descalificación de por vida en Rhode Island (que, bajo ciertas condiciones, puede reducirse a un mínimo de 10 años). Fuente: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"44":{"q":"¿Cuántas violaciones de tránsito serias dentro de un período de 3 años (derivadas de incidentes separados) provocan una descalificación de CDL de 60 días en Rhode Island?","options":["2","3","4","1"],"explanation":"Dos violaciones de tránsito serias en un CMV dentro de 3 años conducen a una descalificación de 60 días en Rhode Island. Fuente: R.I. Gen. Laws 31-10.3-31; Manual de CDL de RI, Sección 2."},"45":{"q":"En Rhode Island, tres violaciones de tránsito serias dentro de un período de 3 años resultan en una descalificación de CDL de ¿cuánto tiempo?","options":["120 días","60 días","90 días","1 año"],"explanation":"Tres violaciones de tránsito serias en un CMV dentro de 3 años conducen a una descalificación de 120 días en Rhode Island. Fuente: R.I. Gen. Laws 31-10.3-31; Manual de CDL de RI, Sección 2."},"46":{"q":"¿Cuál de las siguientes se clasifica como una violación de tránsito SERIA para un titular de CDL de Rhode Island?","options":["Seguir demasiado cerca del vehículo de adelante","Operar un CMV con un BAC de 0.04%","Negarse a una prueba química","Violar una orden de fuera de servicio"],"explanation":"Seguir demasiado cerca es una de las violaciones de tránsito serias enumeradas; las demás opciones son infracciones graves o violaciones de fuera de servicio con penalidades separadas. Fuente: Manual de CDL de RI, Sección 2; 49 CFR 383.51."},"47":{"q":"Para una violación de tránsito seria en Rhode Island, el exceso de velocidad se define como conducir cuántas millas por hora o más por encima del límite de velocidad señalizado?","options":["15 mph o más","10 mph o más","20 mph o más","25 mph o más"],"explanation":"Conducir a 15 mph o más por encima del límite señalizado es una violación de tránsito seria para efectos de CDL en Rhode Island. Fuente: Manual de CDL de RI, Sección 2; 49 CFR 383.51."},"48":{"q":"Según las reglas federales adoptadas en Rhode Island, usar un teléfono móvil de mano o enviar mensajes de texto mientras se conduce un CMV cuenta como ¿qué tipo de violación para efectos de descalificación?","options":["Una violación de tránsito seria","Una infracción grave","Una violación de una orden de fuera de servicio","Una violación de cruce ferroviario"],"explanation":"Enviar mensajes de texto o usar un teléfono de mano mientras se conduce un CMV es una violación de tránsito seria en Rhode Island, que cuenta para las descalificaciones de 60 días/120 días. Fuente: 49 CFR 383.51, 392.80-392.82; Manual de CDL de RI."},"49":{"q":"¿Cuántas violaciones de mensajes de texto/teléfono de mano dentro de un período de 3 años resultan en una descalificación de CDL de 120 días en Rhode Island?","options":["3 o más","2","5","4"],"explanation":"Debido a que enviar mensajes de texto/usar un teléfono de mano son violaciones de tránsito serias, tres o más dentro de 3 años causan una descalificación de 120 días (dos causan 60 días). Fuente: 49 CFR 383.51, 392.82; Manual de CDL de RI."},"50":{"q":"En Rhode Island, una TERCERA o subsiguiente violación de una orden de fuera de servicio dentro de un período de 10 años (operaciones estándar) resulta en ¿qué descalificación?","options":["3 años","1 año","5 años","De por vida"],"explanation":"Una tercera o subsiguiente violación de una orden OOS dentro de 10 años conlleva una descalificación de 3 años en Rhode Island. Fuente: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"51":{"q":"Si un titular de CDL de Rhode Island viola una orden de fuera de servicio mientras transporta materiales peligrosos con placas o mientras opera un vehículo diseñado para transportar 16 o más pasajeros, la descalificación por la PRIMERA violación es de al menos:","options":["180 días","90 días","1 año","60 días"],"explanation":"Una primera violación de OOS mientras se transporta hazmat o se llevan 16+ pasajeros eleva la descalificación mínima a 180 días en Rhode Island. Fuente: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"52":{"q":"En Rhode Island, ¿cuál es la descalificación mínima para la PRIMERA violación de cruce ferroviario a nivel de un titular de CDL?","options":["60 días","30 días","90 días","120 días"],"explanation":"Una primera violación de cruce ferroviario a nivel resulta en una descalificación mínima de 60 días en Rhode Island. Fuente: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"53":{"q":"En Rhode Island, una SEGUNDA violación de cruce ferroviario a nivel dentro de un período de 3 años resulta en una descalificación mínima de:","options":["120 días","60 días","1 año","90 días"],"explanation":"Una segunda violación de cruce ferroviario dentro de 3 años conlleva una descalificación mínima de 120 días en Rhode Island. Fuente: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"54":{"q":"En Rhode Island, una TERCERA o subsiguiente violación de cruce ferroviario a nivel dentro de un período de 3 años resulta en una descalificación mínima de:","options":["1 año","120 días","60 días","3 años"],"explanation":"Una tercera o subsiguiente violación de cruce ferroviario dentro de 3 años conlleva una descalificación mínima de 1 año en Rhode Island. Fuente: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"55":{"q":"Un titular de CDL de Rhode Island es condenado por DUI mientras conduce su PROPIO vehículo personal (no comercial). ¿Qué sucede con su CDL?","options":["Es descalificado de conducir un CMV por al menos 1 año","Nada, porque no era un vehículo comercial","Recibe solo una descalificación de 60 días","Enfrenta solo una penalidad de violación seria"],"explanation":"En Rhode Island, una condena por DUI en cualquier vehículo, incluido un automóvil personal, descalifica a un titular de CDL de operar un CMV por al menos 1 año como infracción grave. Fuente: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"56":{"q":"¿Cuál de las siguientes es una infracción GRAVE (descalificación de 1 año) para un titular de CDL de Rhode Island en lugar de una violación de tránsito seria?","options":["Usar un CMV en la comisión de un delito grave","Seguir demasiado cerca","Un cambio de carril indebido o errático","Conducir un CMV sin la clase o el endoso apropiados"],"explanation":"Usar un CMV para cometer un delito grave es una infracción grave que conlleva una descalificación de 1 año; las demás opciones son violaciones de tránsito serias. Fuente: R.I. Gen. Laws 31-10.3-31; Manual de CDL de RI, Sección 2; 49 CFR 383.51."},"57":{"q":"En Rhode Island, ¿a qué distancia del riel más cercano debe detenerse un autobús escolar que transporta niños, un autobús que transporta pasajeros a cambio de pago, o un vehículo que transporta explosivos o líquidos inflamables antes de cruzar las vías del ferrocarril?","options":["A menos de 100 pies pero no menos de 50 pies","A menos de 50 pies pero no menos de 15 pies","A menos de 25 pies pero no menos de 10 pies","A menos de 75 pies pero no menos de 25 pies"],"explanation":"La Ley General de RI § 31-20-4 exige que el conductor de cualquier vehículo de motor que transporte pasajeros a cambio de pago, cualquier autobús escolar que transporte a un niño en edad escolar, o cualquier vehículo que transporte sustancias explosivas o líquidos inflamables se detenga a menos de cincuenta pies (50') pero no a menos de quince pies (15') del riel más cercano. Fuente: RIGL § 31-20-4."},"58":{"q":"Según la ley de Rhode Island, la parada obligatoria en los cruces ferroviarios exigida a los autobuses de pago, autobuses escolares y transportistas de explosivos/líquidos inflamables NO aplica en cuál de las siguientes situaciones?","options":["Siempre que el vehículo esté vacío de carga o pasajeros","Cada vez que el conductor tenga un endoso de materiales peligrosos","En cualquier cruce equipado con barreras automáticas","En un cruce donde un oficial o una señal de control de tránsito indica al tránsito que avance, o en cruces dentro de un distrito comercial o residencial"],"explanation":"La RIGL § 31-20-4 establece que no es necesario detenerse cuando un oficial de policía o una señal de control de tránsito indica al tránsito que avance, y la sección no aplica en cruces ferroviarios a nivel dentro de un distrito comercial o residencial. Un autobús vacío o la presencia de barreras no exime del cumplimiento de la regla. Fuente: RIGL § 31-20-4."},"59":{"q":"En una carretera dividida de Rhode Island, ¿cuándo NO está obligado un conductor a detenerse ante un autobús escolar detenido que muestra luces rojas intermitentes?","options":["Siempre que el conductor circule a menos de 20 mph","Cuando el conductor esté a más de dos largos de auto del autobús","Nunca: todos los conductores deben detenerse siempre en ambas direcciones","Cuando el autobús está detenido en la calzada del lado opuesto de la carretera dividida con respecto al conductor"],"explanation":"La RIGL § 31-20-13 dispone que un conductor no necesita detenerse cuando la carretera es una carretera dividida y el autobús está detenido en la calzada de un lado de la carretera dividida mientras el conductor circula por el otro lado. La RI DMV define una carretera dividida como aquella separada por una barrera, guardarraíl, o un camellón de césped/cemento. Fuente: RIGL § 31-20-13; página de Autobuses Escolares de la RI DMV."},"60":{"q":"Rhode Island define una 'carretera dividida' para la excepción de parada ante autobuses escolares como una calzada separada por cuál de los siguientes?","options":["Únicamente una línea central doble amarilla","Un carril central de giro a la izquierda de doble sentido","Una barrera Jersey, guardarraíl, camellón de césped o cemento, árboles, agua, o una separación similar entre los carriles de sentido contrario","Cualquier calzada con tres o más carriles en total"],"explanation":"La RI DMV explica que la excepción de carretera dividida aplica únicamente cuando los sentidos opuestos están separados por una barrera Jersey, guardarraíl, camellón de césped o cemento, árboles, agua, etc. Una línea central pintada o un carril de giro no constituyen un divisor. Fuente: página de Autobuses Escolares de la RI DMV (interpretando la RIGL § 31-20-13)."},"61":{"q":"Al encontrar o rebasar a un autobús escolar de Rhode Island con sus luces rojas intermitentes encendidas en una carretera común (no dividida) de dos carriles, ¿qué debe hacer un conductor?","options":["Reducir a 15 mph y pasar con precaución","Detenerse solo si se aproxima por detrás del autobús","Ceder el paso solo a los niños que realmente estén en la calzada","Detenerse desde cualquier dirección y no avanzar hasta que el autobús se mueva o se apaguen las luces intermitentes"],"explanation":"La RIGL § 31-20-12 exige que los conductores que encuentren o rebasen desde cualquier dirección a un autobús marcado como 'school bus' con luces rojas intermitentes se detengan, y el conductor no debe avanzar hasta que el autobús reanude la marcha o las luces intermitentes ya no estén accionadas. Fuente: RIGL § 31-20-12."},"62":{"q":"La ley de Rhode Island prohíbe al conductor de cualquier vehículo (que no sea un vehículo de emergencia en servicio oficial) seguir a un autobús escolar a una distancia menor de cuál de las siguientes?","options":["100 pies","20 pies","50 pies","300 pies"],"explanation":"La RIGL § 31-20-12 prohíbe circular detrás de un autobús escolar a una distancia menor de cincuenta pies (50'), salvo los vehículos de emergencia en servicio oficial. Fuente: RIGL § 31-20-12."},"63":{"q":"Según la ley 'Move Over' (Cambie de Carril) de Rhode Island, ¿qué debe hacer un conductor al aproximarse a un vehículo de emergencia, una grúa o un vehículo de mantenimiento de carreteras detenido que muestra luces intermitentes en una vía con al menos dos carriles en la dirección del conductor?","options":["Detenerse por completo hasta que el vehículo se retire","Tocar la bocina y continuar a la velocidad indicada","Pasarse al acotamiento derecho y detenerse","Cambiarse a un carril que no sea el más cercano al vehículo detenido, cuando pueda hacerse de manera segura"],"explanation":"La RIGL § 31-14-3 exige que un conductor se cambie a un carril que no sea el más cercano al vehículo de emergencia autorizado, grúa/transportadora, vehículo de asistencia en carretera o equipo de mantenimiento detenido que muestre luces intermitentes, siempre que la vía tenga dos o más carriles en esa dirección y el cambio pueda hacerse de manera segura. Fuente: RIGL § 31-14-3."},"64":{"q":"Según la ley 'Move Over' (Cambie de Carril) de Rhode Island, ¿qué debe hacer un conductor cuando solo hay un carril en su dirección o cuando un cambio de carril no puede hacerse de manera segura?","options":["Detenerse por completo en el carril de circulación","Mantener el límite de velocidad indicado","Salirse de la vía y esperar cinco minutos","Reducir a una velocidad segura y disminuida y mantenerla hasta haber pasado por completo el vehículo"],"explanation":"La RIGL § 31-14-3 indica que, cuando solo hay un carril o el cambio de carril no es seguro, el conductor debe reducir la velocidad del vehículo a una velocidad segura para las condiciones y circular a esa velocidad reducida hasta haber pasado por completo el vehículo detenido. Fuente: RIGL § 31-14-3."},"65":{"q":"La ley 'Move Over' (Cambie de Carril) de Rhode Island protege a cuál de los siguientes vehículos detenidos que muestran luces de advertencia?","options":["Únicamente patrullas de policía y ambulancias","Únicamente vehículos propiedad del estado","Vehículos de emergencia, grúas/transportadoras, vehículos de asistencia en carretera y equipo de mantenimiento de carreteras","Únicamente unidades de bomberos que estén combatiendo activamente un incendio"],"explanation":"La RIGL § 31-14-3 enumera como protegidos a los vehículos de emergencia autorizados, grúas, vehículos transportadores, vehículos de asistencia en carretera y equipos de mantenimiento de carreteras que muestren luces intermitentes. La ley no se limita a la policía y las ambulancias. Fuente: RIGL § 31-14-3."},"66":{"q":"En ausencia de un límite señalizado, el límite de velocidad prima facie de Rhode Island en cualquier distrito comercial o residencial es de:","options":["25 mph","30 mph","20 mph","35 mph"],"explanation":"La RIGL § 31-14-2 establece un límite prima facie de veinticinco millas por hora (25 mph) en cualquier distrito comercial o residencial. Fuente: RIGL § 31-14-2."},"67":{"q":"Según los límites de velocidad prima facie de Rhode Island, ¿cuál es el límite diurno en lugares distintos de los distritos comerciales/residenciales y las zonas escolares, donde no haya otro límite señalizado?","options":["55 mph de día","50 mph de día","45 mph de día","65 mph de día"],"explanation":"La RIGL § 31-14-2 establece un límite prima facie de cincuenta millas por hora (50 mph) en otros lugares durante el día, y de cuarenta y cinco (45 mph) durante la noche. Los límites señalizados en la interestatal pueden ser mayores. Fuente: RIGL § 31-14-2."},"68":{"q":"A menos de 300 pies de las entradas y salidas de una escuela durante los días de clases, Rhode Island establece un límite de velocidad prima facie de:","options":["15 mph en todo momento","20 mph durante el día","25 mph durante el día","10 mph cuando haya niños presentes"],"explanation":"La RIGL § 31-14-2 establece veinte millas por hora (20 mph) a menos de trescientos pies (300') de las entradas y salidas de los terrenos de una escuela durante el día, en los días en que las escuelas están abiertas. Fuente: RIGL § 31-14-2."},"69":{"q":"En una carretera de Rhode Island, un vehículo comercial que circula a menor velocidad que la velocidad normal del tránsito debe:","options":["Circular por el carril derecho o lo más cerca posible del borde derecho de la calzada","Mantenerse en el carril central para evitar el tránsito que se incorpora","Usar el carril izquierdo para mantenerse alejado de las rampas de acceso","Usar cualquier carril mientras tenga encendidas las luces de emergencia de cuatro vías"],"explanation":"La RIGL § 31-15-2 ('Tránsito lento a la derecha') exige que todo vehículo que circule a menor velocidad que la velocidad normal del tránsito sea conducido por el carril derecho disponible, o lo más cerca posible del borde o cuneta derecha, salvo al alcanzar, rebasar o prepararse para un giro a la izquierda. Fuente: RIGL § 31-15-2."},"70":{"q":"Sin un permiso de sobredimensión, el ancho máximo legal de un vehículo o su carga en Rhode Island es de:","options":["102 pulgadas (8 pies 6 pulgadas)","96 pulgadas (8 pies)","108 pulgadas (9 pies)","120 pulgadas (10 pies)"],"explanation":"La RIGL § 31-25-3 limita el ancho total exterior de un vehículo o su carga a ciento dos pulgadas (102\"), es decir, 8 pies 6 pulgadas, antes de que se requiera un permiso de sobredimensión. Fuente: RIGL § 31-25-3; guía Legal OSOW de RIDOT."},"71":{"q":"Sin un permiso de sobredimensión, la altura máxima legal de un vehículo incluyendo su carga en Rhode Island es de:","options":["168 pulgadas (14 pies)","162 pulgadas (13 pies 6 pulgadas)","156 pulgadas (13 pies)","150 pulgadas (12 pies 6 pulgadas)"],"explanation":"La RIGL § 31-25-4 limita la altura del vehículo incluyendo la carga a ciento sesenta y dos pulgadas (162\"), es decir, 13 pies 6 pulgadas. La guía Legal OSOW de RIDOT confirma 13'6\" como la altura legal. Fuente: RIGL § 31-25-4; guía Legal OSOW de RIDOT."},"72":{"q":"En Rhode Island, un semirremolque de más de 48 pies 6 pulgadas solo puede circular ¿dónde?","options":["En cualquier lugar del estado sin restricción","Únicamente en carreteras de peaje","En el sistema de carreteras interestatales y otras carreteras designadas por el director de RIDOT","Únicamente entre el amanecer y el atardecer en cualquier vía"],"explanation":"La RIGL § 31-25-6 limita los semirremolques a cincuenta y tres pies (53') pero permite que aquellos de más de cuarenta y ocho pies y medio (48'6\") circulen únicamente en el sistema interestatal y en las carreteras/calles/caminos designados por el director de RIDOT. Fuente: RIGL § 31-25-6."},"73":{"q":"El peso bruto máximo de cualquier vehículo o combinación de vehículos en las carreteras de Rhode Island, sin un permiso, es de:","options":["73,280 libras","80,000 libras","88,000 libras","100,000 libras"],"explanation":"La RIGL § 31-25-14 limita el peso bruto total a ochenta mil libras (80,000 lbs), sujeto también a la fórmula federal de puentes (federal bridge formula). Fuente: RIGL § 31-25-14."},"74":{"q":"Según la ley de Rhode Island, el peso bruto máximo permitido sobre cualquier eje simple de un vehículo es de:","options":["22,400 libras","20,000 libras","34,000 libras","18,000 libras"],"explanation":"La RIGL § 31-25-14 limita el peso bruto sobre las ruedas de cualquier eje simple a veintidós mil cuatrocientas (22,400) libras; un eje tándem (con separación de hasta 8 pies) se limita a 36,000 libras. Fuente: RIGL § 31-25-14."},"75":{"q":"A partir de 2026, el programa de peaje de puentes RhodeWorks de Rhode Island está estructurado para cobrar peajes a cuáles vehículos?","options":["Únicamente camiones tractotráiler de Clase 8 (y mayores); los autos de pasajeros y las camionetas pickup están exentos","Todos los vehículos de más de 10,000 libras","Todo vehículo que cruce un puente con peaje","Únicamente camiones comerciales de fuera del estado"],"explanation":"El programa RhodeWorks de Rhode Island cobra peaje únicamente a los camiones comerciales grandes (tractotráileres de Clase 8 y mayores) en los pórticos de los puentes, eximiendo a los autos de pasajeros y a los vehículos comerciales más pequeños. El Primer Circuito confirmó la estructura aplicable solo a tractotráileres (anulando únicamente el tope diario). Fuente: RIDOT/RhodeWorks; decisión del Primer Circuito sobre RhodeWorks."},"76":{"q":"Cuando un vehículo comercial de Rhode Island se detiene sobre la parte transitada de una vía de dos carriles y doble sentido, ¿dónde debe colocar el conductor los tres triángulos de advertencia requeridos?","options":["Los tres a menos de 10 pies del parachoques trasero","Uno a 200 pies y dos a 100 pies, todos detrás del vehículo","Aproximadamente a 10 pies detrás del vehículo hacia el tránsito, aproximadamente a 100 pies detrás, y aproximadamente a 100 pies delante del vehículo","Solo un triángulo, colocado a 50 pies de la parte trasera"],"explanation":"Rhode Island sigue el estándar federal (49 CFR 392.22) que se enseña en el manual de CDL: en una vía de dos carriles y doble sentido, coloque un triángulo aproximadamente a 10 pies de la parte trasera hacia el tránsito, uno aproximadamente a 100 pies de la parte trasera, y uno aproximadamente a 100 pies del frente. (En una vía dividida o de un solo sentido, los dispositivos traseros se colocan a 10, 100 y 200 pies). Fuente: Manual de CDL de RI; 49 CFR 392.22."},"77":{"q":"¿Qué agencia emite las Licencias de Conducir Comerciales (CDL) en Rhode Island?","options":["La División de Vehículos Motorizados de Rhode Island (DMV)","El Departamento de Transporte de Rhode Island (RIDOT)","La Unidad de Cumplimiento Comercial de la Policía Estatal de Rhode Island","La Administración Federal de Seguridad de Autotransportes (FMCSA)"],"explanation":"Las CDL en Rhode Island son emitidas por la División de Vehículos Motorizados de RI (RI DMV). RIDOT se encarga de las carreteras y los permisos de sobredimensión/sobrepeso, y la FMCSA establece los estándares federales pero no emite licencias estatales. Fuente: RI DMV, páginas de Licencia de Conducir Comercial (CDL)."},"78":{"q":"¿Dónde se administran en persona los exámenes de habilidades (de manejo) para la CDL en Rhode Island?","options":["En el sitio de examen de CDL dedicado, ubicado en 400 Romano Vineyard Way, North Kingstown","En cualquier sucursal de AAA en todo el estado","Únicamente en la sede de la DMV en Cranston","En las estaciones de pesaje de RIDOT a lo largo de la I-95"],"explanation":"Los exámenes comerciales de habilidades de RI se realizan con cita previa en el sitio de examen de CDL, 400 Romano Vineyard Way, North Kingstown. La DMV de Cranston atiende los trámites de mostrador de CDL en persona y los exámenes de conocimientos, pero el examen de habilidades se realiza en el sitio de North Kingstown. Fuente: RI DMV, página del Examen Comercial de Habilidades."},"79":{"q":"¿Durante cuánto tiempo debe haber tenido un solicitante una licencia de conducir regular (Clase D) antes de solicitar una CDL de Rhode Island?","options":["Al menos 2 años","Al menos 6 meses","Al menos 1 año","Al menos 3 años"],"explanation":"Rhode Island exige que un solicitante de CDL haya sido conductor con licencia por un mínimo de dos (2) años al momento de la solicitud. Fuente: RI DMV, páginas de Licencia de Conducir Comercial (CDL) / Permiso de Aprendiz Comercial y Exámenes."},"80":{"q":"Según las reglas de Rhode Island, ¿cuál es la edad mínima para obtener una CDL para conducir intraestatal (únicamente dentro del estado)?","options":["18 años","16 años","21 años","25 años"],"explanation":"A los 18 años puede recibir una CDL de Rhode Island únicamente para viajes intraestatales (dentro del estado); debe tener 21 años para conducir interestatal (a través de las fronteras estatales). Fuente: RI DMV, página de Licencia de Conducir Comercial (CDL)."},"81":{"q":"¿Cuál es la edad mínima requerida en Rhode Island para conducir un vehículo comercial interestatal (a través de las fronteras estatales)?","options":["21 años","18 años","19 años","23 años"],"explanation":"Rhode Island, siguiendo el estándar federal, exige que un conductor tenga 21 años para la operación comercial interestatal; los conductores de 18 a 20 años están limitados a conducir intraestatal. Fuente: RI DMV, página de Licencia de Conducir Comercial (CDL)."},"82":{"q":"¿Qué formulario de solicitud debe completarse para solicitar una CDL de Rhode Island?","options":["La Solicitud de Licencia de Conducir Comercial (CDL-1)","El Formulario MCSA-5876","La Solicitud de Licencia Estándar (LI-1)","El Formulario DL-44C"],"explanation":"Los solicitantes de Rhode Island completan la Solicitud de Licencia de Conducir Comercial (CDL-1), que también incluye la declaración jurada del historial de conducir. Fuente: RI DMV, página de Permiso de Aprendiz Comercial y Exámenes (formulario CDL-1)."},"83":{"q":"En Rhode Island, ¿qué prueba de presencia legal debe presentar un solicitante de CDL?","options":["Prueba de ciudadanía estadounidense o residencia permanente legal","Un pasaporte válido de cualquier país","Únicamente una tarjeta de Seguro Social, sin ninguna otra prueba","Una declaración de residencia notariada de un empleador"],"explanation":"La RI DMV exige que todos los solicitantes de CDL presenten prueba de su condición de ciudadano estadounidense o residente permanente legal, junto con prueba de residencia en Rhode Island. Fuente: RI DMV, página de Licencia de Conducir Comercial (CDL)."},"84":{"q":"¿Cuál examen de conocimientos es el requisito mínimo para obtener un Permiso de Aprendiz Comercial (CLP) de Rhode Island?","options":["El examen de Conocimientos Generales","El examen de Frenos de Aire","El examen de Vehículos Combinados","El examen de Materiales Peligrosos"],"explanation":"El examen de Conocimientos Generales es el requisito mínimo para un CLP en Rhode Island; se requieren exámenes de conocimientos adicionales según la clase y los endosos que se busquen. Fuente: RI DMV, página de Permiso de Aprendiz Comercial y Exámenes."},"85":{"q":"En el examen de Conocimientos Generales de CDL de Rhode Island (50 preguntas), ¿qué puntaje se necesita para aprobar?","options":["80% (40 de 50 correctas)","70% (35 de 50 correctas)","75% (38 de 50 correctas)","90% (45 de 50 correctas)"],"explanation":"Rhode Island sigue el umbral estándar de aprobación de CDL del 80%; en el examen de Conocimientos Generales de 50 preguntas eso significa 40 respuestas correctas. Fuente: Manual de CDL de RI / estándares de exámenes de conocimientos de la RI DMV."},"86":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Rhode Island, y puede renovarse?","options":["Válido por un máximo de un año y no renovable","Válido por 180 días y renovable una vez","Válido por dos años y renovable","Válido por 60 días y no renovable"],"explanation":"Un CLP de Rhode Island es válido por un máximo de un año y no es renovable; si vence, el solicitante debe volver a presentar todos los exámenes de conocimientos y pagar nuevamente las tarifas. Fuente: RI DMV, página de Permiso de Aprendiz Comercial y Exámenes."},"87":{"q":"Después de obtener un CLP de Rhode Island, ¿durante cuánto tiempo debe conservarse antes de que el titular pueda presentar el examen de habilidades de la CDL?","options":["Al menos 14 días","Al menos 30 días","Al menos 7 días","Al menos 60 días"],"explanation":"De acuerdo con la regla federal que sigue, Rhode Island exige que el CLP se conserve durante al menos 14 días antes de presentar el examen de habilidades de la CDL. Fuente: RI DMV, página del Examen Comercial de Habilidades (estándar FMCSA 49 CFR 383)."},"88":{"q":"¿Cuáles son las tres partes del examen de habilidades de la CDL de Rhode Island?","options":["Inspección del Vehículo, Habilidades Básicas de Control y Examen de Manejo","Examen escrito, Examen de la vista y Examen de Manejo","Frenos de Aire, Reversa y Manejo en Carretera","Pre-viaje, Materiales Peligrosos y Manejo Nocturno"],"explanation":"El examen de habilidades de Rhode Island tiene tres partes: el Examen de Inspección del Vehículo (pre-viaje), el Examen de Habilidades Básicas de Control y el Examen de Manejo; el solicitante debe aprobar las tres. Fuente: RI DMV, página del Examen Comercial de Habilidades."},"89":{"q":"¿Quién debe proporcionar el vehículo utilizado para el examen de habilidades de la CDL de Rhode Island, y en qué condición debe estar?","options":["El solicitante proporciona su propio vehículo, que debe llegar vacío (sin carga)","La DMV proporciona un vehículo de examen propiedad del estado para todos los solicitantes","El empleador del solicitante debe proporcionar un vehículo de examen cargado","Cualquier camión de caja rentado, sin importar su clase de peso, es aceptable"],"explanation":"En Rhode Island el candidato debe proporcionar su propio vehículo representativo, y este debe llegar vacío (sin carga); los camiones cisterna deben estar certificados como vacíos, limpiados y purgados. Fuente: RI DMV, página del Examen Comercial de Habilidades."},"90":{"q":"Además del CLP y la licencia de operador, ¿qué documentos deben presentarse para el examen de habilidades de Rhode Island?","options":["Registro vehicular válido, comprobante de seguro activo y una calcomanía de inspección válida","Un diploma de preparatoria y comprobante de empleo","Únicamente un pasaporte y un acta de nacimiento","Una carta notariada de una escuela de capacitación de CDL"],"explanation":"Rhode Island exige copias impresas del CLP y de la licencia de operador, además del registro vehicular válido (y del remolque, si aplica), comprobante de seguro activo y una calcomanía de inspección vehicular activa. Fuente: RI DMV, página del Examen Comercial de Habilidades."},"91":{"q":"Según las reglas de Rhode Island, ¿cuándo debe completarse la Capacitación para Conductores Principiantes (ELDT) para un solicitante por primera vez de Clase A o Clase B?","options":["Antes de presentar el examen de habilidades de la CDL","Dentro de los 30 días posteriores a aprobar el examen de habilidades","Solo después de que la CDL ya haya sido emitida","Es opcional y puede omitirse con la aprobación del empleador"],"explanation":"La ELDT debe completarse satisfactoriamente con un proveedor registrado antes de que se permita a un solicitante por primera vez de Clase A/B presentar el examen de habilidades de la CDL. Fuente: RI DMV, página de ELDT (regla federal de ELDT, vigente a partir del 7 de febrero de 2022)."},"92":{"q":"¿Para cuál endoso exige Rhode Island que se complete la ELDT antes del examen de CONOCIMIENTOS (no del examen de habilidades)?","options":["El endoso de Materiales Peligrosos (H)","El endoso de Pasajeros (P)","El endoso de Autobús Escolar (S)","El endoso de Dobles/Triples (T)"],"explanation":"Para el endoso de Materiales Peligrosos (H), la ELDT debe completarse antes de presentar el examen de conocimientos; para los endosos P y S la ELDT se completa antes del examen de habilidades. Fuente: RI DMV, página de ELDT."},"93":{"q":"¿Dónde debe buscar un solicitante de Rhode Island para encontrar un proveedor de capacitación ELDT aprobado?","options":["El Registro de Proveedores de Capacitación (TPR) de la FMCSA","El portal de lista de espera de CLP de la RI DMV","El Registro Nacional de Examinadores Médicos Certificados","La lista de proveedores de la oficina de permisos de RIDOT"],"explanation":"Los proveedores de ELDT aprobados están listados en el Registro de Proveedores de Capacitación de la FMCSA (tpr.fmcsa.dot.gov); la finalización también puede verificarse allí. Fuente: RI DMV, página de ELDT."},"94":{"q":"¿Entre cuántas categorías de comercio de autocertificación debe elegir un solicitante de CDL de Rhode Island?","options":["Cuatro categorías","Dos categorías","Tres categorías","Seis categorías"],"explanation":"Un solicitante de Rhode Island debe autocertificarse en una de cuatro categorías: Interestatal No Exceptuado, Interestatal Exceptuado, Intraestatal No Exceptuado o Intraestatal Exceptuado. Fuente: RI DMV, página de Certificación Médica / Autocertificación."},"95":{"q":"Un conductor de Rhode Island que se certifica como 'Interestatal No Exceptuado' debe hacer ¿qué?","options":["Obtener y mantener un Certificado de Examinador Médico federal del DOT","Evitar transportar cualquier carga a través de las fronteras estatales","Renovar la CDL anualmente en lugar de cada cinco años","Omitir el examen de manejo debido a su condición interestatal"],"explanation":"Los conductores Interestatales No Exceptuados operan dentro y fuera de Rhode Island y deben obtener un Certificado de Examinador Médico federal del DOT; las categorías exceptuadas no lo requieren. Fuente: RI DMV, página de Certificación Médica / Autocertificación."},"96":{"q":"¿Cómo se transmite ahora a la DMV la certificación médica del DOT de un conductor de CDL no exceptuado de Rhode Island?","options":["El examinador médico certificado la envía electrónicamente al Registro Nacional de la FMCSA, que la reenvía a la RI DMV","El conductor envía por correo una copia en papel de la tarjeta médica directamente a la RI DMV","El empleador envía por fax el certificado a RIDOT para su archivo","El conductor la sube a través del portal de su cuenta de RI E-ZPass"],"explanation":"La RI DMV ya no acepta la certificación médica directamente; el examinador médico certificado envía electrónicamente el Certificado de Examinador Médico (Formulario MCSA-5876/5875) al Registro Nacional de la FMCSA, que lo reenvía a la DMV. No mantenerlo vigente resulta en una degradación de la CDL. Fuente: RI DMV, página de Certificación Médica; Registro Nacional de Examinadores Médicos Certificados."}},"hi":{"0":{"q":"रोड आइलैंड के राजमार्गों पर, बिना किसी विशेष परमिट के किसी वाणिज्यिक वाहन या उसके लोड की अधिकतम कानूनी चौड़ाई कितनी है?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"रोड आइलैंड जनरल लॉज़ § 31-25-3 किसी भी वाहन या उसके लोड की अधिकतम चौड़ाई 102 inches (8 feet 6 inches) निर्धारित करता है। इससे अधिक चौड़ी किसी भी चीज़ के लिए RIDOT ओवरसाइज़ परमिट आवश्यक है। स्रोत: R.I. Gen. Laws § 31-25-3."},"1":{"q":"रोड आइलैंड के राजमार्गों पर बिना परमिट के किसी वाहन की, उसके लोड सहित, अधिकतम कानूनी ऊँचाई कितनी है?","options":["162 inches (13 feet 6 inches)","156 inches (13 feet)","168 inches (14 feet)","150 inches (12 feet 6 inches)"],"explanation":"रोड आइलैंड जनरल लॉज़ § 31-25-4 वाहन की ऊँचाई को, लोड सहित, 162 inches (13 feet 6 inches) तक सीमित करता है। इससे अधिक ऊँचाई वाले लोड के लिए RIDOT ओवरहाइट परमिट आवश्यक है। स्रोत: R.I. Gen. Laws § 31-25-4."},"2":{"q":"रोड आइलैंड के राजमार्गों पर बिना ओवरवेट परमिट के किसी वाहन या वाहनों के संयोजन के लिए अधिकतम कुल सकल वजन, पाउंड में, कितना है?","options":["73,280 pounds","80,000 pounds","88,000 pounds","100,000 pounds"],"explanation":"रोड आइलैंड कुल सकल वजन को 80,000 pounds पर सीमित करता है, जो संघीय इंटरस्टेट मानक से मेल खाता है, जब तक कि कोई विशेष परमिट प्राप्त न किया गया हो। स्रोत: R.I. Gen. Laws § 31-25-14; RIDOT Manual for Overweight and Oversize Vehicle Permits."},"3":{"q":"रोड आइलैंड में, किसी एकल एक्सल के पहियों द्वारा राजमार्ग पर डाला गया सकल वजन कितने पाउंड से अधिक नहीं हो सकता?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"रोड आइलैंड जनरल लॉज़ § 31-25-13 एकल-एक्सल सीमा 22,400 pounds निर्धारित करता है। यह 20,000-pound संघीय इंटरस्टेट एकल-एक्सल मानक से अधिक है, जो रोड आइलैंड का राज्य-विशिष्ट आंकड़ा है। स्रोत: R.I. Gen. Laws § 31-25-13."},"4":{"q":"रोड आइलैंड में जब एक्सल की दूरी 8 feet से अधिक न हो, तो टैंडम एक्सल समूह पर अधिकतम कानूनी वजन कितना है?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"रोड आइलैंड जनरल लॉज़ § 31-25-14 टैंडम एक्सल समूह को 36,000 pounds तक सीमित करता है जब एक्सल की दूरी 8 feet से अधिक न हो। स्रोत: R.I. Gen. Laws § 31-25-14."},"5":{"q":"रोड आइलैंड कानून के तहत, वजन-सीमा के उद्देश्यों के लिए एकल \"एक्सल लोड\" को कैसे परिभाषित किया गया है?","options":["40 inches की दूरी पर स्थित दो समानांतर अनुप्रस्थ ऊर्ध्वाधर तलों के भीतर सभी पहियों पर कुल लोड","96 inches की दूरी पर स्थित दो तलों के भीतर सभी पहियों पर कुल लोड","वाहन के किसी एक टायर द्वारा वहन किया गया लोड","वाहन के पंजीकृत सकल वजन का आधा"],"explanation":"रोड आइलैंड जनरल लॉज़ § 31-25-13 एक्सल लोड को उन सभी पहियों द्वारा सड़क पर प्रेषित कुल लोड के रूप में परिभाषित करता है जिनके केंद्र 40 inches की दूरी पर स्थित दो समानांतर अनुप्रस्थ ऊर्ध्वाधर तलों के बीच होते हैं, जो वाहन की पूरी चौड़ाई तक फैले होते हैं। स्रोत: R.I. Gen. Laws § 31-25-13."},"6":{"q":"रोड आइलैंड के राजमार्गों पर किसी एकल वाहन (संयोजन नहीं) की, लोड और बंपर सहित, अधिकतम लंबाई कितनी है?","options":["35 feet","40 feet","48 feet","53 feet"],"explanation":"रोड आइलैंड जनरल लॉज़ § 31-25-5 किसी एकल वाहन को, किसी भी लोड सहित, कुल 40 feet तक सीमित करता है (मोटर बस, मोटराइज़्ड कैंपर, या कैंपिंग रिक्रिएशनल वाहन के लिए 45 feet)। स्रोत: R.I. Gen. Laws § 31-25-5."},"7":{"q":"रोड आइलैंड में किसी एकल मोटर बस, मोटराइज़्ड कैंपर, या कैंपिंग रिक्रिएशनल वाहन की अधिकतम लंबाई कितनी है?","options":["40 feet","42 feet","45 feet","48 feet"],"explanation":"रोड आइलैंड जनरल लॉज़ § 31-25-5 किसी मोटर बस, मोटराइज़्ड कैंपर, या कैंपिंग रिक्रिएशनल वाहन को 45 feet तक पहुँचने की अनुमति देता है, जबकि अन्य एकल वाहन 40 feet तक सीमित हैं। स्रोत: R.I. Gen. Laws § 31-25-5."},"8":{"q":"रोड आइलैंड में संचालित होने वाले किसी सेमीट्रेलर की, बंपर और सहायक उपकरणों को छोड़कर, अधिकतम लंबाई कितनी है?","options":["48 feet 6 inches","51 feet","53 feet","57 feet"],"explanation":"रोड आइलैंड जनरल लॉज़ § 31-25-6 सेमीट्रेलरों को, बंपर और सहायक उपकरणों को छोड़कर, 53 feet तक की अनुमति देता है। स्रोत: R.I. Gen. Laws § 31-25-6."},"9":{"q":"रोड आइलैंड में, कितनी लंबाई से अधिक के सेमीट्रेलर केवल इंटरस्टेट राजमार्ग प्रणाली पर और निदेशक द्वारा विशेष रूप से नामित राजमार्गों पर ही संचालित हो सकते हैं?","options":["45 feet","48 feet 6 inches","50 feet","53 feet"],"explanation":"रोड आइलैंड जनरल लॉज़ § 31-25-6, 48 feet 6 inches से अधिक के सेमीट्रेलरों को इंटरस्टेट राजमार्ग प्रणाली और निदेशक द्वारा नामित राजमार्गों, सड़कों और मार्गों तक सीमित करता है। स्रोत: R.I. Gen. Laws § 31-25-6."},"10":{"q":"रोड आइलैंड में ओवरसाइज़ और ओवरवेट वाहन परमिट कौन सी एजेंसी जारी करती है?","options":["रोड आइलैंड परिवहन विभाग (RIDOT)","रोड आइलैंड स्टेट पुलिस","संघीय राजमार्ग प्रशासन","स्थानीय शहर या टाउन क्लर्क जहाँ से यात्रा शुरू होती है"],"explanation":"कानूनी आकार या वजन सीमा से अधिक वाहनों के लिए विशेष परमिट राज्य परिवहन विभाग (RIDOT) द्वारा जारी किए जाते हैं। स्रोत: RIDOT Manual for Overweight and Oversize Vehicle Permits; R.I. Gen. Laws § 31-25-18."},"11":{"q":"रोड आइलैंड किसी भी लगातार एक्सल समूह पर अनुमेय सकल वजन निर्धारित करने के लिए कौन सा सूत्र उपयोग करता है?","options":["संघीय ब्रिज सूत्र: W = 500[(LN/(N-1)) + 12N + 36]","सकल वजन = प्रति inch टायर चौड़ाई 1,000 pounds","सकल वजन = प्रति एक्सल समूह 34,000 pounds, निश्चित","सकल वजन = 80,000 को एक्सल की संख्या से विभाजित"],"explanation":"रोड आइलैंड जनरल लॉज़ § 31-25-14 संघीय ब्रिज सूत्र, W = 500[(LN/(N-1)) + 12N + 36], लागू करता है, जहाँ W लगातार एक्सल के समूह पर सकल वजन है, L समूह के बाहरी एक्सल के बीच feet में दूरी है, और N एक्सल की संख्या है। स्रोत: R.I. Gen. Laws § 31-25-14."},"12":{"q":"रोड आइलैंड ब्रिज सूत्र W = 500[(LN/(N-1)) + 12N + 36] में, चर \"N\" किसका प्रतिनिधित्व करता है?","options":["विचाराधीन समूह में एक्सल की संख्या","केवल कार्गो का शुद्ध वजन","ड्राइव एक्सल पर टायरों की संख्या","वाहन की नाममात्र चौड़ाई feet में"],"explanation":"रोड आइलैंड द्वारा अपनाए गए ब्रिज सूत्र में, N समूह में एक्सल की संख्या है, L चरम एक्सल के बीच feet में दूरी है, और W उस समूह पर अधिकतम अनुमेय सकल वजन है। स्रोत: R.I. Gen. Laws § 31-25-14."},"13":{"q":"रोड आइलैंड के वजन नियमों के तहत, यदि ब्रिज सूत्र 36,000 pounds से कम की टैंडम-एक्सल सीमा देता है, तो कानूनी सीमा के रूप में कौन सा मान उपयोग किया जाता है?","options":["कम सूत्र परिणाम का उपयोग किया जाना चाहिए","34,000 pounds का उपयोग किया जाता है","36,000 pounds को कानूनी सीमा माना जाता है","लोडिंग से पहले एक्सल समूह को पुनः-दूरी पर रखना होगा"],"explanation":"रोड आइलैंड जनरल लॉज़ § 31-25-14 प्रावधान करता है कि जब ब्रिज सूत्र 36,000 pounds से कम का टैंडम-एक्सल आंकड़ा देता है, तो 36,000 pounds को कानूनी सीमा माना जाता है। स्रोत: R.I. Gen. Laws § 31-25-14."},"14":{"q":"एक वाहक को रोड आइलैंड राजमार्ग पर 11 feet चौड़ा अविभाज्य लोड ले जाना है। वाहक को क्या करना चाहिए?","options":["कुछ नहीं; 11 feet कानूनी चौड़ाई के भीतर है","ले जाने से पहले RIDOT से ओवरसाइज़ परमिट प्राप्त करें","केवल स्थानीय पुलिस विभाग को सूचित करें","पहले लोड को 96 inches तक कम करें"],"explanation":"क्योंकि 11 feet (132 inches) § 31-25-3 के तहत 102-inch कानूनी चौड़ाई से अधिक है, वाहक को लोड ले जाने से पहले RIDOT से ओवरसाइज़ परमिट प्राप्त करना होगा। स्रोत: R.I. Gen. Laws § 31-25-3 और § 31-25-18; RIDOT Permit Manual."},"15":{"q":"रोड आइलैंड में किसी अविभाज्य ओवरसाइज़ या ओवरवेट वाहन या लोड को ले जाने के लिए मानक RIDOT एकल-यात्रा शुल्क कितना है?","options":["$10.00 per trip","$20.00 per trip","$50.00 per trip","$100.00 per trip"],"explanation":"RIDOT Manual for Overweight and Oversize Vehicle Permits अविभाज्य वाहनों या लोड की आवाजाही के लिए $20.00 ट्रिप शुल्क लेता है। स्रोत: RIDOT Manual for Overweight and Oversize Vehicle Permits, Sec. 4.4."},"16":{"q":"प्रति-यात्रा शुल्क का भुगतान करने के बजाय, रोड आइलैंड में बार-बार इंट्रास्टेट ओवरसाइज़/ओवरवेट आवाजाही करने वाला वाहक किस शुल्क पर ब्लैंकेट परमिट प्राप्त कर सकता है?","options":["$50.00","$100.00","$250.00","$500.00"],"explanation":"RIDOT परमिट मैनुअल प्रति-यात्रा शुल्क का भुगतान करने के बजाय इंट्रास्टेट आवाजाही के लिए $100.00 में ब्लैंकेट परमिट प्राप्त करने की अनुमति देता है। स्रोत: RIDOT Manual for Overweight and Oversize Vehicle Permits, Sec. 4.4."},"17":{"q":"रोड आइलैंड परमिट मैनुअल के अनुसार, 14 feet 6 inches से अधिक कुल चौड़ाई वाले लोड के लिए कितने एस्कॉर्ट (पायलट) वाहन आवश्यक हैं?","options":["कोई एस्कॉर्ट आवश्यक नहीं है","एक एस्कॉर्ट वाहन","दो एस्कॉर्ट वाहन","चार एस्कॉर्ट वाहन"],"explanation":"RIDOT परमिट मैनुअल 12 feet 0 inches और 14 feet 6 inches के बीच की चौड़ाई के लिए एक एस्कॉर्ट, और 14 feet 6 inches से अधिक चौड़ाई के लिए दो एस्कॉर्ट वाहन आवश्यक करता है। स्रोत: RIDOT Manual for Overweight and Oversize Vehicle Permits, Sec. 5.4."},"18":{"q":"रोड आइलैंड परमिट मैनुअल के अनुसार, परमिट प्राप्त ओवरसाइज़/ओवरवेट आवाजाही आम तौर पर कब अधिकृत नहीं होती?","options":["शुक्रवार सूर्यास्त से सोमवार सूर्योदय तक और सूचीबद्ध छुट्टियों पर","केवल प्रतिदिन मध्यरात्रि और 4:00 a.m. के बीच","केवल प्रत्येक माह के पहले सप्ताह के दौरान","कभी नहीं; परमिट प्राप्त आवाजाही किसी भी समय चल सकती है"],"explanation":"RIDOT परमिट मैनुअल, जब तक अन्यथा नोट न किया गया हो, शुक्रवार सूर्यास्त से सोमवार सूर्योदय तक और सूचीबद्ध कानूनी छुट्टियों पर आवाजाही को प्रतिबंधित करता है। स्रोत: RIDOT Manual for Overweight and Oversize Vehicle Permits, Sec. 4.15 / 5.7."},"19":{"q":"रोड आइलैंड कानून अध्याय 31-25 की आकार और वजन सीमाओं के संबंध में फार्म वाहनों, फार्म ट्रैक्टरों, रोड मशीनरी, और अग्निशमन उपकरणों के साथ कैसा व्यवहार करता है?","options":["वे आकार और वजन सीमाओं से छूट प्राप्त हैं","वे सामान्य वजन सीमा के 50% तक सीमित हैं","उन्हें हर समय वार्षिक ओवरसाइज़ परमिट रखना होगा","उन्हें सभी क्रमांकित राज्य राजमार्गों से प्रतिबंधित किया गया है"],"explanation":"रोड आइलैंड जनरल लॉज़ § 31-25-2 अस्थायी रूप से राजमार्ग पर ले जाए गए अग्निशमन उपकरण, रोड मशीनरी, और फार्म वाहनों (फार्म ट्रैक्टरों सहित) को अध्याय 31-25 की आकार और वजन सीमाओं से छूट देता है। स्रोत: R.I. Gen. Laws § 31-25-2."},"20":{"q":"रोड आइलैंड में, केवल INTRASTATE (राज्य के भीतर) संचालन के लिए वैध CDL प्राप्त करने हेतु न्यूनतम आयु क्या है?","options":["16 years old","18 years old","21 years old","25 years old"],"explanation":"RI CDL Manual (Guidelines for CDL Applicants) बताता है कि केवल INTRASTATE CDL के लिए आपके पास कम से कम दो वर्षों से वैध ऑपरेटर लाइसेंस होना चाहिए और आपकी आयु कम से कम 18 वर्ष होनी चाहिए; इंटरस्टेट के लिए 21 वर्ष आवश्यक है। स्रोत: RI DMV Commercial Driver License Manual (AAMVA 2005, Rev. July 2014)."},"21":{"q":"रोड आइलैंड में INTERSTATE वाणिज्य (राज्य की सीमाओं को पार करना) में वाणिज्यिक मोटर वाहन संचालित करने के लिए न्यूनतम आयु क्या आवश्यक है?","options":["18 years old","19 years old","21 years old","23 years old"],"explanation":"RI DMV के लिए इंटरस्टेट (राज्य की सीमाओं को पार करना) CDL संचालन के लिए पात्र होने हेतु चालक की आयु 21 वर्ष होनी आवश्यक है; 18 वर्ष केवल इंट्रास्टेट के लिए योग्य है। स्रोत: RI DMV CDL page और RI Commercial Driver License Manual (Rev. July 2014)."},"22":{"q":"रोड आइलैंड के CDL वर्गीकरण के तहत, कौन सा वर्ग 26,001 lbs या उससे अधिक GCWR वाले वाहनों के किसी भी COMBINATION को संचालित करने के लिए अधिकृत करता है, बशर्ते खींची जा रही इकाई(यों) का GVWR 10,000 lbs से अधिक हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"RI CDL Manual के अनुसार, Class A CDL 26,001 या उससे अधिक pounds GCWR वाले वाहनों के किसी भी संयोजन के संचालन को अधिकृत करता है, बशर्ते खींचे जा रहे वाहन(नों) का GVWR 10,000 pounds से अधिक हो। स्रोत: RI Commercial Driver License Manual, License Classes."},"23":{"q":"रोड आइलैंड में, 26,001 lbs या उससे अधिक GVWR वाले किसी SINGLE वाहन को (या ऐसा वाहन जो 10,000 lbs GVWR से अधिक न खींचने वाली इकाई को खींच रहा हो) अधिकृत करने वाला CDL किस वर्ग का है?","options":["Class A","Class B","Class C","Class E"],"explanation":"RI CDL Manual, Class B को 26,001 या उससे अधिक pounds GVWR वाले किसी भी एकल वाहन के रूप में परिभाषित करता है, या ऐसा वाहन जो 10,000 pounds GVWR से अधिक न खींचने वाले वाहन को खींच रहा हो। स्रोत: RI Commercial Driver License Manual, License Classes."},"24":{"q":"कौन सा रोड आइलैंड CDL वर्ग ऐसे वाहन को कवर करता है (जो Class A या B को पूरा नहीं करता) जिसे चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किया गया हो, या जिस पर खतरनाक सामग्री के लिए प्लेकार्ड लगाया गया हो?","options":["Class A","Class B","Class C","Class M"],"explanation":"RI CDL Manual, Class C को ऐसे किसी भी वाहन के रूप में परिभाषित करता है जो Class A या B को पूरा नहीं करता लेकिन जिसे चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किया गया हो, या जिस पर खतरनाक सामग्री के लिए प्लेकार्ड लगाया गया हो। स्रोत: RI Commercial Driver License Manual, License Classes."},"25":{"q":"रोड आइलैंड CDL पर, संघीय DOT विनियमों के तहत प्लेकार्ड लगाने की आवश्यकता वाली मात्रा में खतरनाक सामग्री ले जाने के लिए कौन सा एंडोर्समेंट कोड आवश्यक है?","options":["Code N","Code H","Code T","Code P"],"explanation":"RI CDL Manual के अनुसार, संघीय DOT विनियमों द्वारा प्लेकार्ड लगाने की आवश्यकता वाली किसी भी मात्रा में खतरनाक सामग्री ले जाते समय किसी भी लाइसेंस वर्ग पर H (HazMat) एंडोर्समेंट आवश्यक है। स्रोत: RI Commercial Driver License Manual, Endorsements."},"26":{"q":"तरल या गैसीय सामग्री ढोने वाले टैंक वाहन, या 1,000 गैलन या उससे अधिक रेटेड पोर्टेबल टैंक को संचालित करने के लिए रोड आइलैंड को कौन सा एंडोर्समेंट आवश्यक है?","options":["N - Tank Vehicles","T - Double/Triple Trailers","P - Passenger","S - School Bus"],"explanation":"RI CDL Manual बताता है कि टैंक वाहन में तरल या गैसीय सामग्री, या 1,000 गैलन या उससे अधिक रेटेड किसी पोर्टेबल टैंक को ले जाते समय किसी भी लाइसेंस वर्ग पर N (Tank Vehicles) एंडोर्समेंट आवश्यक है। स्रोत: RI Commercial Driver License Manual, Endorsements."},"27":{"q":"रोड आइलैंड में, T (Double/Triple Trailers) एंडोर्समेंट केवल किस CDL वर्ग को धारण करने वाले ऑपरेटरों द्वारा प्राप्त किया जा सकता है?","options":["Class C ऑपरेटर","Class B ऑपरेटर","Class A ऑपरेटर","किसी भी वर्ग का ऑपरेटर"],"explanation":"RI CDL Manual बताता है कि T (Double/Triple Trailers) एंडोर्समेंट उन Class A ऑपरेटरों के लिए आवश्यक है जो डबल/ट्रिपल ट्रेलर ढोते हैं जहाँ कानून द्वारा संचालन की अनुमति है। स्रोत: RI Commercial Driver License Manual, Endorsements."},"28":{"q":"परीक्षण से पहले, स्कूल बस (S) एंडोर्समेंट के लिए रोड आइलैंड लिखित परीक्षा और स्किल्स टेस्ट के अलावा कौन सा अतिरिक्त चरण आवश्यक करता है?","options":["एक TSA सुरक्षा खतरा आकलन","DMV School Bus Safety Office के माध्यम से एक RI School Bus Certificate","एक हरा शॉफर लाइसेंस आवेदन","एक डबल्स/ट्रिपल्स ज्ञान परीक्षा"],"explanation":"RI CDL Manual बताता है कि S (School Bus) एंडोर्समेंट ऑपरेटरों को पहले DMV School Bus Safety Office के माध्यम से एक RI School Bus Certificate प्राप्त करना होगा। स्रोत: RI Commercial Driver License Manual, Endorsements."},"29":{"q":"रोड आइलैंड CDL Manual के अनुसार, P (Passenger) एंडोर्समेंट तब आवश्यक होता है जब वाहन को ऑपरेटर सहित कितने से अधिक लोगों के बैठने के लिए डिज़ाइन किया गया हो?","options":["8","12","15","16"],"explanation":"RI CDL Manual बताता है कि जब वाहन को ऑपरेटर सहित 16 से अधिक यात्रियों के बैठने के लिए डिज़ाइन किया गया हो तो किसी भी लाइसेंस वर्ग पर P एंडोर्समेंट आवश्यक है; एक हरा शॉफर लाइसेंस आवेदन भी पूरा किया जाना चाहिए। स्रोत: RI Commercial Driver License Manual, Endorsements."},"30":{"q":"कौन सा रोड आइलैंड CDL एंडोर्समेंट HazMat और Tank Vehicle एंडोर्समेंट को जोड़ता है, जिसके लिए दोनों ज्ञान परीक्षाओं को पास करना आवश्यक है?","options":["Code S","Code T","Code X","Code P"],"explanation":"RI CDL Manual एंडोर्समेंट X को H (HazMat) और N (Tank) के संयोजन के रूप में वर्णित करता है; दोनों परीक्षाएँ देनी होंगी। स्रोत: RI Commercial Driver License Manual, Endorsements."},"31":{"q":"रोड आइलैंड में लागू संघीय नियमों के तहत, CDL स्किल्स टेस्ट देने से पहले Commercial Learner's Permit को कितने समय तक धारण करना आवश्यक है?","options":["7 days","14 days","30 days","60 days"],"explanation":"संघीय विनियमन 49 CFR 383.25, जिसे RI DMV द्वारा लागू किया गया है, CLP प्रारंभ में जारी होने के बाद पहले 14 days में CLP धारक को CDL स्किल्स टेस्ट देने से प्रतिबंधित करता है। स्रोत: 49 CFR 383.25; RI DMV CLP requirements."},"32":{"q":"मांगे गए वर्ग या एंडोर्समेंट की परवाह किए बिना, हर रोड आइलैंड CDL आवेदक को कौन सी ज्ञान परीक्षा पास करनी होगी?","options":["Air Brakes test","Combination Vehicles test","General Knowledge test","Passenger Transport test"],"explanation":"RI CDL Manual बताता है कि General Knowledge test सभी आवेदकों द्वारा ली जाती है; अन्य परीक्षाएँ वर्ग और एंडोर्समेंट पर निर्भर करती हैं। स्रोत: RI Commercial Driver License Manual, Section 1, Knowledge Tests."},"33":{"q":"रोड आइलैंड General Knowledge CDL परीक्षा में, पास होने के लिए 50 प्रश्नों में से कितने सही उत्तर देने होंगे (80%)?","options":["30","40","44","45"],"explanation":"RI CDL Manual का इलेक्ट्रॉनिक/मैनुअल परीक्षा शेड्यूल General Knowledge test को 50 प्रश्नों के रूप में सूचीबद्ध करता है, जिसमें पास होने के लिए 40 सही (80%) आवश्यक हैं। स्रोत: RI Commercial Driver License Manual, Electronic/Manual Tests."},"34":{"q":"रोड आइलैंड आवेदकों के लिए CDL रोड (स्किल्स) टेस्ट कौन सी एजेंसी आयोजित और शेड्यूल करती है?","options":["Cranston में RI DMV मुख्य कार्यालय","Community College of Rhode Island (CCRI)","RI स्टेट पुलिस","Rhode Island DOT परमिट कार्यालय"],"explanation":"RI CDL Manual बताता है कि रोड टेस्ट Community College of Rhode Island (CCRI) द्वारा दिए जाते हैं और इनके साथ शेड्यूल किए जाने चाहिए। स्रोत: RI Commercial Driver License Manual, Road Tests."},"35":{"q":"RI DMV के CLP दिशानिर्देशों के अनुसार, रोड आइलैंड CDL आवेदक के लिए निम्नलिखित में से कौन सा एक आवश्यक दस्तावेज़ है?","options":["एक वैध Social Security card","एक नोटरीकृत नियोक्ता पत्र","एक वाणिज्यिक वाहन शीर्षक","एक मोटरसाइकिल एंडोर्समेंट"],"explanation":"RI CDL Manual सभी आवेदकों को एक वैध Social Security card, एक वैध Medical Card (यदि गैर-अपवादित), और पहचान/निवास का प्रमाण प्रस्तुत करना आवश्यक करता है। स्रोत: RI Commercial Driver License Manual, Guidelines for CDL Applicants."},"36":{"q":"रोड आइलैंड में लागू किया गया संघीय Entry-Level Driver Training (ELDT), किस रजिस्ट्री पर सूचीबद्ध प्रदाता के माध्यम से पूरा किया जाना चाहिए?","options":["राज्य DMV प्रशिक्षण डेटाबेस","FMCSA Training Provider Registry (TPR)","AAMVA ड्राइवर शिक्षा सूची","TSA अनुमोदित स्कूलों की सूची"],"explanation":"Feb 7, 2022 से, पहली बार के Class A/B आवेदकों, B-to-A अपग्रेड, और नए P/S/H एंडोर्समेंट चाहने वालों को स्किल्स टेस्ट से पहले (H के लिए ज्ञान परीक्षा) FMCSA Training Provider Registry पर एक प्रदाता के साथ ELDT पूरा करना होगा। स्रोत: FMCSA ELDT rule; FMCSA Training Provider Registry."},"37":{"q":"रोड आइलैंड DMV को चिकित्सा स्थिति की स्व-प्रमाणित करते समय, निम्नलिखित में से कौन सी एक उन चार वैध श्रेणियों में से है जिनमें से CDL धारक को चुनना होगा?","options":["Interstate Commerce Non-excepted","Recreational Commerce Exempt","Foreign Commerce Certified","Agricultural Commerce Waived"],"explanation":"RI CDL Manual चार स्व-प्रमाणन श्रेणियाँ सूचीबद्ध करता है: Interstate Excepted, Interstate Non-excepted, Intrastate Excepted, और Intrastate Non-excepted। गैर-अपवादित चालकों को एक वैध मेडिकल कार्ड (49 CFR 391.45) प्रस्तुत करना होगा। स्रोत: RI Commercial Driver License Manual, Self-Certification."},"38":{"q":"रोड आइलैंड CDL Manual के अनुसार, नया Medical Card जारी होने के बाद CDL धारक को इसे DMV को कितने दिनों के भीतर प्रस्तुत करना होगा?","options":["10 days","15 days","30 days","45 days"],"explanation":"RI CDL Manual बताता है कि आपको अपना नया Medical Card जारी होने के 15 days के भीतर DMV को प्रस्तुत करना होगा; अनुपालन में विफलता के परिणामस्वरूप आपके लाइसेंस का डाउनग्रेड हो सकता है। स्रोत: RI Commercial Driver License Manual, Medical Certification."},"39":{"q":"रोड आइलैंड में वाणिज्यिक मोटर वाहन संचालित करते समय, रक्त अल्कोहल सांद्रता (BAC) कितनी या उससे अधिक होने पर चालक को CMV उद्देश्यों के लिए कानूनी रूप से नशे में माना जाता है?","options":["0.04%","0.08%","0.02%","0.10%"],"explanation":"रोड आइलैंड में, 0.04% या उससे अधिक BAC के साथ CMV संचालित करना एक प्रमुख अपराध है, जो गैर-वाणिज्यिक चालकों पर लागू होने वाली 0.08% सीमा का आधा है। स्रोत: R.I. Gen. Laws 31-10.3-31; RI CDL Manual, Section 2."},"40":{"q":"रोड आइलैंड के निहित सहमति कानून के तहत, एक CDL धारक जो कानूनी रूप से अनुरोध किए जाने पर साँस, रक्त, या मूत्र के रासायनिक परीक्षण से इनकार करता है, उसे क्या किया हुआ माना जाता है?","options":["एक प्रमुख अपराध, DUI दोषसिद्धि की तरह","केवल एक गंभीर यातायात उल्लंघन","एक आउट-ऑफ-सर्विस आदेश उल्लंघन","एक गैर-रिपोर्ट योग्य प्रशासनिक मामला"],"explanation":"रोड आइलैंड में, आवश्यक रासायनिक परीक्षण से इनकार करना एक प्रमुख अपराध है जो DUI दोषसिद्धि के समान ही अयोग्यता वहन करता है। स्रोत: R.I. Gen. Laws 31-10.3-31; RI CDL Manual, Section 2."},"41":{"q":"रोड आइलैंड में, जब प्लेकार्ड लगी खतरनाक सामग्री नहीं ले जाई जा रही हो, तो CDL धारक के पहले प्रमुख अपराध (जैसे CMV में DUI) के लिए न्यूनतम अयोग्यता अवधि क्या है?","options":["1 year","60 days","3 years","6 months"],"explanation":"रोड आइलैंड पहले प्रमुख अपराध (DUI, 0.04+ BAC, इनकार, घटनास्थल छोड़ना, या किसी अपराध में CMV का उपयोग) के लिए चालक को कम से कम 1 year के लिए अयोग्य ठहराता है। स्रोत: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"42":{"q":"रोड आइलैंड में, यदि कोई चालक प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री ले जाते समय पहला प्रमुख अपराध करता है, तो न्यूनतम अयोग्यता अवधि बढ़कर हो जाती है:","options":["3 years","1 year","120 days","5 years"],"explanation":"प्लेकार्ड लगे हैज़मैट वाहन का संचालन करते समय पहला प्रमुख अपराध रोड आइलैंड में मानक 1 year के बजाय न्यूनतम 3-year अयोग्यता का परिणाम होता है। स्रोत: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"43":{"q":"रोड आइलैंड में, एक CDL धारक जो अपने जीवनकाल के दौरान दूसरे प्रमुख अपराध का दोषी ठहराया जाता है, उसे किस अयोग्यता का सामना करना पड़ता है?","options":["आजीवन अयोग्यता","10-year अयोग्यता","3-year अयोग्यता","1-year अयोग्यता"],"explanation":"जीवनकाल में दूसरे प्रमुख अपराध का परिणाम रोड आइलैंड में आजीवन अयोग्यता है (जो कुछ शर्तों के तहत, न्यूनतम 10 years तक कम की जा सकती है)। स्रोत: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"44":{"q":"3-year की अवधि के भीतर कितने गंभीर यातायात उल्लंघन (अलग-अलग घटनाओं से उत्पन्न) रोड आइलैंड में 60-day की CDL अयोग्यता को ट्रिगर करते हैं?","options":["2","3","4","1"],"explanation":"3 years के भीतर CMV में दो गंभीर यातायात उल्लंघन रोड आइलैंड में 60-day की अयोग्यता का कारण बनते हैं। स्रोत: R.I. Gen. Laws 31-10.3-31; RI CDL Manual, Section 2."},"45":{"q":"रोड आइलैंड में, 3-year की अवधि के भीतर तीन गंभीर यातायात उल्लंघनों का परिणाम कितने समय की CDL अयोग्यता होती है?","options":["120 days","60 days","90 days","1 year"],"explanation":"3 years के भीतर CMV में तीन गंभीर यातायात उल्लंघन रोड आइलैंड में 120-day की अयोग्यता का कारण बनते हैं। स्रोत: R.I. Gen. Laws 31-10.3-31; RI CDL Manual, Section 2."},"46":{"q":"निम्नलिखित में से किसे रोड आइलैंड CDL धारक के लिए एक SERIOUS यातायात उल्लंघन के रूप में वर्गीकृत किया गया है?","options":["आगे वाले वाहन के बहुत करीब चलना","0.04% BAC के साथ CMV संचालित करना","रासायनिक परीक्षण से इनकार करना","आउट-ऑफ-सर्विस आदेश का उल्लंघन करना"],"explanation":"बहुत करीब चलना सूचीबद्ध गंभीर यातायात उल्लंघनों में से एक है; अन्य विकल्प अलग दंड वाले प्रमुख अपराध या आउट-ऑफ-सर्विस उल्लंघन हैं। स्रोत: RI CDL Manual, Section 2; 49 CFR 383.51."},"47":{"q":"रोड आइलैंड में गंभीर यातायात उल्लंघन के लिए, अत्यधिक तेज़ गति को निर्धारित गति सीमा से कितने मील प्रति घंटे या उससे अधिक की गति से चलने के रूप में परिभाषित किया गया है?","options":["15 mph or more","10 mph or more","20 mph or more","25 mph or more"],"explanation":"निर्धारित सीमा से 15 mph या उससे अधिक की गति रोड आइलैंड में CDL उद्देश्यों के लिए एक गंभीर यातायात उल्लंघन है। स्रोत: RI CDL Manual, Section 2; 49 CFR 383.51."},"48":{"q":"रोड आइलैंड में अपनाए गए संघीय नियमों के तहत, CMV चलाते समय हैंड-हेल्ड मोबाइल फ़ोन का उपयोग करना या टेक्स्टिंग करना अयोग्यता उद्देश्यों के लिए किस प्रकार के उल्लंघन के रूप में गिना जाता है?","options":["एक गंभीर यातायात उल्लंघन","एक प्रमुख अपराध","एक आउट-ऑफ-सर्विस आदेश उल्लंघन","एक रेलरोड-क्रॉसिंग उल्लंघन"],"explanation":"CMV चलाते समय टेक्स्टिंग करना या हैंड-हेल्ड फ़ोन का उपयोग करना रोड आइलैंड में एक गंभीर यातायात उल्लंघन है, जो 60-day/120-day अयोग्यताओं की ओर गिना जाता है। स्रोत: 49 CFR 383.51, 392.80-392.82; RI CDL Manual."},"49":{"q":"3-year की अवधि के भीतर कितने टेक्स्टिंग/हैंड-हेल्ड फ़ोन उल्लंघन रोड आइलैंड में 120-day की CDL अयोग्यता का परिणाम होते हैं?","options":["3 or more","2","5","4"],"explanation":"क्योंकि टेक्स्टिंग/हैंड-हेल्ड उपयोग गंभीर यातायात उल्लंघन हैं, 3 years के भीतर तीन या अधिक 120-day की अयोग्यता का कारण बनते हैं (दो 60 days का कारण बनते हैं)। स्रोत: 49 CFR 383.51, 392.82; RI CDL Manual."},"50":{"q":"रोड आइलैंड में, 10-year की अवधि के भीतर तीसरा या उसके बाद का आउट-ऑफ-सर्विस आदेश उल्लंघन (मानक संचालन) किस अयोग्यता का परिणाम होता है?","options":["3 years","1 year","5 years","आजीवन"],"explanation":"10 years के भीतर तीसरा या उसके बाद का OOS आदेश उल्लंघन रोड आइलैंड में 3-year की अयोग्यता वहन करता है। स्रोत: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"51":{"q":"यदि कोई रोड आइलैंड CDL धारक प्लेकार्ड लगी खतरनाक सामग्री ले जाते समय या 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किए गए वाहन का संचालन करते समय आउट-ऑफ-सर्विस आदेश का उल्लंघन करता है, तो पहली-उल्लंघन अयोग्यता कम से कम होती है:","options":["180 days","90 days","1 year","60 days"],"explanation":"हैज़मैट ढोते समय या 16+ यात्रियों को ले जाते समय पहला OOS उल्लंघन रोड आइलैंड में न्यूनतम अयोग्यता को बढ़ाकर 180 days कर देता है। स्रोत: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"52":{"q":"रोड आइलैंड में, CDL धारक के पहले रेलरोड-ग्रेड-क्रॉसिंग उल्लंघन के लिए न्यूनतम अयोग्यता क्या है?","options":["60 days","30 days","90 days","120 days"],"explanation":"पहला रेलरोड-ग्रेड-क्रॉसिंग उल्लंघन रोड आइलैंड में न्यूनतम 60-day की अयोग्यता का परिणाम होता है। स्रोत: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"53":{"q":"रोड आइलैंड में, 3-year की अवधि के भीतर दूसरा रेलरोड-ग्रेड-क्रॉसिंग उल्लंघन किस न्यूनतम अयोग्यता का परिणाम होता है:","options":["120 days","60 days","1 year","90 days"],"explanation":"3 years के भीतर दूसरा रेलरोड-क्रॉसिंग उल्लंघन रोड आइलैंड में न्यूनतम 120-day की अयोग्यता वहन करता है। स्रोत: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"54":{"q":"रोड आइलैंड में, 3-year की अवधि के भीतर तीसरा या उसके बाद का रेलरोड-ग्रेड-क्रॉसिंग उल्लंघन किस न्यूनतम अयोग्यता का परिणाम होता है:","options":["1 year","120 days","60 days","3 years"],"explanation":"3 years के भीतर तीसरा या उसके बाद का रेलरोड-क्रॉसिंग उल्लंघन रोड आइलैंड में न्यूनतम 1-year की अयोग्यता वहन करता है। स्रोत: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"55":{"q":"एक रोड आइलैंड CDL धारक को अपने स्वयं के व्यक्तिगत (गैर-वाणिज्यिक) वाहन को चलाते समय DUI का दोषी ठहराया जाता है। उनके CDL का क्या होता है?","options":["उन्हें कम से कम 1 year के लिए CMV चलाने से अयोग्य ठहराया जाता है","कुछ नहीं, क्योंकि यह वाणिज्यिक वाहन नहीं था","उन्हें केवल 60-day की अयोग्यता मिलती है","उन्हें केवल गंभीर-उल्लंघन दंड का सामना करना पड़ता है"],"explanation":"रोड आइलैंड में किसी भी वाहन में, जिसमें व्यक्तिगत कार भी शामिल है, DUI दोषसिद्धि एक CDL धारक को एक प्रमुख अपराध के रूप में कम से कम 1 year के लिए CMV संचालित करने से अयोग्य ठहराती है। स्रोत: R.I. Gen. Laws 31-10.3-31; 49 CFR 383.51."},"56":{"q":"निम्नलिखित में से कौन सा रोड आइलैंड CDL धारक के लिए एक गंभीर यातायात उल्लंघन के बजाय एक MAJOR अपराध (1-year अयोग्यता) है?","options":["किसी अपराध के कमीशन में CMV का उपयोग करना","बहुत करीब चलना","अनुचित या अनियमित लेन परिवर्तन","उचित वर्ग या एंडोर्समेंट के बिना CMV चलाना"],"explanation":"किसी अपराध को करने के लिए CMV का उपयोग करना एक प्रमुख अपराध है जो 1-year की अयोग्यता वहन करता है; अन्य विकल्प गंभीर यातायात उल्लंघन हैं। स्रोत: R.I. Gen. Laws 31-10.3-31; RI CDL Manual, Section 2; 49 CFR 383.51."},"57":{"q":"रोड आइलैंड में, बच्चों को ले जा रही स्कूल बस, किराए पर यात्रियों को ले जा रही बस, या विस्फोटक या ज्वलनशील तरल पदार्थ ढो रहे वाहन को रेलरोड पटरियों को पार करने से पहले निकटतम रेल से कितनी दूरी पर रुकना चाहिए?","options":["100 फीट के भीतर लेकिन 50 फीट से कम नहीं","50 फीट के भीतर लेकिन 15 फीट से कम नहीं","25 फीट के भीतर लेकिन 10 फीट से कम नहीं","75 फीट के भीतर लेकिन 25 फीट से कम नहीं"],"explanation":"RI General Laws § 31-20-4 के अनुसार किराए पर यात्रियों को ले जा रहे किसी भी मोटर वाहन के चालक, किसी स्कूली बच्चे को ले जा रही किसी स्कूल बस, या विस्फोटक पदार्थ या ज्वलनशील तरल पदार्थ ले जा रहे किसी भी वाहन को निकटतम रेल से पचास फीट (50') के भीतर लेकिन पंद्रह फीट (15') से कम नहीं रुकना आवश्यक है। स्रोत: RIGL § 31-20-4."},"58":{"q":"रोड आइलैंड कानून के अंतर्गत, किराए की बसों, स्कूल बसों, और विस्फोटक/ज्वलनशील-तरल ढोने वाले वाहनों के लिए आवश्यक रेलरोड-क्रॉसिंग पर रुकना किस स्थिति में लागू नहीं होता?","options":["जब भी वाहन माल या यात्रियों से खाली हो","जब भी चालक के पास खतरनाक सामग्री समर्थन (एंडोर्समेंट) हो","स्वचालित गेटों से सुसज्जित किसी भी क्रॉसिंग पर","ऐसे क्रॉसिंग पर जहाँ कोई अधिकारी या यातायात-नियंत्रण संकेत यातायात को आगे बढ़ने का निर्देश देता है, या किसी व्यापारिक या आवासीय क्षेत्र के भीतर के क्रॉसिंग पर"],"explanation":"RIGL § 31-20-4 कहता है कि जहाँ कोई पुलिस अधिकारी या यातायात-नियंत्रण संकेत यातायात को आगे बढ़ने का निर्देश देता है वहाँ रुकने की आवश्यकता नहीं है, और यह धारा किसी व्यापारिक या आवासीय क्षेत्र के भीतर रेलरोड ग्रेड क्रॉसिंग पर लागू नहीं होती। एक खाली बस या गेटों की उपस्थिति इस नियम से छूट नहीं देती। स्रोत: RIGL § 31-20-4."},"59":{"q":"रोड आइलैंड में एक विभाजित राजमार्ग पर, चालक को चमकती लाल बत्तियाँ दिखा रही रुकी हुई स्कूल बस के लिए कब रुकने की आवश्यकता नहीं होती?","options":["जब भी चालक 20 mph से कम गति से चल रहा हो","जब चालक बस से दो कार-लंबाई से अधिक दूर हो","कभी नहीं — सभी चालकों को हमेशा दोनों दिशाओं में रुकना चाहिए","जब बस विभाजित राजमार्ग के चालक से दूसरी ओर वाली सड़क पर रुकी हो"],"explanation":"RIGL § 31-20-13 प्रावधान करता है कि चालक को रुकने की आवश्यकता नहीं है जहाँ राजमार्ग एक विभाजित राजमार्ग है और बस विभाजित राजमार्ग के एक ओर की सड़क पर रुकी है जबकि चालक दूसरी ओर वाहन चला रहा है। RI DMV एक विभाजित राजमार्ग को ऐसा परिभाषित करता है जो किसी अवरोधक, गार्डरेल, या घास/सीमेंट के मध्य-विभाजक (मीडियन) द्वारा अलग किया गया हो। स्रोत: RIGL § 31-20-13; RI DMV School Buses पृष्ठ."},"60":{"q":"रोड आइलैंड स्कूल-बस रुकने के अपवाद के लिए एक 'विभाजित राजमार्ग' को ऐसी सड़क के रूप में परिभाषित करता है जो निम्नलिखित में से किसके द्वारा अलग की गई हो?","options":["केवल एक दोहरी-पीली केंद्र रेखा","एक केंद्रीय दो-तरफा बाएँ-मुड़ने वाली लेन","एक जर्सी अवरोधक (बैरियर), गार्डरेल, घास या सीमेंट का मीडियन, पेड़, पानी, या विपरीत लेनों के बीच समान विभाजन","तीन या अधिक कुल लेन वाली कोई भी सड़क"],"explanation":"RI DMV समझाता है कि विभाजित-राजमार्ग अपवाद केवल वहाँ लागू होता है जहाँ विपरीत दिशाएँ एक जर्सी अवरोधक, गार्डरेल, घास या सीमेंट के मीडियन, पेड़, पानी, आदि द्वारा अलग की गई हों। एक रंगी हुई केंद्र रेखा या मुड़ने वाली लेन विभाजक नहीं है। स्रोत: RI DMV School Buses पृष्ठ (RIGL § 31-20-13 की व्याख्या करते हुए)."},"61":{"q":"एक सामान्य (अविभाजित) दो-लेन सड़क पर अपनी लाल बत्तियाँ चमका रही रोड आइलैंड स्कूल बस से मिलते या उससे आगे निकलते समय, चालक को क्या करना चाहिए?","options":["15 mph तक धीमा हो जाएँ और सावधानी से आगे निकलें","केवल तभी रुकें जब बस के पीछे से आ रहे हों","केवल वास्तव में सड़क पर मौजूद बच्चों को रास्ता दें","किसी भी दिशा से रुकें और तब तक आगे न बढ़ें जब तक बस चल न दे या चमकती बत्तियाँ बंद न हो जाएँ"],"explanation":"RIGL § 31-20-12 के अनुसार चमकती लाल बत्तियों के साथ 'स्कूल बस' चिह्नित बस से किसी भी दिशा से मिलते या उससे आगे निकलते चालकों को रुकना आवश्यक है, और चालक को तब तक आगे नहीं बढ़ना चाहिए जब तक बस फिर से चलना शुरू न कर दे या चमकती बत्तियाँ अब चालू न रहें। स्रोत: RIGL § 31-20-12."},"62":{"q":"रोड आइलैंड कानून किसी भी वाहन के चालक (आधिकारिक काम पर किसी आपातकालीन वाहन को छोड़कर) को स्कूल बस के पीछे किस दूरी से अधिक करीब चलने से रोकता है?","options":["100 फीट","20 फीट","50 फीट","300 फीट"],"explanation":"RIGL § 31-20-12 आधिकारिक काम पर आपातकालीन वाहनों को छोड़कर स्कूल बस के पीछे पचास फीट (50') से कम दूरी पर चलाने से रोकता है। स्रोत: RIGL § 31-20-12."},"63":{"q":"रोड आइलैंड के मूव ओवर (Move Over) कानून के अंतर्गत, चालक की दिशा में कम से कम दो लेन वाली सड़क पर चमकती बत्तियाँ दिखा रहे रुके हुए आपातकालीन वाहन, टो ट्रक, या राजमार्ग-रखरखाव वाहन के पास पहुँचते समय चालक को क्या करना चाहिए?","options":["वाहन के जाने तक पूरी तरह रुक जाएँ","हॉर्न बजाएँ और निर्धारित गति पर चलते रहें","दाहिने किनारे (शोल्डर) पर जाएँ और रुक जाएँ","जब सुरक्षित रूप से किया जा सके, ऐसी लेन में जाएँ जो रुके हुए वाहन के सबसे निकट न हो"],"explanation":"RIGL § 31-14-3 के अनुसार चालक को चमकती बत्तियाँ दिखा रहे रुके हुए अधिकृत आपातकालीन वाहन, टो/ट्रांसपोर्टर ट्रक, सड़क-किनारे सहायता वाहन, या रखरखाव उपकरण के सबसे निकट न होने वाली लेन में जाना आवश्यक है — यदि सड़क पर उस दिशा में दो या अधिक लेन हों और यह कदम सुरक्षित रूप से उठाया जा सके। स्रोत: RIGL § 31-14-3."},"64":{"q":"रोड आइलैंड के मूव ओवर (Move Over) कानून के अंतर्गत, जब चालक की दिशा में केवल एक लेन हो या लेन बदलना सुरक्षित रूप से न किया जा सके, तो चालक को क्या करना चाहिए?","options":["यात्रा लेन में पूरी तरह रुक जाएँ","निर्धारित गति सीमा बनाए रखें","सड़क से बाहर निकलें और पाँच मिनट प्रतीक्षा करें","एक सुरक्षित, कम गति तक धीमा हो जाएँ और वाहन से पूरी तरह आगे निकलने तक उसी पर बने रहें"],"explanation":"RIGL § 31-14-3 निर्देश देता है कि जहाँ केवल एक लेन हो या लेन बदलना असुरक्षित हो, चालक को वाहन को परिस्थितियों के लिए सुरक्षित गति तक धीमा करना चाहिए और रुके हुए वाहन से पूरी तरह आगे निकलने तक उसी कम गति पर चलाना चाहिए। स्रोत: RIGL § 31-14-3."},"65":{"q":"रोड आइलैंड का मूव ओवर (Move Over) कानून चेतावनी बत्तियाँ दिखा रहे निम्नलिखित में से किन रुके हुए वाहनों की रक्षा करता है?","options":["केवल पुलिस कारें और एम्बुलेंस","केवल राज्य के स्वामित्व वाले वाहन","आपातकालीन वाहन, टो/ट्रांसपोर्टर ट्रक, सड़क-किनारे सहायता वाहन, और राजमार्ग-रखरखाव उपकरण","केवल सक्रिय रूप से आग बुझा रहे अग्निशमन वाहन"],"explanation":"RIGL § 31-14-3 चमकती बत्तियाँ दिखा रहे अधिकृत आपातकालीन वाहनों, टो ट्रकों, ट्रांसपोर्टर ट्रकों, सड़क-किनारे सहायता वाहनों, और राजमार्ग-रखरखाव उपकरणों को संरक्षित के रूप में सूचीबद्ध करता है। यह कानून केवल पुलिस और एम्बुलेंस तक सीमित नहीं है। स्रोत: RIGL § 31-14-3."},"66":{"q":"एक निर्धारित सीमा के अभाव में, किसी भी व्यापारिक या आवासीय क्षेत्र में रोड आइलैंड की प्रथम-दृष्टया (prima facie) गति सीमा है:","options":["25 mph","30 mph","20 mph","35 mph"],"explanation":"RIGL § 31-14-2 किसी भी व्यापारिक या आवासीय क्षेत्र में पच्चीस मील प्रति घंटा (25 mph) की प्रथम-दृष्टया सीमा निर्धारित करता है। स्रोत: RIGL § 31-14-2."},"67":{"q":"रोड आइलैंड की प्रथम-दृष्टया (prima facie) गति सीमाओं के अंतर्गत, व्यापारिक/आवासीय क्षेत्रों और स्कूल क्षेत्रों के अलावा अन्य स्थानों पर, जहाँ कोई अन्य सीमा निर्धारित न हो, दिन के समय की सीमा क्या है?","options":["55 mph दिन के समय","50 mph दिन के समय","45 mph दिन के समय","65 mph दिन के समय"],"explanation":"RIGL § 31-14-2 अन्य स्थानों पर दिन के समय पचास मील प्रति घंटा (50 mph) की प्रथम-दृष्टया सीमा, और रात के समय पैंतालीस (45 mph) की सीमा निर्धारित करता है। इंटरस्टेट पर निर्धारित सीमाएँ अधिक हो सकती हैं। स्रोत: RIGL § 31-14-2."},"68":{"q":"स्कूल के दिनों के दौरान किसी स्कूल के प्रवेश और निकास द्वारों के 300 फीट के भीतर, रोड आइलैंड एक प्रथम-दृष्टया (prima facie) गति सीमा निर्धारित करता है:","options":["हर समय 15 mph","दिन के समय 20 mph","दिन के समय 25 mph","बच्चों के मौजूद होने पर 10 mph"],"explanation":"RIGL § 31-14-2 स्कूल खुले रहने वाले दिनों में दिन के समय किसी भी स्कूलघर परिसर के प्रवेश और निकास द्वारों के तीन सौ फीट (300') के भीतर बीस मील प्रति घंटा (20 mph) निर्धारित करता है। स्रोत: RIGL § 31-14-2."},"69":{"q":"रोड आइलैंड राजमार्ग पर, यातायात की सामान्य गति से धीमे चल रहे वाणिज्यिक वाहन को:","options":["दाहिनी ओर वाली लेन में या सड़क के दाहिने किनारे के यथासंभव निकट चलाना चाहिए","विलय करते यातायात से बचने के लिए केंद्र लेन में रहना चाहिए","प्रवेश रैंप से दूर रहने के लिए बाईं लेन का उपयोग करना चाहिए","जब तक चारों दिशाओं की चमकती बत्तियाँ चालू हों, किसी भी लेन का उपयोग कर सकता है"],"explanation":"RIGL § 31-15-2 ('धीमा यातायात दाईं ओर') के अनुसार यातायात की सामान्य गति से धीमे चल रहे किसी भी वाहन को उपलब्ध दाहिनी ओर वाली लेन में, या दाहिने कर्ब या किनारे के यथासंभव निकट चलाना आवश्यक है, सिवाय आगे निकलते, पास करते, या बाएँ मुड़ने की तैयारी करते समय। स्रोत: RIGL § 31-15-2."},"70":{"q":"एक ओवरसाइज़ परमिट के बिना, रोड आइलैंड में किसी वाहन या उसके भार की अधिकतम कानूनी चौड़ाई है:","options":["102 inches (8 feet 6 inches)","96 inches (8 feet)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"RIGL § 31-25-3 ओवरसाइज़ परमिट की आवश्यकता पड़ने से पहले किसी वाहन या उसके भार की कुल बाहरी चौड़ाई को एक सौ दो इंच (102\"), यानी 8 feet 6 inches तक सीमित करता है। स्रोत: RIGL § 31-25-3; RIDOT Legal OSOW guide."},"71":{"q":"एक ओवरसाइज़ परमिट के बिना, रोड आइलैंड में किसी वाहन की उसके भार सहित अधिकतम कानूनी ऊँचाई है:","options":["168 inches (14 feet)","162 inches (13 feet 6 inches)","156 inches (13 feet)","150 inches (12 feet 6 inches)"],"explanation":"RIGL § 31-25-4 वाहन की भार सहित ऊँचाई को एक सौ बासठ इंच (162\"), यानी 13 feet 6 inches तक सीमित करता है। RIDOT का Legal OSOW guide 13'6\" को कानूनी ऊँचाई के रूप में पुष्टि करता है। स्रोत: RIGL § 31-25-4; RIDOT Legal OSOW guide."},"72":{"q":"रोड आइलैंड में, 48 feet 6 inches से लंबा एक सेमीट्रेलर केवल कहाँ संचालित हो सकता है?","options":["राज्य में कहीं भी बिना किसी प्रतिबंध के","केवल टोल सड़कों पर","इंटरस्टेट राजमार्ग प्रणाली और RIDOT निदेशक द्वारा निर्दिष्ट अन्य राजमार्गों पर","किसी भी सड़क पर केवल सूर्योदय और सूर्यास्त के बीच"],"explanation":"RIGL § 31-25-6 सेमीट्रेलरों को तिरपन फीट (53') तक सीमित करता है लेकिन साढ़े अड़तालीस फीट (48'6\") से अधिक वालों को केवल इंटरस्टेट प्रणाली और RIDOT निदेशक द्वारा निर्दिष्ट राजमार्गों/सड़कों/मार्गों पर संचालित होने की अनुमति देता है। स्रोत: RIGL § 31-25-6."},"73":{"q":"एक परमिट के अभाव में, रोड आइलैंड राजमार्गों पर किसी भी वाहन या वाहनों के संयोजन का अधिकतम सकल भार है:","options":["73,280 pounds","80,000 pounds","88,000 pounds","100,000 pounds"],"explanation":"RIGL § 31-25-14 कुल सकल भार को अस्सी हज़ार पाउंड (80,000 lbs) तक सीमित करता है, जो संघीय ब्रिज फार्मूला के भी अधीन है। स्रोत: RIGL § 31-25-14."},"74":{"q":"रोड आइलैंड कानून के अंतर्गत, किसी वाहन के किसी एकल एक्सल पर अनुमत अधिकतम सकल भार है:","options":["22,400 pounds","20,000 pounds","34,000 pounds","18,000 pounds"],"explanation":"RIGL § 31-25-14 किसी एक एक्सल के पहियों पर सकल भार को बाईस हज़ार चार सौ (22,400) पाउंड तक सीमित करता है; एक टैंडम एक्सल (8 feet तक की दूरी) 36,000 pounds तक सीमित है। स्रोत: RIGL § 31-25-14."},"75":{"q":"2026 तक, रोड आइलैंड का RhodeWorks ब्रिज टोलिंग कार्यक्रम किन वाहनों से टोल वसूलने के लिए संरचित है?","options":["केवल Class 8 (और उससे बड़े) ट्रैक्टर-ट्रेलर; यात्री कारें और पिकअप छूट प्राप्त हैं","10,000 pounds से अधिक के सभी वाहन","हर वह वाहन जो किसी टोल वाले पुल को पार करता है","केवल राज्य के बाहर के वाणिज्यिक ट्रक"],"explanation":"रोड आइलैंड का RhodeWorks कार्यक्रम पुल गैंट्री पर केवल बड़े वाणिज्यिक ट्रकों — Class 8 और उससे बड़े ट्रैक्टर-ट्रेलरों — से टोल वसूलता है, यात्री कारों और छोटे वाणिज्यिक वाहनों को छूट देता है। First Circuit ने केवल-ट्रैक्टर-ट्रेलर संरचना को बरकरार रखा (केवल दैनिक सीमा को रद्द करते हुए)। स्रोत: RIDOT/RhodeWorks; First Circuit RhodeWorks decision."},"76":{"q":"जब कोई रोड आइलैंड वाणिज्यिक वाहन दो-लेन, दो-तरफा सड़क के यात्रा वाले हिस्से पर रुका हो, तो चालक को तीन आवश्यक चेतावनी त्रिकोण कहाँ रखने चाहिए?","options":["तीनों पिछले बंपर के 10 ft के भीतर","एक 200 ft पर और दो 100 ft पर, सभी वाहन के पीछे","लगभग 10 ft वाहन के पीछे यातायात की ओर, लगभग 100 ft पीछे, और लगभग 100 ft वाहन के आगे","केवल एक त्रिकोण, पीछे की ओर 50 ft पर रखा गया"],"explanation":"रोड आइलैंड CDL मैनुअल में सिखाए गए संघीय मानक (49 CFR 392.22) का पालन करता है: दो-लेन, दो-तरफा सड़क पर एक त्रिकोण लगभग 10 ft पीछे यातायात की ओर रखें, एक लगभग 100 ft पीछे, और एक लगभग 100 ft आगे। (विभाजित या एक-तरफा सड़क पर पीछे के उपकरण 10, 100, और 200 ft पर रखे जाते हैं।) स्रोत: RI CDL Manual; 49 CFR 392.22."},"77":{"q":"रोड आइलैंड में वाणिज्यिक ड्राइवर लाइसेंस (CDL) कौन सी एजेंसी जारी करती है?","options":["रोड आइलैंड डिवीज़न ऑफ़ मोटर व्हीकल्स (DMV)","रोड आइलैंड डिपार्टमेंट ऑफ़ ट्रांसपोर्टेशन (RIDOT)","रोड आइलैंड स्टेट पुलिस कमर्शियल एनफोर्समेंट यूनिट","फेडरल मोटर कैरियर सेफ्टी एडमिनिस्ट्रेशन (FMCSA)"],"explanation":"रोड आइलैंड में CDL, RI Division of Motor Vehicles (RI DMV) द्वारा जारी किए जाते हैं। RIDOT सड़कों और ओवरसाइज़/ओवरवेट परमिट को संभालता है, और FMCSA संघीय मानक निर्धारित करता है लेकिन राज्य लाइसेंस जारी नहीं करता। स्रोत: RI DMV, Commercial Driver License (CDL) पृष्ठ."},"78":{"q":"रोड आइलैंड में व्यक्तिगत रूप से CDL कौशल (सड़क) परीक्षण कहाँ आयोजित किए जाते हैं?","options":["400 Romano Vineyard Way, North Kingstown में समर्पित CDL परीक्षण स्थल पर","राज्यभर में किसी भी AAA शाखा कार्यालय में","केवल Cranston DMV मुख्यालय में","I-95 के साथ RIDOT वज़न स्टेशनों पर"],"explanation":"RI वाणिज्यिक कौशल परीक्षण CDL परीक्षण स्थल, 400 Romano Vineyard Way, North Kingstown पर अपॉइंटमेंट द्वारा दिए जाते हैं। Cranston DMV व्यक्तिगत रूप से CDL काउंटर लेनदेन और ज्ञान परीक्षण संभालता है, लेकिन कौशल परीक्षण North Kingstown स्थल पर आयोजित किया जाता है। स्रोत: RI DMV, Commercial Skills Test पृष्ठ."},"79":{"q":"रोड आइलैंड CDL के लिए आवेदन करने से पहले किसी आवेदक को कितने समय तक एक नियमित (Class D) ड्राइवर लाइसेंस धारण किया होना चाहिए?","options":["कम से कम 2 वर्ष","कम से कम 6 महीने","कम से कम 1 वर्ष","कम से कम 3 वर्ष"],"explanation":"रोड आइलैंड के लिए आवश्यक है कि एक CDL आवेदक आवेदन के समय कम से कम दो (2) वर्षों के लिए एक लाइसेंस प्राप्त चालक रहा हो। स्रोत: RI DMV, Commercial Driving License (CDL) / Commercial Learner's Permit and Exams पृष्ठ."},"80":{"q":"रोड आइलैंड नियमों के अंतर्गत, इंट्रास्टेट (केवल राज्य के भीतर) ड्राइविंग के लिए CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["18 वर्ष","16 वर्ष","21 वर्ष","25 वर्ष"],"explanation":"18 वर्ष की आयु में आप केवल इंट्रास्टेट (राज्य के भीतर) यात्रा के लिए रोड आइलैंड CDL प्राप्त कर सकते हैं; इंटरस्टेट (राज्य की सीमाओं के पार) ड्राइविंग के लिए आपको 21 वर्ष का होना चाहिए। स्रोत: RI DMV, Commercial Driving License (CDL) पृष्ठ."},"81":{"q":"रोड आइलैंड में इंटरस्टेट (राज्य की सीमाओं के पार) वाणिज्यिक वाहन चलाने के लिए आवश्यक न्यूनतम आयु क्या है?","options":["21 वर्ष","18 वर्ष","19 वर्ष","23 वर्ष"],"explanation":"रोड आइलैंड, संघीय मानक का पालन करते हुए, इंटरस्टेट वाणिज्यिक संचालन के लिए चालक के 21 वर्ष का होने की आवश्यकता रखता है; 18 से 20 वर्ष के लोग इंट्रास्टेट ड्राइविंग तक सीमित हैं। स्रोत: RI DMV, Commercial Driving License (CDL) पृष्ठ."},"82":{"q":"रोड आइलैंड CDL के लिए आवेदन करने हेतु कौन सा आवेदन फॉर्म पूरा किया जाना चाहिए?","options":["वाणिज्यिक ड्राइवर लाइसेंस के लिए आवेदन (CDL-1)","Form MCSA-5876","मानक लाइसेंस आवेदन (LI-1)","Form DL-44C"],"explanation":"रोड आइलैंड के आवेदक वाणिज्यिक ड्राइवर लाइसेंस के लिए आवेदन (CDL-1) पूरा करते हैं, जिसमें चालक-इतिहास शपथपत्र भी शामिल है। स्रोत: RI DMV, Commercial Learner's Permit and Exams पृष्ठ (CDL-1 form)."},"83":{"q":"रोड आइलैंड में, एक CDL आवेदक को कानूनी उपस्थिति का क्या प्रमाण प्रदान करना चाहिए?","options":["अमेरिकी नागरिकता या वैध स्थायी निवास का प्रमाण","किसी भी देश का एक वैध पासपोर्ट","केवल एक सामाजिक सुरक्षा कार्ड, बिना किसी और प्रमाण के","किसी नियोक्ता से निवास का नोटरीकृत बयान"],"explanation":"RI DMV सभी CDL आवेदकों से अमेरिकी नागरिक या वैध स्थायी निवासी के रूप में स्थिति का प्रमाण, साथ ही रोड आइलैंड निवास का प्रमाण प्रदान करने की आवश्यकता रखता है। स्रोत: RI DMV, Commercial Driving License (CDL) पृष्ठ."},"84":{"q":"रोड आइलैंड वाणिज्यिक शिक्षार्थी परमिट (CLP) प्राप्त करने के लिए न्यूनतम आवश्यकता कौन सी ज्ञान परीक्षा है?","options":["सामान्य ज्ञान (General Knowledge) परीक्षा","एयर ब्रेक्स परीक्षा","कॉम्बिनेशन व्हीकल्स परीक्षा","खतरनाक सामग्री (Hazardous Materials) परीक्षा"],"explanation":"सामान्य ज्ञान (General Knowledge) परीक्षा रोड आइलैंड में CLP के लिए न्यूनतम आवश्यकता है; मांगी गई श्रेणी और समर्थनों (एंडोर्समेंट) के आधार पर अतिरिक्त ज्ञान परीक्षाएँ आवश्यक हैं। स्रोत: RI DMV, Commercial Learner's Permit and Exams पृष्ठ."},"85":{"q":"रोड आइलैंड सामान्य ज्ञान (General Knowledge) CDL परीक्षा (50 प्रश्न) में, उत्तीर्ण होने के लिए कौन सा स्कोर आवश्यक है?","options":["80% (50 में से 40 सही)","70% (50 में से 35 सही)","75% (50 में से 38 सही)","90% (50 में से 45 सही)"],"explanation":"रोड आइलैंड 80% की मानक CDL उत्तीर्ण सीमा का पालन करता है; 50-प्रश्न वाली सामान्य ज्ञान परीक्षा में इसका अर्थ है 40 सही उत्तर। स्रोत: RI CDL Manual / RI DMV knowledge-testing standards."},"86":{"q":"रोड आइलैंड वाणिज्यिक शिक्षार्थी परमिट (CLP) कितने समय के लिए वैध होता है, और क्या इसे नवीनीकृत किया जा सकता है?","options":["अधिकतम एक वर्ष के लिए वैध और गैर-नवीकरणीय","180 दिनों के लिए वैध और एक बार नवीकरणीय","दो वर्ष के लिए वैध और नवीकरणीय","60 दिनों के लिए वैध और गैर-नवीकरणीय"],"explanation":"एक रोड आइलैंड CLP अधिकतम एक वर्ष के लिए वैध है और गैर-नवीकरणीय है; यदि यह समाप्त हो जाता है तो आवेदक को सभी ज्ञान परीक्षाएँ फिर से देनी होंगी और शुल्क फिर से चुकाने होंगे। स्रोत: RI DMV, Commercial Learner's Permit and Exams पृष्ठ."},"87":{"q":"रोड आइलैंड CLP प्राप्त करने के बाद, CDL कौशल परीक्षण देने से पहले धारक को इसे कितने समय तक धारण करना चाहिए?","options":["कम से कम 14 दिन","कम से कम 30 दिन","कम से कम 7 दिन","कम से कम 60 दिन"],"explanation":"जिस संघीय नियम का यह पालन करता है उसके अनुरूप, रोड आइलैंड CDL कौशल परीक्षण देने से पहले CLP को कम से कम 14 दिनों तक धारण करने की आवश्यकता रखता है। स्रोत: RI DMV, Commercial Skills Test पृष्ठ (FMCSA 49 CFR 383 standard)."},"88":{"q":"रोड आइलैंड CDL कौशल परीक्षण के तीन भाग कौन से हैं?","options":["वाहन निरीक्षण, बुनियादी नियंत्रण कौशल, और सड़क परीक्षण","लिखित परीक्षण, दृष्टि परीक्षण, और सड़क परीक्षण","एयर ब्रेक्स, बैकिंग, और राजमार्ग ड्राइविंग","प्री-ट्रिप, खतरनाक सामग्री, और रात्रि ड्राइविंग"],"explanation":"रोड आइलैंड कौशल परीक्षण के तीन भाग हैं: वाहन निरीक्षण (प्री-ट्रिप) परीक्षण, बुनियादी नियंत्रण कौशल परीक्षण, और सड़क परीक्षण; एक आवेदक को तीनों उत्तीर्ण करने होंगे। स्रोत: RI DMV, Commercial Skills Test पृष्ठ."},"89":{"q":"रोड आइलैंड CDL कौशल परीक्षण के लिए उपयोग किया जाने वाला वाहन किसे उपलब्ध कराना चाहिए, और यह किस स्थिति में होना चाहिए?","options":["आवेदक अपना वाहन उपलब्ध कराता है, जो खाली (कोई माल नहीं) पहुँचना चाहिए","DMV सभी आवेदकों के लिए राज्य-स्वामित्व वाला परीक्षण वाहन प्रदान करता है","आवेदक के नियोक्ता को एक भरा हुआ परीक्षण वाहन प्रदान करना चाहिए","वज़न श्रेणी की परवाह किए बिना, कोई भी किराए का बॉक्स ट्रक स्वीकार्य है"],"explanation":"रोड आइलैंड में उम्मीदवार को अपना प्रतिनिधि वाहन उपलब्ध कराना चाहिए, और यह खाली (कोई माल नहीं) पहुँचना चाहिए; टैंकरों को खाली, साफ और शुद्ध (purged) प्रमाणित होना चाहिए। स्रोत: RI DMV, Commercial Skills Test पृष्ठ."},"90":{"q":"CLP और ऑपरेटर लाइसेंस के अलावा, रोड आइलैंड कौशल परीक्षण के लिए कौन से दस्तावेज़ प्रस्तुत किए जाने चाहिए?","options":["वैध वाहन पंजीकरण, सक्रिय बीमा का प्रमाण, और एक वैध निरीक्षण स्टिकर","एक हाई-स्कूल डिप्लोमा और रोज़गार का प्रमाण","केवल एक पासपोर्ट और जन्म प्रमाणपत्र","एक CDL प्रशिक्षण स्कूल से एक नोटरीकृत पत्र"],"explanation":"रोड आइलैंड को CLP और ऑपरेटर लाइसेंस की हार्ड कॉपी के साथ-साथ वैध वाहन (और ट्रेलर, यदि लागू हो) पंजीकरण, सक्रिय बीमा का प्रमाण, और एक सक्रिय वाहन निरीक्षण स्टिकर की आवश्यकता है। स्रोत: RI DMV, Commercial Skills Test पृष्ठ."},"91":{"q":"रोड आइलैंड नियमों के अंतर्गत, पहली बार के Class A या Class B आवेदक के लिए एंट्री-लेवल ड्राइवर ट्रेनिंग (ELDT) कब पूरा किया जाना चाहिए?","options":["CDL कौशल परीक्षण देने से पहले","कौशल परीक्षण उत्तीर्ण करने के 30 दिनों के भीतर","केवल CDL जारी हो जाने के बाद","यह वैकल्पिक है और नियोक्ता की मंज़ूरी से छोड़ा जा सकता है"],"explanation":"पहली बार के Class A/B आवेदक को CDL कौशल परीक्षण देने की अनुमति देने से पहले ELDT को एक पंजीकृत प्रदाता के साथ सफलतापूर्वक पूरा किया जाना चाहिए। स्रोत: RI DMV, ELDT पृष्ठ (federal ELDT rule, effective Feb 7, 2022)."},"92":{"q":"किस समर्थन (एंडोर्समेंट) के लिए रोड आइलैंड को ज्ञान (KNOWLEDGE) परीक्षण से पहले (न कि कौशल परीक्षण से पहले) ELDT पूरा करने की आवश्यकता होती है?","options":["खतरनाक सामग्री (H) समर्थन","यात्री (P) समर्थन","स्कूल बस (S) समर्थन","डबल्स/ट्रिपल्स (T) समर्थन"],"explanation":"खतरनाक सामग्री (H) समर्थन के लिए, ELDT को ज्ञान परीक्षण देने से पहले पूरा किया जाना चाहिए; P और S समर्थनों के लिए ELDT कौशल परीक्षण से पहले पूरा किया जाता है। स्रोत: RI DMV, ELDT पृष्ठ."},"93":{"q":"एक अनुमोदित ELDT प्रशिक्षण प्रदाता खोजने के लिए एक रोड आइलैंड आवेदक को कहाँ खोजना चाहिए?","options":["FMCSA Training Provider Registry (TPR)","RI DMV CLP प्रतीक्षा-सूची पोर्टल","National Registry of Certified Medical Examiners","RIDOT परमिट कार्यालय विक्रेता सूची"],"explanation":"अनुमोदित ELDT प्रदाता FMCSA Training Provider Registry (tpr.fmcsa.dot.gov) पर सूचीबद्ध हैं; वहाँ पूर्णता को भी सत्यापित किया जा सकता है। स्रोत: RI DMV, ELDT पृष्ठ."},"94":{"q":"एक रोड आइलैंड CDL आवेदक को कितनी स्व-प्रमाणन वाणिज्य श्रेणियों में से चुनना चाहिए?","options":["चार श्रेणियाँ","दो श्रेणियाँ","तीन श्रेणियाँ","छह श्रेणियाँ"],"explanation":"एक रोड आइलैंड आवेदक को चार श्रेणियों में से एक में स्व-प्रमाणित होना चाहिए: Interstate Non-Excepted, Interstate Excepted, Intrastate Non-Excepted, या Intrastate Excepted. स्रोत: RI DMV, Medical Certification / Self-Certification पृष्ठ."},"95":{"q":"एक रोड आइलैंड चालक जो 'Interstate Non-Excepted' के रूप में प्रमाणित होता है उसे क्या करना चाहिए?","options":["एक संघीय DOT Medical Examiner's Certificate प्राप्त करना और बनाए रखना","राज्य की सीमाओं के पार कोई भी माल ले जाने से बचना","हर पाँच वर्ष के बजाय CDL को सालाना नवीनीकृत करना","अपनी इंटरस्टेट स्थिति के कारण सड़क परीक्षण छोड़ देना"],"explanation":"Interstate Non-Excepted चालक रोड आइलैंड के भीतर और बाहर संचालन करते हैं और उन्हें एक संघीय DOT Medical Examiner's Certificate प्राप्त करना आवश्यक है; छूट प्राप्त (excepted) श्रेणियों को नहीं। स्रोत: RI DMV, Medical Certification / Self-Certification पृष्ठ."},"96":{"q":"एक गैर-छूट प्राप्त (non-excepted) रोड आइलैंड CDL चालक का DOT चिकित्सा प्रमाणन अब DMV को कैसे प्रेषित किया जाता है?","options":["प्रमाणित चिकित्सा परीक्षक इसे इलेक्ट्रॉनिक रूप से FMCSA National Registry को प्रस्तुत करता है, जो इसे RI DMV को अग्रेषित करता है","चालक चिकित्सा कार्ड की एक कागज़ी प्रति सीधे RI DMV को डाक से भेजता है","नियोक्ता प्रमाणपत्र को फाइलिंग के लिए RIDOT को फैक्स करता है","चालक इसे RI E-ZPass खाता पोर्टल के माध्यम से अपलोड करता है"],"explanation":"RI DMV अब सीधे चिकित्सा प्रमाणन स्वीकार नहीं करता; प्रमाणित चिकित्सा परीक्षक Medical Examiner's Certificate (Form MCSA-5876/5875) को इलेक्ट्रॉनिक रूप से FMCSA National Registry को प्रस्तुत करता है, जो इसे DMV को अग्रेषित करता है। इसे अद्यतन रखने में विफलता के परिणामस्वरूप CDL डाउनग्रेड होता है। स्रोत: RI DMV, Medical Certification पृष्ठ; National Registry of Certified Medical Examiners."}},"ar":{"0":{"q":"على طرق رود آيلاند السريعة، ما هو الحد الأقصى القانوني لعرض المركبة التجارية أو حمولتها، دون الحصول على تصريح خاص؟","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"تحدد القوانين العامة لولاية رود آيلاند § 31-25-3 الحد الأقصى لعرض أي مركبة أو حمولتها بـ 102 inches (8 feet 6 inches). وأي شيء أعرض من ذلك يتطلب تصريح حجم زائد من RIDOT. المصدر: R.I. Gen. Laws § 31-25-3."},"1":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة، بما في ذلك حمولتها، على طرق رود آيلاند السريعة دون تصريح؟","options":["162 inches (13 feet 6 inches)","156 inches (13 feet)","168 inches (14 feet)","150 inches (12 feet 6 inches)"],"explanation":"تحدّ القوانين العامة لولاية رود آيلاند § 31-25-4 ارتفاع المركبة، بما في ذلك الحمولة، بـ 162 inches (13 feet 6 inches). والحمولات التي تتجاوز ذلك تتطلب تصريح ارتفاع زائد من RIDOT. المصدر: R.I. Gen. Laws § 31-25-4."},"2":{"q":"ما هو الحد الأقصى للوزن الإجمالي الكلي، بالأرطال، لمركبة أو مجموعة مركبات على طرق رود آيلاند السريعة دون تصريح وزن زائد؟","options":["73,280 pounds","80,000 pounds","88,000 pounds","100,000 pounds"],"explanation":"تحدّ رود آيلاند الوزن الإجمالي الكلي بـ 80,000 pounds، بما يطابق المعيار الفيدرالي للطرق السريعة بين الولايات، ما لم يتم الحصول على تصريح خاص. المصدر: R.I. Gen. Laws § 31-25-14؛ دليل RIDOT لتصاريح المركبات الزائدة الوزن والحجم."},"3":{"q":"في رود آيلاند، الوزن الإجمالي المفروض على الطريق السريع من عجلات أي محور مفرد لا يجوز أن يتجاوز كم رطلاً؟","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"تحدد القوانين العامة لولاية رود آيلاند § 31-25-13 حد المحور المفرد بـ 22,400 pounds. وهذا أعلى من المعيار الفيدرالي للمحور المفرد البالغ 20,000 pounds للطرق بين الولايات، وهو رقم خاص بولاية رود آيلاند. المصدر: R.I. Gen. Laws § 31-25-13."},"4":{"q":"ما هو الحد الأقصى القانوني للوزن على مجموعة محاور مزدوجة في رود آيلاند عندما لا تتجاوز المسافة بين المحورين 8 feet؟","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"تحدّ القوانين العامة لولاية رود آيلاند § 31-25-14 مجموعة المحاور المزدوجة بـ 36,000 pounds عندما لا تتجاوز المسافة بين المحورين 8 feet. المصدر: R.I. Gen. Laws § 31-25-14."},"5":{"q":"بموجب قانون رود آيلاند، كيف يُعرَّف \"حمل المحور\" المفرد لأغراض حدود الوزن؟","options":["إجمالي الحمل على جميع العجلات الواقعة بين مستويين عموديين عرضيين متوازيين تفصل بينهما مسافة 40 inches","إجمالي الحمل على جميع العجلات الواقعة بين مستويين تفصل بينهما مسافة 96 inches","الحمل الذي يحمله أي إطار واحد على المركبة","نصف الوزن الإجمالي المسجّل للمركبة"],"explanation":"تعرّف القوانين العامة لولاية رود آيلاند § 31-25-13 حمل المحور بأنه إجمالي الحمل المنقول إلى الطريق من جميع العجلات التي تقع مراكزها بين مستويين عموديين عرضيين متوازيين تفصل بينهما مسافة 40 inches، ممتدّين عبر كامل عرض المركبة. المصدر: R.I. Gen. Laws § 31-25-13."},"6":{"q":"ما هو الحد الأقصى لطول مركبة مفردة (وليست مجموعة مركبات)، بما في ذلك الحمولة والمصدّات، على طرق رود آيلاند السريعة؟","options":["35 feet","40 feet","48 feet","53 feet"],"explanation":"تحدّ القوانين العامة لولاية رود آيلاند § 31-25-5 المركبة المفردة، بما في ذلك أي حمولة، بـ 40 feet إجمالاً (45 feet للحافلة، أو الكرفان الآلي، أو مركبة التخييم الترفيهية). المصدر: R.I. Gen. Laws § 31-25-5."},"7":{"q":"في رود آيلاند، ما هو الحد الأقصى لطول الحافلة المفردة، أو الكرفان الآلي، أو مركبة التخييم الترفيهية؟","options":["40 feet","42 feet","45 feet","48 feet"],"explanation":"تسمح القوانين العامة لولاية رود آيلاند § 31-25-5 للحافلة، أو الكرفان الآلي، أو مركبة التخييم الترفيهية بأن يصل طولها إلى 45 feet، بينما تقتصر المركبات المفردة الأخرى على 40 feet. المصدر: R.I. Gen. Laws § 31-25-5."},"8":{"q":"ما هو الحد الأقصى لطول نصف المقطورة العاملة في رود آيلاند، باستثناء المصدّات والملحقات؟","options":["48 feet 6 inches","51 feet","53 feet","57 feet"],"explanation":"تسمح القوانين العامة لولاية رود آيلاند § 31-25-6 بنصف المقطورات حتى 53 feet، باستثناء المصدّات والملحقات. المصدر: R.I. Gen. Laws § 31-25-6."},"9":{"q":"في رود آيلاند، أنصاف المقطورات التي يزيد طولها عن أي طول لا يجوز أن تعمل إلا على شبكة الطرق السريعة بين الولايات وعلى الطرق التي يحددها المدير تحديداً؟","options":["45 feet","48 feet 6 inches","50 feet","53 feet"],"explanation":"تقيّد القوانين العامة لولاية رود آيلاند § 31-25-6 أنصاف المقطورات التي تتجاوز 48 feet 6 inches بشبكة الطرق السريعة بين الولايات وبالطرق والشوارع والممرات التي يحددها المدير. المصدر: R.I. Gen. Laws § 31-25-6."},"10":{"q":"ما هي الجهة التي تصدر تصاريح المركبات الزائدة الحجم والزائدة الوزن في رود آيلاند؟","options":["إدارة النقل في ولاية رود آيلاند (RIDOT)","شرطة ولاية رود آيلاند","الإدارة الفيدرالية للطرق السريعة","كاتب المدينة أو البلدة المحلي حيث يبدأ السفر"],"explanation":"تُصدر التصاريح الخاصة للمركبات التي تتجاوز حدود الحجم أو الوزن القانونية من قبل إدارة النقل بالولاية (RIDOT). المصدر: دليل RIDOT لتصاريح المركبات الزائدة الوزن والحجم؛ R.I. Gen. Laws § 31-25-18."},"11":{"q":"ما هي المعادلة التي تستخدمها رود آيلاند لتحديد الوزن الإجمالي المسموح به على أي مجموعة من المحاور المتتالية؟","options":["معادلة الجسر الفيدرالية: W = 500[(LN/(N-1)) + 12N + 36]","الوزن الإجمالي = 1,000 pounds لكل إنش من عرض الإطار","الوزن الإجمالي = 34,000 pounds لكل مجموعة محاور، ثابت","الوزن الإجمالي = 80,000 مقسوماً على عدد المحاور"],"explanation":"تطبّق القوانين العامة لولاية رود آيلاند § 31-25-14 معادلة الجسر الفيدرالية، W = 500[(LN/(N-1)) + 12N + 36]، حيث W هو الوزن الإجمالي على مجموعة من المحاور المتتالية، وL هي المسافة بالأقدام بين المحورين الخارجيين للمجموعة، وN هو عدد المحاور. المصدر: R.I. Gen. Laws § 31-25-14."},"12":{"q":"في معادلة الجسر لرود آيلاند W = 500[(LN/(N-1)) + 12N + 36]، ماذا يمثّل المتغير \"N\"؟","options":["عدد المحاور في المجموعة قيد النظر","الوزن الصافي للحمولة فقط","عدد الإطارات على المحور القائد","العرض الاسمي للمركبة بالأقدام"],"explanation":"في معادلة الجسر التي اعتمدتها رود آيلاند، N هو عدد المحاور في المجموعة، وL هي المسافة بالأقدام بين المحورين الطرفيين، وW هو الحد الأقصى المسموح به للوزن الإجمالي على تلك المجموعة. المصدر: R.I. Gen. Laws § 31-25-14."},"13":{"q":"بموجب قواعد الوزن في رود آيلاند، إذا أنتجت معادلة الجسر حداً للمحور المزدوج أقل من 36,000 pounds، فما القيمة التي تُستخدم باعتبارها الحد القانوني؟","options":["يجب استخدام نتيجة المعادلة الأدنى","يُستخدم 34,000 pounds","يُعامل 36,000 pounds باعتباره الحد القانوني","يجب إعادة تباعد مجموعة المحاور قبل التحميل"],"explanation":"تنص القوانين العامة لولاية رود آيلاند § 31-25-14 على أنه عندما تنتج معادلة الجسر رقماً للمحور المزدوج أقل من 36,000 pounds، يُعتبر 36,000 pounds هو الحد القانوني. المصدر: R.I. Gen. Laws § 31-25-14."},"14":{"q":"يحتاج ناقل إلى نقل حمولة غير قابلة للتجزئة عرضها 11 feet على طريق سريع في رود آيلاند. ماذا يجب على الناقل أن يفعل؟","options":["لا شيء؛ فـ 11 feet ضمن العرض القانوني","الحصول على تصريح حجم زائد من RIDOT قبل النقل","إخطار الشرطة المحلية فقط","تقليل الحمولة إلى 96 inches أولاً"],"explanation":"لأن 11 feet (132 inches) تتجاوز العرض القانوني البالغ 102 inches بموجب § 31-25-3، يجب على الناقل الحصول على تصريح حجم زائد من RIDOT قبل نقل الحمولة. المصدر: R.I. Gen. Laws § 31-25-3 و§ 31-25-18؛ دليل تصاريح RIDOT."},"15":{"q":"ما هي رسوم RIDOT القياسية للرحلة الواحدة لنقل مركبة أو حمولة غير قابلة للتجزئة زائدة الحجم أو الوزن في رود آيلاند؟","options":["$10.00 per trip","$20.00 per trip","$50.00 per trip","$100.00 per trip"],"explanation":"يفرض دليل RIDOT لتصاريح المركبات الزائدة الوزن والحجم رسم رحلة قدره $20.00 لنقل المركبات أو الحمولات غير القابلة للتجزئة. المصدر: دليل RIDOT لتصاريح المركبات الزائدة الوزن والحجم، القسم 4.4."},"16":{"q":"بدلاً من دفع رسوم لكل رحلة، يجوز للناقل الذي يقوم بعمليات نقل متكررة زائدة الحجم/الوزن داخل ولاية رود آيلاند الحصول على تصريح شامل مقابل أي رسم؟","options":["$50.00","$100.00","$250.00","$500.00"],"explanation":"يسمح دليل تصاريح RIDOT بالحصول على تصريح شامل لعمليات النقل داخل الولاية مقابل $100.00 بدلاً من دفع رسوم لكل رحلة. المصدر: دليل RIDOT لتصاريح المركبات الزائدة الوزن والحجم، القسم 4.4."},"17":{"q":"بموجب دليل تصاريح رود آيلاند، كم عدد مركبات المرافقة (المركبات القائدة) المطلوبة لحمولة يزيد عرضها الإجمالي عن 14 feet 6 inches؟","options":["لا يُطلب أي مرافق","مركبة مرافقة واحدة","مركبتا مرافقة","أربع مركبات مرافقة"],"explanation":"يتطلب دليل تصاريح RIDOT مرافقاً واحداً للأعراض التي تتراوح بين 12 feet 0 inches و14 feet 6 inches، ومركبتي مرافقة للأعراض التي تتجاوز 14 feet 6 inches. المصدر: دليل RIDOT لتصاريح المركبات الزائدة الوزن والحجم، القسم 5.4."},"18":{"q":"وفقاً لدليل تصاريح رود آيلاند، متى لا يُسمح عموماً بعمليات النقل المرخّصة الزائدة الحجم/الوزن؟","options":["من غروب شمس يوم الجمعة إلى شروق شمس يوم الاثنين وفي العطلات المدرجة","فقط بين منتصف الليل و4:00 a.m. يومياً","فقط خلال الأسبوع الأول من كل شهر","أبداً؛ يجوز تشغيل عمليات النقل المرخّصة في أي وقت"],"explanation":"يحظر دليل تصاريح RIDOT عمليات النقل، ما لم يُذكر خلاف ذلك، من غروب شمس يوم الجمعة إلى شروق شمس يوم الاثنين وفي العطلات الرسمية المدرجة. المصدر: دليل RIDOT لتصاريح المركبات الزائدة الوزن والحجم، القسم 4.15 / 5.7."},"19":{"q":"كيف يعامل قانون رود آيلاند المركبات الزراعية، والجرارات الزراعية، وآلات الطرق، وأجهزة الإطفاء فيما يتعلق بحدود الحجم والوزن في الفصل 31-25؟","options":["تُعفى من قيود الحجم والوزن","تقتصر على 50% من حدود الوزن العادية","يجب أن تحمل تصريح حجم زائد سنوياً في جميع الأوقات","تُمنع من جميع الطرق السريعة المرقّمة للولاية"],"explanation":"تعفي القوانين العامة لولاية رود آيلاند § 31-25-2 أجهزة الإطفاء، وآلات الطرق، والمركبات الزراعية (بما في ذلك الجرارات الزراعية) التي تُنقل مؤقتاً على طريق سريع من قيود الحجم والوزن في الفصل 31-25. المصدر: R.I. Gen. Laws § 31-25-2."},"20":{"q":"في رود آيلاند، ما هو الحد الأدنى للعمر للحصول على CDL صالح للتشغيل داخل الولاية (INTRASTATE) فقط؟","options":["16 years old","18 years old","21 years old","25 years old"],"explanation":"ينص دليل CDL لرود آيلاند (إرشادات لمتقدمي CDL) على أنه يجب أن يكون لديك رخصة قيادة سارية لمدة سنتين على الأقل وأن يكون عمرك 18 عاماً على الأقل للحصول على CDL داخل الولاية INTRASTATE فقط؛ ويُشترط عمر 21 للتشغيل بين الولايات. المصدر: دليل رخصة القيادة التجارية لـ RI DMV (AAMVA 2005، مراجعة يوليو 2014)."},"21":{"q":"ما هو الحد الأدنى للعمر المطلوب في رود آيلاند لتشغيل مركبة آلية تجارية في التجارة بين الولايات INTERSTATE (عبور حدود الولايات)؟","options":["18 years old","19 years old","21 years old","23 years old"],"explanation":"تشترط RI DMV أن يكون عمر السائق 21 ليكون مؤهلاً لتشغيل CDL بين الولايات (عبور حدود الولايات)؛ وعمر 18 يؤهل فقط للتشغيل داخل الولاية. المصدر: صفحة CDL في RI DMV ودليل رخصة القيادة التجارية لرود آيلاند (مراجعة يوليو 2014)."},"22":{"q":"بموجب تصنيف CDL في رود آيلاند، أي فئة تُجيز تشغيل أي مجموعة (COMBINATION) من المركبات بوزن إجمالي مركّب GCWR يبلغ 26,001 lbs أو أكثر، بشرط أن يتجاوز الوزن الإجمالي للمركبة GVWR للوحدة (الوحدات) المقطورة 10,000 lbs؟","options":["Class A","Class B","Class C","Class D"],"explanation":"وفقاً لدليل CDL لرود آيلاند، تُجيز رخصة Class A CDL تشغيل أي مجموعة من المركبات بوزن إجمالي مركّب GCWR يبلغ 26,001 رطلاً أو أكثر، بشرط أن يتجاوز الوزن الإجمالي GVWR للمركبة (المركبات) المقطورة 10,000 رطل. المصدر: دليل رخصة القيادة التجارية لرود آيلاند، فئات الرخصة."},"23":{"q":"في رود آيلاند، رخصة CDL التي تُجيز قيادة مركبة مفردة (SINGLE) بوزن إجمالي GVWR يبلغ 26,001 lbs أو أكثر (أو مثل هذه المركبة وهي تقطر وحدة لا يتجاوز وزنها الإجمالي GVWR مقدار 10,000 lbs) هي أي فئة؟","options":["Class A","Class B","Class C","Class E"],"explanation":"يعرّف دليل CDL لرود آيلاند الفئة Class B بأنها أي مركبة مفردة بوزن إجمالي GVWR يبلغ 26,001 رطلاً أو أكثر، أو مثل هذه المركبة وهي تقطر مركبة لا يتجاوز وزنها الإجمالي GVWR مقدار 10,000 رطل. المصدر: دليل رخصة القيادة التجارية لرود آيلاند، فئات الرخصة."},"24":{"q":"أي فئة CDL في رود آيلاند تشمل مركبة (لا تستوفي شروط الفئة A أو B) مصممة لنقل 16 راكباً أو أكثر بما في ذلك السائق، أو مركبة تحمل لوحات تحذيرية للمواد الخطرة؟","options":["Class A","Class B","Class C","Class M"],"explanation":"يعرّف دليل CDL لرود آيلاند الفئة Class C بأنها أي مركبة لا تستوفي شروط الفئة A أو B لكنها مصممة لنقل 16 راكباً أو أكثر بما في ذلك السائق، أو تحمل لوحات تحذيرية للمواد الخطرة. المصدر: دليل رخصة القيادة التجارية لرود آيلاند، فئات الرخصة."},"25":{"q":"على رخصة CDL في رود آيلاند، ما هو رمز التظهير المطلوب لنقل المواد الخطرة بكميات تتطلب وضع لوحات تحذيرية بموجب لوائح DOT الفيدرالية؟","options":["Code N","Code H","Code T","Code P"],"explanation":"وفقاً لدليل CDL لرود آيلاند، يُطلب تظهير H (HazMat) على أي فئة رخصة عند نقل المواد الخطرة بأي كمية تتطلب وضع لوحات تحذيرية بموجب لوائح DOT الفيدرالية. المصدر: دليل رخصة القيادة التجارية لرود آيلاند، التظهيرات."},"26":{"q":"أي تظهير تشترطه رود آيلاند لتشغيل مركبة صهريج تنقل مادة سائلة أو غازية، أو خزان متنقل بسعة مصنّفة 1,000 gallons أو أكثر؟","options":["N - Tank Vehicles","T - Double/Triple Trailers","P - Passenger","S - School Bus"],"explanation":"ينص دليل CDL لرود آيلاند على أن تظهير N (مركبات الصهاريج) مطلوب على أي فئة رخصة عند نقل مادة سائلة أو غازية في مركبة صهريج، أو أي خزان متنقل بسعة مصنّفة 1,000 gallons أو أكثر. المصدر: دليل رخصة القيادة التجارية لرود آيلاند، التظهيرات."},"27":{"q":"في رود آيلاند، لا يمكن الحصول على تظهير T (المقطورات المزدوجة/الثلاثية) إلا من قبل المشغّلين الحاملين لأي فئة CDL؟","options":["مشغّلو الفئة Class C","مشغّلو الفئة Class B","مشغّلو الفئة Class A","مشغّلو أي فئة"],"explanation":"ينص دليل CDL لرود آيلاند على أن تظهير T (المقطورات المزدوجة/الثلاثية) مطلوب لمشغّلي الفئة Class A الذين ينقلون مقطورات مزدوجة/ثلاثية حيث يكون التشغيل مسموحاً به قانوناً. المصدر: دليل رخصة القيادة التجارية لرود آيلاند، التظهيرات."},"28":{"q":"قبل الاختبار، ما هي الخطوة الإضافية التي تشترطها رود آيلاند للحصول على تظهير حافلة المدرسة (S) بالإضافة إلى الاختبار التحريري واختبار المهارات؟","options":["تقييم تهديد أمني من TSA","شهادة حافلة مدرسية من رود آيلاند عبر مكتب سلامة الحافلات المدرسية في DMV","طلب رخصة سائق أخضر","اختبار معرفي للمقطورات المزدوجة/الثلاثية"],"explanation":"ينص دليل CDL لرود آيلاند على أن مشغّلي تظهير S (حافلة المدرسة) يجب أن يحصلوا أولاً على شهادة حافلة مدرسية من رود آيلاند عبر مكتب سلامة الحافلات المدرسية في DMV. المصدر: دليل رخصة القيادة التجارية لرود آيلاند، التظهيرات."},"29":{"q":"وفقاً لدليل CDL لرود آيلاند، يُطلب تظهير P (الركاب) عندما تكون المركبة مصممة لاستيعاب أكثر من كم شخصاً بما في ذلك المشغّل؟","options":["8","12","15","16"],"explanation":"ينص دليل CDL لرود آيلاند على أن تظهير P مطلوب على أي فئة رخصة عندما تكون المركبة مصممة لاستيعاب أكثر من 16 راكباً بما في ذلك المشغّل؛ كما يجب إكمال طلب رخصة سائق أخضر. المصدر: دليل رخصة القيادة التجارية لرود آيلاند، التظهيرات."},"30":{"q":"أي تظهير CDL في رود آيلاند يجمع بين تظهيري HazMat ومركبات الصهاريج، ويتطلب اجتياز كلا الاختبارين المعرفيين؟","options":["Code S","Code T","Code X","Code P"],"explanation":"يصف دليل CDL لرود آيلاند التظهير X بأنه الجمع بين H (HazMat) وN (الصهريج)؛ ويجب اجتياز كلا الاختبارين. المصدر: دليل رخصة القيادة التجارية لرود آيلاند، التظهيرات."},"31":{"q":"بموجب القواعد الفيدرالية المطبّقة في رود آيلاند، كم يجب الاحتفاظ بتصريح المتعلّم التجاري (CLP) قبل أن يتمكن حامله من إجراء اختبار مهارات CDL؟","options":["7 days","14 days","30 days","60 days"],"explanation":"تحظر اللائحة الفيدرالية 49 CFR 383.25، التي تطبّقها RI DMV، على حامل CLP إجراء اختبار مهارات CDL في أول 14 days بعد إصدار CLP لأول مرة. المصدر: 49 CFR 383.25؛ متطلبات CLP في RI DMV."},"32":{"q":"أي اختبار معرفي يجب أن يجتازه كل متقدم لـ CDL في رود آيلاند، بغض النظر عن الفئة أو التظهير المطلوب؟","options":["اختبار المكابح الهوائية","اختبار المركبات المركّبة","اختبار المعرفة العامة","اختبار نقل الركاب"],"explanation":"ينص دليل CDL لرود آيلاند على أن اختبار المعرفة العامة يخضع له جميع المتقدمين؛ أما الاختبارات الأخرى فتعتمد على الفئة والتظهيرات. المصدر: دليل رخصة القيادة التجارية لرود آيلاند، القسم 1، الاختبارات المعرفية."},"33":{"q":"في اختبار المعرفة العامة لـ CDL في رود آيلاند، كم سؤالاً من أصل 50 سؤالاً يجب الإجابة عنها بشكل صحيح للنجاح (80%)؟","options":["30","40","44","45"],"explanation":"يدرج جدول الاختبارات الإلكترونية/اليدوية في دليل CDL لرود آيلاند اختبار المعرفة العامة على أنه 50 سؤالاً، يتطلب 40 إجابة صحيحة (80%) للنجاح. المصدر: دليل رخصة القيادة التجارية لرود آيلاند، الاختبارات الإلكترونية/اليدوية."},"34":{"q":"أي جهة تدير وتجدول اختبار القيادة (المهارات) على الطريق لـ CDL لمتقدمي رود آيلاند؟","options":["مكتب RI DMV الرئيسي في كرانستون","كلية المجتمع في رود آيلاند (CCRI)","شرطة ولاية رود آيلاند","مكتب تصاريح DOT في رود آيلاند"],"explanation":"ينص دليل CDL لرود آيلاند على أن اختبارات الطريق تُجرى من قبل كلية المجتمع في رود آيلاند (CCRI) ويجب جدولتها معها. المصدر: دليل رخصة القيادة التجارية لرود آيلاند، اختبارات الطريق."},"35":{"q":"أي مما يلي يُعد مستنداً مطلوباً لمتقدم CDL في رود آيلاند، وفقاً لإرشادات CLP في RI DMV؟","options":["بطاقة ضمان اجتماعي سارية","خطاب موثّق من صاحب العمل","سند ملكية مركبة تجارية","تظهير دراجة نارية"],"explanation":"يشترط دليل CDL لرود آيلاند على جميع المتقدمين تقديم بطاقة ضمان اجتماعي سارية، وبطاقة طبية سارية (إذا كان غير مستثنى)، وإثبات الهوية/الإقامة. المصدر: دليل رخصة القيادة التجارية لرود آيلاند، إرشادات لمتقدمي CDL."},"36":{"q":"يجب إكمال التدريب الفيدرالي لسائقي المستوى المبتدئ (ELDT)، المطبّق في رود آيلاند، من خلال مزوّد مدرج في أي سجل؟","options":["قاعدة بيانات التدريب في DMV الولاية","سجل مزوّدي التدريب التابع لـ FMCSA (TPR)","قائمة تعليم السائقين في AAMVA","قائمة المدارس المعتمدة من TSA"],"explanation":"منذ 7 فبراير 2022، يجب على المتقدمين لأول مرة للفئتين Class A/B، والترقيات من B إلى A، والباحثين عن تظهير جديد P/S/H إكمال ELDT مع مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA قبل اختبار المهارات (الاختبار المعرفي لـ H). المصدر: قاعدة ELDT الخاصة بـ FMCSA؛ سجل مزوّدي التدريب التابع لـ FMCSA."},"37":{"q":"عند التصديق الذاتي على الحالة الطبية لدى RI DMV، أي مما يلي يُعد إحدى الفئات الأربع الصالحة التي يجب أن يختار منها حامل CDL؟","options":["تجارة بين الولايات غير مستثناة (Interstate Commerce Non-excepted)","تجارة ترفيهية مُعفاة","تجارة أجنبية مُصدّق عليها","تجارة زراعية مُتنازَل عنها"],"explanation":"يدرج دليل CDL لرود آيلاند أربع فئات للتصديق الذاتي: بين الولايات مستثناة، وبين الولايات غير مستثناة، وداخل الولاية مستثناة، وداخل الولاية غير مستثناة. ويجب على السائقين غير المستثنين تقديم بطاقة طبية سارية (49 CFR 391.45). المصدر: دليل رخصة القيادة التجارية لرود آيلاند، التصديق الذاتي."},"38":{"q":"وفقاً لدليل CDL لرود آيلاند، في غضون كم يوماً يجب على حامل CDL تقديم بطاقة طبية جديدة إلى DMV بعد إصدارها؟","options":["10 days","15 days","30 days","45 days"],"explanation":"ينص دليل CDL لرود آيلاند على أنه يجب تقديم بطاقتك الطبية الجديدة إلى DMV في غضون 15 days من إصدارها؛ وعدم الالتزام بذلك قد يؤدي إلى تخفيض درجة رخصتك. المصدر: دليل رخصة القيادة التجارية لرود آيلاند، التصديق الطبي."},"39":{"q":"أثناء تشغيل مركبة آلية تجارية في رود آيلاند، ما هو تركيز الكحول في الدم (BAC) الذي يُعتبر عنده السائق أو فوقه مخموراً قانوناً لأغراض CMV؟","options":["0.04%","0.08%","0.02%","0.10%"],"explanation":"في رود آيلاند، يُعد تشغيل CMV بتركيز BAC يبلغ 0.04% أو أكثر مخالفة كبرى، وهو نصف حد 0.08% الذي ينطبق على السائقين غير التجاريين. المصدر: R.I. Gen. Laws 31-10.3-31؛ دليل CDL لرود آيلاند، القسم 2."},"40":{"q":"بموجب قانون الموافقة الضمنية في رود آيلاند، حامل CDL الذي يرفض الخضوع لاختبار كيميائي للنفَس أو الدم أو البول عند طلبه بشكل قانوني يُعامل على أنه ارتكب ماذا؟","options":["مخالفة كبرى، مثل إدانة بقيادة تحت تأثير الكحول (DUI)","مخالفة مرورية خطيرة فقط","انتهاك أمر خارج الخدمة","مسألة إدارية غير قابلة للإبلاغ"],"explanation":"في رود آيلاند، يُعد رفض اختبار كيميائي مطلوب مخالفة كبرى تحمل نفس عقوبة عدم الأهلية المترتبة على إدانة DUI. المصدر: R.I. Gen. Laws 31-10.3-31؛ دليل CDL لرود آيلاند، القسم 2."},"41":{"q":"في رود آيلاند، ما هو الحد الأدنى لفترة عدم الأهلية لحامل CDL عن أول مخالفة كبرى (مثل DUI في مركبة CMV) عند عدم نقل مواد خطرة تحمل لوحات تحذيرية؟","options":["1 year","60 days","3 years","6 months"],"explanation":"تُسقط رود آيلاند أهلية السائق لمدة سنة واحدة 1 year على الأقل عن أول مخالفة كبرى (DUI، أو BAC بقيمة 0.04 فأكثر، أو الرفض، أو مغادرة مكان الحادث، أو استخدام CMV في جناية). المصدر: R.I. Gen. Laws 31-10.3-31؛ 49 CFR 383.51."},"42":{"q":"في رود آيلاند، إذا ارتكب سائق أول مخالفة كبرى أثناء نقل مواد خطرة تتطلب لوحات تحذيرية، فإن الحد الأدنى لفترة عدم الأهلية يرتفع إلى:","options":["3 years","1 year","120 days","5 years"],"explanation":"تؤدي أول مخالفة كبرى أثناء تشغيل مركبة مواد خطرة تحمل لوحات تحذيرية إلى عدم أهلية لمدة 3 years كحد أدنى في رود آيلاند، بدلاً من السنة الواحدة المعتادة. المصدر: R.I. Gen. Laws 31-10.3-31؛ 49 CFR 383.51."},"43":{"q":"في رود آيلاند، حامل CDL الذي يُدان بمخالفة كبرى ثانية خلال حياته يواجه أي عقوبة عدم أهلية؟","options":["عدم أهلية مدى الحياة","عدم أهلية لمدة 10-year","عدم أهلية لمدة 3-year","عدم أهلية لمدة 1-year"],"explanation":"تؤدي المخالفة الكبرى الثانية في الحياة إلى عدم أهلية مدى الحياة في رود آيلاند (والتي قد تُخفَّض، بموجب شروط معينة، إلى حد أدنى قدره 10 years). المصدر: R.I. Gen. Laws 31-10.3-31؛ 49 CFR 383.51."},"44":{"q":"كم عدد المخالفات المرورية الخطيرة خلال فترة 3-year (الناشئة عن حوادث منفصلة) التي تؤدي إلى عدم أهلية CDL لمدة 60-day في رود آيلاند؟","options":["2","3","4","1"],"explanation":"تؤدي مخالفتان مروريتان خطيرتان في مركبة CMV خلال 3 years إلى عدم أهلية لمدة 60-day في رود آيلاند. المصدر: R.I. Gen. Laws 31-10.3-31؛ دليل CDL لرود آيلاند، القسم 2."},"45":{"q":"في رود آيلاند، ثلاث مخالفات مرورية خطيرة خلال فترة 3-year تؤدي إلى عدم أهلية CDL لمدة كم؟","options":["120 days","60 days","90 days","1 year"],"explanation":"تؤدي ثلاث مخالفات مرورية خطيرة في مركبة CMV خلال 3 years إلى عدم أهلية لمدة 120-day في رود آيلاند. المصدر: R.I. Gen. Laws 31-10.3-31؛ دليل CDL لرود آيلاند، القسم 2."},"46":{"q":"أي مما يلي يُصنّف على أنه مخالفة مرورية خطيرة (SERIOUS) لحامل CDL في رود آيلاند؟","options":["اتباع المركبة الأمامية بمسافة قريبة جداً","تشغيل CMV بتركيز BAC قدره 0.04%","رفض اختبار كيميائي","انتهاك أمر خارج الخدمة"],"explanation":"اتباع المركبة بمسافة قريبة جداً هو إحدى المخالفات المرورية الخطيرة المدرجة؛ أما الخيارات الأخرى فهي مخالفات كبرى أو انتهاكات أوامر خارج الخدمة لها عقوبات منفصلة. المصدر: دليل CDL لرود آيلاند، القسم 2؛ 49 CFR 383.51."},"47":{"q":"بالنسبة لمخالفة مرورية خطيرة في رود آيلاند، يُعرّف الإسراع المفرط بأنه القيادة بسرعة كم ميلاً في الساعة أو أكثر فوق حد السرعة المعلن؟","options":["15 mph or more","10 mph or more","20 mph or more","25 mph or more"],"explanation":"الإسراع بمقدار 15 mph أو أكثر فوق الحد المعلن يُعد مخالفة مرورية خطيرة لأغراض CDL في رود آيلاند. المصدر: دليل CDL لرود آيلاند، القسم 2؛ 49 CFR 383.51."},"48":{"q":"بموجب القواعد الفيدرالية المعتمدة في رود آيلاند، يُعد استخدام هاتف محمول باليد أو إرسال الرسائل النصية أثناء قيادة CMV أي نوع من المخالفات لأغراض عدم الأهلية؟","options":["مخالفة مرورية خطيرة","مخالفة كبرى","انتهاك أمر خارج الخدمة","مخالفة معبر سكة حديد"],"explanation":"إرسال الرسائل النصية أو استخدام هاتف محمول باليد أثناء قيادة CMV هو مخالفة مرورية خطيرة في رود آيلاند، تُحتسب ضمن عدم الأهلية لمدة 60-day/120-day. المصدر: 49 CFR 383.51، 392.80-392.82؛ دليل CDL لرود آيلاند."},"49":{"q":"كم عدد مخالفات الرسائل النصية/الهاتف المحمول باليد خلال فترة 3-year التي تؤدي إلى عدم أهلية CDL لمدة 120-day في رود آيلاند؟","options":["3 or more","2","5","4"],"explanation":"لأن إرسال الرسائل النصية/استخدام الهاتف باليد مخالفات مرورية خطيرة، فإن ثلاثاً أو أكثر منها خلال 3 years تؤدي إلى عدم أهلية لمدة 120-day (مخالفتان تؤديان إلى 60 days). المصدر: 49 CFR 383.51، 392.82؛ دليل CDL لرود آيلاند."},"50":{"q":"في رود آيلاند، ثالث انتهاك أو ما بعده لأمر خارج الخدمة خلال فترة 10-year (عمليات قياسية) يؤدي إلى أي عدم أهلية؟","options":["3 years","1 year","5 years","مدى الحياة"],"explanation":"يحمل ثالث انتهاك أو ما بعده لأمر OOS خلال 10 years عدم أهلية لمدة 3 years في رود آيلاند. المصدر: R.I. Gen. Laws 31-10.3-31؛ 49 CFR 383.51."},"51":{"q":"إذا انتهك حامل CDL في رود آيلاند أمراً خارج الخدمة أثناء نقل مواد خطرة تحمل لوحات تحذيرية أو أثناء تشغيل مركبة مصممة لنقل 16 راكباً أو أكثر، فإن عدم الأهلية عن أول انتهاك يكون على الأقل:","options":["180 days","90 days","1 year","60 days"],"explanation":"يرفع أول انتهاك OOS أثناء نقل مواد خطرة أو حمل 16+ راكباً الحد الأدنى لعدم الأهلية إلى 180 days في رود آيلاند. المصدر: R.I. Gen. Laws 31-10.3-31؛ 49 CFR 383.51."},"52":{"q":"في رود آيلاند، ما هو الحد الأدنى لعدم الأهلية لأول مخالفة لحامل CDL عند معبر سكة حديد بمستوى الطريق؟","options":["60 days","30 days","90 days","120 days"],"explanation":"تؤدي أول مخالفة عند معبر سكة حديد بمستوى الطريق إلى عدم أهلية لمدة 60-day كحد أدنى في رود آيلاند. المصدر: R.I. Gen. Laws 31-10.3-31؛ 49 CFR 383.51."},"53":{"q":"في رود آيلاند، ثاني مخالفة عند معبر سكة حديد بمستوى الطريق خلال فترة 3-year تؤدي إلى حد أدنى لعدم الأهلية قدره:","options":["120 days","60 days","1 year","90 days"],"explanation":"تحمل ثاني مخالفة عند معبر سكة حديد خلال 3 years حداً أدنى لعدم الأهلية قدره 120-day في رود آيلاند. المصدر: R.I. Gen. Laws 31-10.3-31؛ 49 CFR 383.51."},"54":{"q":"في رود آيلاند، ثالث مخالفة أو ما بعدها عند معبر سكة حديد بمستوى الطريق خلال فترة 3-year تؤدي إلى حد أدنى لعدم الأهلية قدره:","options":["1 year","120 days","60 days","3 years"],"explanation":"تحمل ثالث مخالفة أو ما بعدها عند معبر سكة حديد خلال 3 years حداً أدنى لعدم الأهلية قدره 1 year في رود آيلاند. المصدر: R.I. Gen. Laws 31-10.3-31؛ 49 CFR 383.51."},"55":{"q":"يُدان حامل CDL في رود آيلاند بقيادة تحت تأثير الكحول (DUI) أثناء قيادة مركبته الشخصية (غير التجارية). ماذا يحدث لرخصة CDL الخاصة به؟","options":["يُسقطون أهليته لقيادة CMV لمدة 1 year على الأقل","لا شيء، لأنها لم تكن مركبة تجارية","يحصلون على عدم أهلية لمدة 60-day فقط","يواجهون عقوبة مخالفة خطيرة فقط"],"explanation":"في رود آيلاند، تؤدي إدانة DUI في أي مركبة، بما في ذلك سيارة شخصية، إلى إسقاط أهلية حامل CDL لتشغيل CMV لمدة 1 year على الأقل باعتبارها مخالفة كبرى. المصدر: R.I. Gen. Laws 31-10.3-31؛ 49 CFR 383.51."},"56":{"q":"أي مما يلي يُعد مخالفة كبرى (عدم أهلية لمدة سنة واحدة 1-year) لحامل CDL في رود آيلاند وليس مخالفة مرورية خطيرة؟","options":["استخدام CMV في ارتكاب جناية","الاتباع بمسافة قريبة جداً","تغيير غير سليم أو غير منتظم للمسار","قيادة CMV دون الفئة أو التظهير المناسب"],"explanation":"استخدام CMV لارتكاب جناية هو مخالفة كبرى تحمل عدم أهلية لمدة 1-year؛ أما الخيارات الأخرى فهي مخالفات مرورية خطيرة. المصدر: R.I. Gen. Laws 31-10.3-31؛ دليل CDL لرود آيلاند، القسم 2؛ 49 CFR 383.51."},"57":{"q":"في ولاية رود آيلاند، على أي مسافة من أقرب قضيب سكة حديد يجب أن تتوقف حافلة مدرسية تنقل أطفالاً، أو حافلة تنقل ركاباً مقابل أجر، أو مركبة تنقل متفجرات أو سوائل قابلة للاشتعال قبل عبور خطوط السكك الحديدية؟","options":["ضمن 100 قدم ولكن ليس أقل من 50 قدماً","ضمن 50 قدماً ولكن ليس أقل من 15 قدماً","ضمن 25 قدماً ولكن ليس أقل من 10 أقدام","ضمن 75 قدماً ولكن ليس أقل من 25 قدماً"],"explanation":"تشترط المادة § 31-20-4 من القوانين العامة لولاية رود آيلاند على سائق أي مركبة آلية تنقل ركاباً مقابل أجر، أو أي حافلة مدرسية تنقل طفلاً مدرسياً، أو أي مركبة تنقل مواد متفجرة أو سوائل قابلة للاشتعال أن يتوقف ضمن خمسين قدماً (50') ولكن ليس أقل من خمسة عشر قدماً (15') من أقرب قضيب سكة حديد. المصدر: RIGL § 31-20-4."},"58":{"q":"بموجب قانون رود آيلاند، التوقف عند معبر السكك الحديدية المطلوب من الحافلات المؤجرة، والحافلات المدرسية، وناقلات المتفجرات/السوائل القابلة للاشتعال لا ينطبق في أي من الحالات التالية؟","options":["كلما كانت المركبة خالية من الحمولة أو الركاب","في أي وقت يحمل فيه السائق تصديقاً للمواد الخطرة","عند أي معبر مزود ببوابات أوتوماتيكية","عند معبر يوجه فيه ضابط أو إشارة تحكم مروري حركة المرور للمضي قدماً، أو عند المعابر الواقعة ضمن منطقة تجارية أو سكنية"],"explanation":"تنص المادة RIGL § 31-20-4 على أنه لا حاجة للتوقف عندما يوجه ضابط شرطة أو إشارة تحكم مروري حركة المرور للمضي قدماً، ولا تنطبق المادة عند معابر السكك الحديدية المستوية الواقعة ضمن منطقة تجارية أو سكنية. لا تُلغي الحافلة الفارغة أو وجود البوابات هذه القاعدة. المصدر: RIGL § 31-20-4."},"59":{"q":"على طريق سريع مقسوم في رود آيلاند، متى لا يُطلب من السائق التوقف لحافلة مدرسية متوقفة تعرض أضواء حمراء وامضة؟","options":["كلما كان السائق يسير بسرعة أقل من 20 ميلاً في الساعة","عندما يكون السائق على بعد أكثر من طولَي سيارة من الحافلة","أبداً — يجب على جميع السائقين التوقف دائماً في كلا الاتجاهين","عندما تكون الحافلة متوقفة على الطريق في الجانب الآخر من الطريق السريع المقسوم بالنسبة للسائق"],"explanation":"تنص المادة RIGL § 31-20-13 على أنه لا حاجة للسائق للتوقف عندما يكون الطريق السريع مقسوماً وتكون الحافلة متوقفة على الطريق في أحد جانبي الطريق السريع المقسوم بينما يقود السائق على الجانب الآخر. تُعرّف هيئة RI DMV الطريق السريع المقسوم بأنه طريق مفصول بحاجز أو حاجز واقٍ أو فاصل عشبي/إسمنتي. المصدر: RIGL § 31-20-13؛ صفحة الحافلات المدرسية في RI DMV."},"60":{"q":"تُعرّف رود آيلاند 'الطريق السريع المقسوم' لأغراض استثناء التوقف للحافلة المدرسية بأنه طريق مفصول بأي مما يلي؟","options":["خط منتصف أصفر مزدوج فقط","مسار وسطي للانعطاف لليسار في الاتجاهين","حاجز جيرسي، أو حاجز واقٍ، أو فاصل عشبي أو إسمنتي، أو أشجار، أو مياه، أو فاصل مماثل بين المسارات المتعاكسة","أي طريق يحتوي على ثلاثة مسارات أو أكثر إجمالاً"],"explanation":"توضح هيئة RI DMV أن استثناء الطريق السريع المقسوم ينطبق فقط حيث تكون الاتجاهات المتعاكسة مفصولة بحاجز جيرسي، أو حاجز واقٍ، أو فاصل عشبي أو إسمنتي، أو أشجار، أو مياه، إلخ. خط المنتصف المرسوم أو مسار الانعطاف لا يُعد فاصلاً. المصدر: صفحة الحافلات المدرسية في RI DMV (تفسيراً للمادة RIGL § 31-20-13)."},"61":{"q":"عند مقابلة أو تجاوز حافلة مدرسية في رود آيلاند تعرض أضواءها الحمراء الوامضة على طريق عادي (غير مقسوم) ذي مسارين، ماذا يجب على السائق أن يفعل؟","options":["التباطؤ إلى 15 ميلاً في الساعة والتجاوز بحذر","التوقف فقط إذا كان قادماً من خلف الحافلة","إفساح الطريق فقط للأطفال الموجودين فعلياً على الطريق","التوقف من أي اتجاه وعدم المضي قدماً حتى تتحرك الحافلة أو تُطفأ الأضواء الوامضة"],"explanation":"تشترط المادة RIGL § 31-20-12 على السائقين الذين يقابلون أو يتجاوزون من أي اتجاه حافلة تحمل علامة 'حافلة مدرسية' مع أضواء حمراء وامضة أن يتوقفوا، ولا يجوز للسائق المضي قدماً حتى تستأنف الحافلة الحركة أو تتوقف الأضواء الوامضة عن العمل. المصدر: RIGL § 31-20-12."},"62":{"q":"يحظر قانون رود آيلاند على سائق أي مركبة (باستثناء مركبة الطوارئ في مهمة رسمية) تتبع حافلة مدرسية بمسافة أقرب من أي مسافة؟","options":["100 قدم","20 قدماً","50 قدماً","300 قدم"],"explanation":"تحظر المادة RIGL § 31-20-12 القيادة خلف حافلة مدرسية بمسافة أقل من خمسين قدماً (50')، باستثناء مركبات الطوارئ في مهمة رسمية. المصدر: RIGL § 31-20-12."},"63":{"q":"بموجب قانون 'أفسح الطريق' (Move Over) في رود آيلاند، ماذا يجب على السائق أن يفعل عند الاقتراب من مركبة طوارئ متوقفة، أو شاحنة قطر، أو مركبة صيانة طرق تعرض أضواءً وامضة على طريق يحتوي على مسارين على الأقل في اتجاه السائق؟","options":["التوقف التام حتى تغادر المركبة","إطلاق البوق والاستمرار بالسرعة المحددة","الانتقال إلى الكتف الأيمن والتوقف","الانتقال إلى مسار ليس الأقرب إلى المركبة المتوقفة، عندما يمكن فعل ذلك بأمان"],"explanation":"تشترط المادة RIGL § 31-14-3 على السائق الانتقال إلى مسار ليس الأقرب إلى مركبة الطوارئ المرخصة المتوقفة، أو شاحنة القطر/النقل، أو مركبة المساعدة على جانب الطريق، أو معدات الصيانة التي تعرض أضواءً وامضة — إذا كان الطريق يحتوي على مسارين أو أكثر في ذلك الاتجاه وكان بالإمكان القيام بالتحرك بأمان. المصدر: RIGL § 31-14-3."},"64":{"q":"بموجب قانون 'أفسح الطريق' (Move Over) في رود آيلاند، ماذا يجب على السائق أن يفعل عندما يكون هناك مسار واحد فقط في اتجاه السائق أو عندما لا يمكن تغيير المسار بأمان؟","options":["التوقف التام في مسار السير","الحفاظ على حد السرعة المحدد","الخروج من الطريق والانتظار خمس دقائق","التباطؤ إلى سرعة آمنة ومنخفضة والبقاء عليها حتى تجاوز المركبة بالكامل"],"explanation":"توجه المادة RIGL § 31-14-3 بأنه حيث يوجد مسار واحد فقط أو يكون تغيير المسار غير آمن، يجب على السائق إبطاء المركبة إلى سرعة آمنة للظروف والسير بتلك السرعة المنخفضة حتى تجاوز المركبة المتوقفة بالكامل. المصدر: RIGL § 31-14-3."},"65":{"q":"يحمي قانون 'أفسح الطريق' (Move Over) في رود آيلاند أياً من المركبات المتوقفة التالية التي تعرض أضواء تحذير؟","options":["سيارات الشرطة وسيارات الإسعاف فقط","المركبات المملوكة للولاية فقط","مركبات الطوارئ، وشاحنات القطر/النقل، ومركبات المساعدة على جانب الطريق، ومعدات صيانة الطرق السريعة","آليات الإطفاء التي تكافح حريقاً بنشاط فقط"],"explanation":"تدرج المادة RIGL § 31-14-3 مركبات الطوارئ المرخصة، وشاحنات القطر، وشاحنات النقل، ومركبات المساعدة على جانب الطريق، ومعدات صيانة الطرق السريعة التي تعرض أضواءً وامضة كمركبات محمية. لا يقتصر القانون على الشرطة وسيارات الإسعاف. المصدر: RIGL § 31-14-3."},"66":{"q":"في غياب حد مرور منشور، فإن حد السرعة الافتراضي المبدئي (prima facie) في رود آيلاند في أي منطقة تجارية أو سكنية هو:","options":["25 ميلاً في الساعة","30 ميلاً في الساعة","20 ميلاً في الساعة","35 ميلاً في الساعة"],"explanation":"تحدد المادة RIGL § 31-14-2 حداً افتراضياً مبدئياً قدره خمسة وعشرون ميلاً في الساعة (25 ميلاً في الساعة) في أي منطقة تجارية أو سكنية. المصدر: RIGL § 31-14-2."},"67":{"q":"بموجب حدود السرعة الافتراضية المبدئية في رود آيلاند، ما هو الحد النهاري في المواقع غير المناطق التجارية/السكنية والمناطق المدرسية، حيث لا يوجد حد آخر منشور؟","options":["55 ميلاً في الساعة نهاراً","50 ميلاً في الساعة نهاراً","45 ميلاً في الساعة نهاراً","65 ميلاً في الساعة نهاراً"],"explanation":"تحدد المادة RIGL § 31-14-2 حداً افتراضياً مبدئياً قدره خمسون ميلاً في الساعة (50 ميلاً في الساعة) في المواقع الأخرى أثناء النهار، وخمسة وأربعون (45 ميلاً في الساعة) أثناء الليل. قد تكون الحدود المنشورة على الطريق السريع الولائي أعلى. المصدر: RIGL § 31-14-2."},"68":{"q":"ضمن 300 قدم من مداخل ومخارج المدرسة خلال الأيام الدراسية، تحدد رود آيلاند حد سرعة افتراضياً مبدئياً قدره:","options":["15 ميلاً في الساعة في جميع الأوقات","20 ميلاً في الساعة أثناء النهار","25 ميلاً في الساعة أثناء النهار","10 أميال في الساعة عند وجود أطفال"],"explanation":"تحدد المادة RIGL § 31-14-2 عشرين ميلاً في الساعة (20 ميلاً في الساعة) ضمن ثلاثمائة قدم (300') من مداخل ومخارج أراضي المبنى المدرسي أثناء النهار في الأيام التي تكون فيها المدارس مفتوحة. المصدر: RIGL § 31-14-2."},"69":{"q":"على طريق سريع في رود آيلاند، يجب على المركبة التجارية التي تسير بسرعة أبطأ من السرعة العادية لحركة المرور أن:","options":["تقود في المسار الأيمن أو أقرب ما يمكن عملياً إلى الحافة اليمنى للطريق","تبقى في المسار الأوسط لتجنب حركة المرور المندمجة","تستخدم المسار الأيسر للابتعاد عن منحدرات الدخول","تستخدم أي مسار طالما أن الأضواء الوامضة الرباعية مشغّلة"],"explanation":"تشترط المادة RIGL § 31-15-2 ('حركة المرور البطيئة إلى اليمين') على أي مركبة تسير بسرعة أبطأ من السرعة العادية لحركة المرور أن تُقاد في المسار الأيمن المتاح، أو أقرب ما يمكن عملياً إلى الرصيف الأيمن أو الحافة، إلا عند التجاوز أو المرور أو الاستعداد للانعطاف لليسار. المصدر: RIGL § 31-15-2."},"70":{"q":"بدون تصريح للحجم الزائد، فإن الحد الأقصى القانوني لعرض المركبة أو حمولتها في رود آيلاند هو:","options":["102 بوصة (8 أقدام و6 بوصات)","96 بوصة (8 أقدام)","108 بوصة (9 أقدام)","120 بوصة (10 أقدام)"],"explanation":"تحدد المادة RIGL § 31-25-3 إجمالي العرض الخارجي للمركبة أو حمولتها بمئة واثنتين بوصة (102\")، أي 8 أقدام و6 بوصات، قبل أن يصبح تصريح الحجم الزائد مطلوباً. المصدر: RIGL § 31-25-3؛ دليل OSOW القانوني الصادر عن RIDOT."},"71":{"q":"بدون تصريح للحجم الزائد، فإن الحد الأقصى القانوني لارتفاع المركبة بما في ذلك حمولتها في رود آيلاند هو:","options":["168 بوصة (14 قدماً)","162 بوصة (13 قدماً و6 بوصات)","156 بوصة (13 قدماً)","150 بوصة (12 قدماً و6 بوصات)"],"explanation":"تحدد المادة RIGL § 31-25-4 ارتفاع المركبة بما في ذلك الحمولة بمئة واثنتين وستين بوصة (162\")، أي 13 قدماً و6 بوصات. يؤكد دليل OSOW القانوني الصادر عن RIDOT أن 13'6\" هو الارتفاع القانوني. المصدر: RIGL § 31-25-4؛ دليل OSOW القانوني الصادر عن RIDOT."},"72":{"q":"في رود آيلاند، نصف المقطورة التي يزيد طولها عن 48 قدماً و6 بوصات يجوز تشغيلها فقط في أي مكان؟","options":["في أي مكان في الولاية دون قيود","على الطرق ذات الرسوم فقط","على نظام الطرق السريعة الولائية وغيرها من الطرق التي يحددها مدير RIDOT","بين شروق الشمس وغروبها فقط على أي طريق"],"explanation":"تحدد المادة RIGL § 31-25-6 سقف أنصاف المقطورات بثلاثة وخمسين قدماً (53') ولكنها تسمح لتلك التي يزيد طولها عن ثمانية وأربعين قدماً ونصف (48'6\") بالتشغيل فقط على النظام الولائي وعلى الطرق السريعة/الشوارع/الطرق التي يحددها مدير RIDOT. المصدر: RIGL § 31-25-6."},"73":{"q":"الحد الأقصى للوزن الإجمالي لأي مركبة أو مجموعة من المركبات على الطرق السريعة في رود آيلاند، في غياب تصريح، هو:","options":["73,280 رطلاً","80,000 رطل","88,000 رطل","100,000 رطل"],"explanation":"تحدد المادة RIGL § 31-25-14 الوزن الإجمالي الكلي بثمانين ألف رطل (80,000 lbs)، رهناً أيضاً بصيغة الجسر الفيدرالية. المصدر: RIGL § 31-25-14."},"74":{"q":"بموجب قانون رود آيلاند، الحد الأقصى للوزن الإجمالي المسموح به على أي محور مفرد للمركبة هو:","options":["22,400 رطل","20,000 رطل","34,000 رطل","18,000 رطل"],"explanation":"تحدد المادة RIGL § 31-25-14 الوزن الإجمالي على عجلات أي محور واحد باثنين وعشرين ألفاً وأربعمائة (22,400) رطل؛ ويُحدد المحور المزدوج (بتباعد يصل إلى 8 أقدام) بـ 36,000 رطل. المصدر: RIGL § 31-25-14."},"75":{"q":"اعتباراً من عام 2026، برنامج رسوم عبور الجسور RhodeWorks في رود آيلاند مُنظَّم بحيث يفرض رسوماً على أي مركبات؟","options":["فقط شاحنات الجرّار-المقطورة من الفئة 8 (والأكبر)؛ سيارات الركاب والشاحنات الصغيرة (pickups) معفاة","جميع المركبات التي يزيد وزنها عن 10,000 رطل","كل مركبة تعبر جسراً ذا رسوم","فقط الشاحنات التجارية من خارج الولاية"],"explanation":"يفرض برنامج RhodeWorks في رود آيلاند رسوماً فقط على الشاحنات التجارية الكبيرة — شاحنات الجرّار-المقطورة من الفئة 8 والأكبر — عند بوابات الجسور، مع إعفاء سيارات الركاب والمركبات التجارية الأصغر. أيدت محكمة الدائرة الأولى البنية المقتصرة على الجرّار-المقطورة (وألغت فقط الحد اليومي الأقصى). المصدر: RIDOT/RhodeWorks؛ قرار الدائرة الأولى بشأن RhodeWorks."},"76":{"q":"عندما تتوقف مركبة تجارية في رود آيلاند على الجزء المُستخدَم للسير من طريق ذي مسارين باتجاهين، أين يجب على السائق وضع المثلثات التحذيرية الثلاثة المطلوبة؟","options":["المثلثات الثلاثة جميعها ضمن 10 أقدام من المصد الخلفي","واحد على بعد 200 قدم واثنان على بعد 100 قدم، جميعها خلف المركبة","نحو 10 أقدام خلف المركبة باتجاه حركة المرور، ونحو 100 قدم خلفها، ونحو 100 قدم أمام المركبة","مثلث واحد فقط، يُوضع على بعد 50 قدماً إلى الخلف"],"explanation":"تتبع رود آيلاند المعيار الفيدرالي (49 CFR 392.22) المُدرَّس في دليل CDL: على طريق ذي مسارين باتجاهين، ضع مثلثاً واحداً على بعد نحو 10 أقدام إلى الخلف باتجاه حركة المرور، وواحداً على بعد نحو 100 قدم إلى الخلف، وواحداً على بعد نحو 100 قدم إلى الأمام. (على طريق مقسوم أو باتجاه واحد، تُوضع الأجهزة الخلفية على بعد 10 و100 و200 قدم.) المصدر: دليل CDL لرود آيلاند؛ 49 CFR 392.22."},"77":{"q":"أي جهة تصدر رخص القيادة التجارية (CDLs) في رود آيلاند؟","options":["شعبة المركبات الآلية في رود آيلاند (DMV)","وزارة النقل في رود آيلاند (RIDOT)","وحدة الإنفاذ التجاري في شرطة ولاية رود آيلاند","الإدارة الفيدرالية لسلامة الناقلين بالمركبات الآلية (FMCSA)"],"explanation":"تُصدر رخص CDL في رود آيلاند من قبل شعبة المركبات الآلية في رود آيلاند (RI DMV). تتولى RIDOT الطرق وتصاريح الحجم الزائد/الوزن الزائد، وتضع FMCSA المعايير الفيدرالية ولكنها لا تصدر رخص الولايات. المصدر: RI DMV، صفحات رخصة القيادة التجارية (CDL)."},"78":{"q":"أين تُجرى اختبارات المهارات (الطريق) الحضورية لرخصة CDL في رود آيلاند؟","options":["في موقع اختبار CDL المخصص في 400 Romano Vineyard Way، نورث كينغزتاون","في أي فرع لمكتب AAA على مستوى الولاية","في مقر DMV في كرانستون فقط","في محطات وزن RIDOT على طول I-95"],"explanation":"تُجرى اختبارات المهارات التجارية في رود آيلاند بموعد مسبق في موقع اختبار CDL، 400 Romano Vineyard Way، نورث كينغزتاون. يتولى DMV في كرانستون المعاملات الحضورية لرخص CDL واختبارات المعرفة، لكن اختبار المهارات يُجرى في موقع نورث كينغزتاون. المصدر: RI DMV، صفحة اختبار المهارات التجارية."},"79":{"q":"كم من الوقت يجب أن يكون مقدم الطلب قد حمل فيه رخصة قيادة عادية (الفئة D) قبل التقدم للحصول على رخصة CDL في رود آيلاند؟","options":["سنتان (2) على الأقل","6 أشهر على الأقل","سنة (1) واحدة على الأقل","3 سنوات على الأقل"],"explanation":"تشترط رود آيلاند أن يكون مقدم طلب رخصة CDL سائقاً مرخّصاً لمدة سنتين (2) كحد أدنى وقت تقديم الطلب. المصدر: RI DMV، صفحات رخصة القيادة التجارية (CDL) / تصريح المتعلم التجاري والاختبارات."},"80":{"q":"بموجب قواعد رود آيلاند، ما هو الحد الأدنى للسن للحصول على رخصة CDL للقيادة داخل الولاية (ضمن الولاية فقط)؟","options":["18 عاماً","16 عاماً","21 عاماً","25 عاماً"],"explanation":"عند سن 18 يجوز لك الحصول على رخصة CDL في رود آيلاند للسفر داخل الولاية فقط؛ ويجب أن تكون بعمر 21 للقيادة بين الولايات (عبر حدود الولايات). المصدر: RI DMV، صفحة رخصة القيادة التجارية (CDL)."},"81":{"q":"ما هو الحد الأدنى للسن المطلوب في رود آيلاند لقيادة مركبة تجارية بين الولايات (عبر حدود الولايات)؟","options":["21 عاماً","18 عاماً","19 عاماً","23 عاماً"],"explanation":"تشترط رود آيلاند، باتباع المعيار الفيدرالي، أن يكون السائق بعمر 21 عاماً للتشغيل التجاري بين الولايات؛ ويقتصر من تتراوح أعمارهم بين 18 و20 عاماً على القيادة داخل الولاية. المصدر: RI DMV، صفحة رخصة القيادة التجارية (CDL)."},"82":{"q":"أي استمارة طلب يجب إكمالها للتقدم للحصول على رخصة CDL في رود آيلاند؟","options":["طلب رخصة القيادة التجارية (CDL-1)","الاستمارة MCSA-5876","طلب الرخصة القياسي (LI-1)","الاستمارة DL-44C"],"explanation":"يُكمل مقدمو الطلبات في رود آيلاند طلب رخصة القيادة التجارية (CDL-1)، الذي يتضمن أيضاً إقرار سجل السائق. المصدر: RI DMV، صفحة تصريح المتعلم التجاري والاختبارات (استمارة CDL-1)."},"83":{"q":"في رود آيلاند، ما هو إثبات الوجود القانوني الذي يجب على مقدم طلب رخصة CDL تقديمه؟","options":["إثبات الجنسية الأمريكية أو الإقامة الدائمة القانونية","جواز سفر ساري المفعول من أي بلد","بطاقة الضمان الاجتماعي فقط، دون إثبات إضافي","بيان إقامة موثّق من صاحب عمل"],"explanation":"تشترط RI DMV على جميع مقدمي طلبات رخص CDL تقديم إثبات الوضع كمواطن أمريكي أو مقيم دائم قانوني، إلى جانب إثبات الإقامة في رود آيلاند. المصدر: RI DMV، صفحة رخصة القيادة التجارية (CDL)."},"84":{"q":"أي اختبار معرفة هو الحد الأدنى المطلوب للحصول على تصريح المتعلم التجاري (CLP) في رود آيلاند؟","options":["اختبار المعرفة العامة","اختبار الفرامل الهوائية","اختبار المركبات المركبة","اختبار المواد الخطرة"],"explanation":"اختبار المعرفة العامة هو الحد الأدنى المطلوب لتصريح CLP في رود آيلاند؛ وتُطلب اختبارات معرفة إضافية حسب الفئة والتصديقات المطلوبة. المصدر: RI DMV، صفحة تصريح المتعلم التجاري والاختبارات."},"85":{"q":"في اختبار المعرفة العامة لرخصة CDL في رود آيلاند (50 سؤالاً)، ما هي الدرجة المطلوبة للنجاح؟","options":["80٪ (40 من 50 إجابة صحيحة)","70٪ (35 من 50 إجابة صحيحة)","75٪ (38 من 50 إجابة صحيحة)","90٪ (45 من 50 إجابة صحيحة)"],"explanation":"تتبع رود آيلاند عتبة النجاح القياسية لرخص CDL البالغة 80٪؛ وفي اختبار المعرفة العامة المكوّن من 50 سؤالاً يعني ذلك 40 إجابة صحيحة. المصدر: دليل CDL لرود آيلاند / معايير اختبار المعرفة في RI DMV."},"86":{"q":"كم تبلغ مدة صلاحية تصريح المتعلم التجاري (CLP) في رود آيلاند، وهل يمكن تجديده؟","options":["صالح لمدة سنة واحدة كحد أقصى وغير قابل للتجديد","صالح لمدة 180 يوماً وقابل للتجديد مرة واحدة","صالح لمدة سنتين وقابل للتجديد","صالح لمدة 60 يوماً وغير قابل للتجديد"],"explanation":"تصريح CLP في رود آيلاند صالح لمدة سنة واحدة كحد أقصى وغير قابل للتجديد؛ وإذا انتهت صلاحيته يجب على مقدم الطلب إعادة جميع اختبارات المعرفة ودفع الرسوم من جديد. المصدر: RI DMV، صفحة تصريح المتعلم التجاري والاختبارات."},"87":{"q":"بعد الحصول على تصريح CLP في رود آيلاند، كم من الوقت يجب الاحتفاظ به قبل أن يتمكن حامله من إجراء اختبار مهارات CDL؟","options":["14 يوماً على الأقل","30 يوماً على الأقل","7 أيام على الأقل","60 يوماً على الأقل"],"explanation":"تماشياً مع القاعدة الفيدرالية التي تتبعها، تشترط رود آيلاند الاحتفاظ بتصريح CLP لمدة 14 يوماً على الأقل قبل إجراء اختبار مهارات CDL. المصدر: RI DMV، صفحة اختبار المهارات التجارية (معيار FMCSA 49 CFR 383)."},"88":{"q":"ما هي الأجزاء الثلاثة لاختبار مهارات CDL في رود آيلاند؟","options":["فحص المركبة، ومهارات التحكم الأساسية، واختبار الطريق","الاختبار التحريري، واختبار النظر، واختبار الطريق","الفرامل الهوائية، والرجوع للخلف، والقيادة على الطريق السريع","الفحص قبل الرحلة، والمواد الخطرة، والقيادة الليلية"],"explanation":"يتكون اختبار المهارات في رود آيلاند من ثلاثة أجزاء: اختبار فحص المركبة (قبل الرحلة)، واختبار مهارات التحكم الأساسية، واختبار الطريق؛ ويجب على مقدم الطلب اجتياز الثلاثة جميعاً. المصدر: RI DMV، صفحة اختبار المهارات التجارية."},"89":{"q":"من الذي يجب أن يوفّر المركبة المستخدمة في اختبار مهارات CDL في رود آيلاند، وفي أي حالة يجب أن تكون؟","options":["يوفّر مقدم الطلب مركبته الخاصة، ويجب أن تصل فارغة (دون حمولة)","توفّر DMV مركبة اختبار مملوكة للولاية لجميع مقدمي الطلبات","يجب على صاحب عمل مقدم الطلب توفير مركبة اختبار محمّلة","أي شاحنة صندوقية مستأجرة، بغض النظر عن فئة الوزن، مقبولة"],"explanation":"في رود آيلاند، يجب على المرشح توفير مركبته التمثيلية الخاصة، ويجب أن تصل فارغة (دون حمولة)؛ ويجب أن تكون الصهاريج معتمدة بأنها فارغة ومنظّفة ومُطهّرة. المصدر: RI DMV، صفحة اختبار المهارات التجارية."},"90":{"q":"إلى جانب تصريح CLP ورخصة المُشغّل، ما هي المستندات التي يجب تقديمها لاختبار المهارات في رود آيلاند؟","options":["تسجيل مركبة ساري المفعول، وإثبات تأمين فعّال، وملصق فحص ساري المفعول","شهادة الثانوية العامة وإثبات التوظيف","جواز سفر وشهادة ميلاد فقط","خطاب موثّق من مدرسة تدريب CDL"],"explanation":"تشترط رود آيلاند نسخاً ورقية من تصريح CLP ورخصة المُشغّل بالإضافة إلى تسجيل ساري المفعول للمركبة (والمقطورة، إن وُجدت)، وإثبات تأمين فعّال، وملصق فحص مركبة فعّال. المصدر: RI DMV، صفحة اختبار المهارات التجارية."},"91":{"q":"بموجب قواعد رود آيلاند، متى يجب إكمال تدريب السائق المبتدئ (ELDT) بالنسبة لمقدم طلب الفئة A أو الفئة B لأول مرة؟","options":["قبل إجراء اختبار مهارات CDL","خلال 30 يوماً بعد اجتياز اختبار المهارات","فقط بعد أن تكون رخصة CDL قد صدرت بالفعل","إنه اختياري ويمكن تخطيه بموافقة صاحب العمل"],"explanation":"يجب إكمال تدريب ELDT بنجاح لدى مزود مسجّل قبل أن يُسمح لمقدم طلب الفئة A/B لأول مرة بإجراء اختبار مهارات CDL. المصدر: RI DMV، صفحة ELDT (قاعدة ELDT الفيدرالية، السارية في 7 فبراير 2022)."},"92":{"q":"لأي تصديق تشترط رود آيلاند إكمال تدريب ELDT قبل اختبار المعرفة (وليس اختبار المهارات)؟","options":["تصديق المواد الخطرة (H)","تصديق الركاب (P)","تصديق الحافلة المدرسية (S)","تصديق المزدوجات/الثلاثيات (T)"],"explanation":"بالنسبة لتصديق المواد الخطرة (H)، يجب إكمال تدريب ELDT قبل إجراء اختبار المعرفة؛ أما بالنسبة لتصديقَي P وS فيُكمل تدريب ELDT قبل اختبار المهارات. المصدر: RI DMV، صفحة ELDT."},"93":{"q":"أين يجب على مقدم الطلب في رود آيلاند البحث للعثور على مزود تدريب ELDT معتمد؟","options":["سجل مزودي التدريب التابع لـ FMCSA (TPR)","بوابة قائمة انتظار CLP في RI DMV","السجل الوطني للفاحصين الطبيين المعتمدين","قائمة موردي مكتب تصاريح RIDOT"],"explanation":"تُدرَج مزودات ELDT المعتمدة في سجل مزودي التدريب التابع لـ FMCSA (tpr.fmcsa.dot.gov)؛ ويمكن أيضاً التحقق من الإكمال هناك. المصدر: RI DMV، صفحة ELDT."},"94":{"q":"كم عدد فئات التجارة للإقرار الذاتي التي يجب على مقدم طلب رخصة CDL في رود آيلاند الاختيار من بينها؟","options":["أربع فئات","فئتان","ثلاث فئات","ست فئات"],"explanation":"يجب على مقدم الطلب في رود آيلاند الإقرار ذاتياً ضمن واحدة من أربع فئات: بين الولايات غير مستثناة، أو بين الولايات مستثناة، أو داخل الولاية غير مستثناة، أو داخل الولاية مستثناة. المصدر: RI DMV، صفحة الشهادة الطبية / الإقرار الذاتي."},"95":{"q":"السائق في رود آيلاند الذي يُقرّ بأنه 'بين الولايات غير مستثنى' (Interstate Non-Excepted) يجب عليه أن يفعل ماذا؟","options":["الحصول على شهادة الفاحص الطبي الفيدرالية DOT والحفاظ عليها","تجنب نقل أي حمولة عبر حدود الولايات","تجديد رخصة CDL سنوياً بدلاً من كل خمس سنوات","تخطي اختبار الطريق بسبب وضعه بين الولايات"],"explanation":"يعمل السائقون من فئة 'بين الولايات غير مستثنى' داخل رود آيلاند وخارجها ويُطلب منهم الحصول على شهادة الفاحص الطبي الفيدرالية DOT؛ أما الفئات المستثناة فلا. المصدر: RI DMV، صفحة الشهادة الطبية / الإقرار الذاتي."},"96":{"q":"كيف تُنقل الآن الشهادة الطبية DOT لسائق رخصة CDL غير المستثنى في رود آيلاند إلى DMV؟","options":["يقدّمها الفاحص الطبي المعتمد إلكترونياً إلى السجل الوطني التابع لـ FMCSA، الذي يحيلها إلى RI DMV","يرسل السائق نسخة ورقية من البطاقة الطبية بالبريد مباشرة إلى RI DMV","يرسل صاحب العمل الشهادة بالفاكس إلى RIDOT لحفظها","يحمّلها السائق عبر بوابة حساب RI E-ZPass"],"explanation":"لم تعد RI DMV تقبل الشهادة الطبية مباشرة؛ يقدّم الفاحص الطبي المعتمد شهادة الفاحص الطبي (الاستمارة MCSA-5876/5875) إلكترونياً إلى السجل الوطني التابع لـ FMCSA، الذي يحيلها إلى DMV. ويؤدي عدم الحفاظ على سريانها إلى تخفيض رخصة CDL. المصدر: RI DMV، صفحة الشهادة الطبية؛ السجل الوطني للفاحصين الطبيين المعتمدين."}}};
